// ── GEMINI CONFIG (Settings mein daal sakte ho) ──
var CAPTAIN_GEMINI_API_KEY = localStorage.getItem('captain_gemini_key') || '';
var CAPTAIN_GEMINI_MODEL   = 'gemini-2.5-flash-lite-preview-06-17';

function getCaptainGeminiURL() {
  var key = localStorage.getItem('captain_gemini_key') || CAPTAIN_GEMINI_API_KEY;
  return 'https://generativelanguage.googleapis.com/v1beta/models/' + CAPTAIN_GEMINI_MODEL + ':generateContent?key=' + key;
}

// ── CORE GEMINI CALL ──
async function captainCallGemini(systemPrompt, userMessage) {
  try {
    var key = localStorage.getItem('captain_gemini_key') || '';
    if (!key || key === '') {
      return '⚠️ AI API Key set nahi hai. Settings → AI Settings mein Gemini API Key daalo. (aistudio.google.com se free milti hai)';
    }
    var now = Date.now();
    var lastCall = window._captainLastGeminiCall || 0;
    if (now - lastCall < 3000) {
      await new Promise(function(r){ setTimeout(r, 3000 - (now - lastCall)); });
    }
    window._captainLastGeminiCall = Date.now();
    var response = await fetch(getCaptainGeminiURL(), {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        system_instruction: { parts: [{ text: systemPrompt }] },
        contents: [{ role: 'user', parts: [{ text: userMessage }] }],
        generationConfig: { maxOutputTokens: 1024, temperature: 0.7 }
      })
    });
    if (!response.ok) {
      var err = await response.json().catch(function(){ return {}; });
      var errCode = (err && err.error && err.error.code) || response.status;
      var errMsg  = (err && err.error && err.error.message) || 'Unknown error';
      if (errCode === 429) return '⏳ API limit hit hui — 1-2 minute wait karo.';
      if (errCode === 400) return '❌ API Key invalid. aistudio.google.com se nayi key lo.';
      if (errCode === 403) return '❌ API access denied. Key check karo.';
      return '❌ AI Error ' + errCode + ': ' + errMsg;
    }
    var data = await response.json();
    return (data.candidates && data.candidates[0] && data.candidates[0].content && data.candidates[0].content.parts && data.candidates[0].content.parts[0] && data.candidates[0].content.parts[0].text) || '❌ AI ka jawab nahi aaya.';
  } catch(e) {
    if (e.message && e.message.includes('fetch')) return '❌ Network error — Internet check karo.';
    return '❌ Error: ' + e.message;
  }
}

// ── RESTAURANT DATA COLLECTOR ──
window.captainGetRestaurantData = function() {
  try {
    var orders    = JSON.parse(localStorage.getItem('captain_orders')    || '[]');
    var menu      = JSON.parse(localStorage.getItem('captain_menu')      || '[]');
    var today     = new Date().toDateString();
    var todayOrders = orders.filter(function(o){ return new Date(o.timestamp||o.createdAt).toDateString()===today; });
    var todayRev    = todayOrders.reduce(function(s,o){ return s+(o.totalAmount||o.grandTotal||0); }, 0);
    return 'Restaurant: CaptainDash | Date: ' + new Date().toLocaleDateString('en-IN') +
      '\nToday Revenue: ₹' + todayRev.toLocaleString('en-IN') +
      '\nToday Orders: ' + todayOrders.length +
      '\nTotal Menu Items: ' + menu.length;
  } catch(e) { return 'Restaurant data available'; }
};

// ── 1. AI ASSISTANT CHAT ──
window.captainAIChat = async function(userMsg) {
  var data = window.captainGetRestaurantData();
  var systemPrompt = 'Tu hai ARIA — CaptainDash Restaurant ki smart AI assistant! 🌟\n' +
    'Tu Hinglish mein baat karta hai — Hindi + English mix.\n' +
    'Tu captain ki help karta hai — orders, menu, staff, revenue sab ke baare mein.\n' +
    'Tu fun aur helpful hai — emojis use karo.\n' +
    'Restaurant Data: ' + data + '\nAaj: ' + new Date().toLocaleDateString('hi-IN');
  return await captainCallGemini(systemPrompt, userMsg);
};

// ── 2. AI REPORT GENERATOR ──
window.captainAIReport = async function() {
  var data = window.captainGetRestaurantData();
  var systemPrompt = 'Tu ek expert restaurant business analyst hai. Restaurant data analyze karke detailed report banao — Revenue, Orders, Recommendations. Date: ' + new Date().toLocaleString('en-IN');
  return await captainCallGemini(systemPrompt, 'Restaurant data:\n' + data + '\n\nPoori business report banao.');
};

// ── 3. AI QUICK ACTIONS ──
window.captainAIQuickAction = async function(type) {
  var data = window.captainGetRestaurantData();
  var prompts = {
    tips:    { sys: 'Tu restaurant expert hai. Practical tips do.', msg: 'Data: ' + data + '\n\nAaj ke liye 5 actionable tips do.' },
    menu:    { sys: 'Tu menu consultant hai.', msg: 'Data: ' + data + '\n\nMenu improve karne ke suggestions do.' },
    revenue: { sys: 'Tu revenue analyst hai.', msg: 'Data: ' + data + '\n\nRevenue badhane ke 3 quick ideas do.' }
  };
  var p = prompts[type] || prompts.tips;
  return await captainCallGemini(p.sys, p.msg);
};

