// ===== LOGIN =====
// Currently logged-in captain data
window._loggedInCaptain = null;

async function doLogin(){
  const u = document.getElementById('loginUser').value.trim();
  const p = document.getElementById('loginPass').value.trim();

  if (!u || !p) {
    document.getElementById('loginUser').style.borderColor = 'var(--red)';
    setTimeout(() => document.getElementById('loginUser').style.borderColor = '', 1500);
    return;
  }

  const btn = document.querySelector('.login-btn');
  if (btn) { btn.textContent = 'Checking...'; btn.disabled = true; }

  try {
    // Wait for Firebase to be ready
    const [fbAppMod, fbFsMod] = await Promise.all([
      import("https://www.gstatic.com/firebasejs/10.12.2/firebase-app.js"),
      import("https://www.gstatic.com/firebasejs/10.12.2/firebase-firestore.js")
    ]);
    const { initializeApp, getApps } = fbAppMod;
    const { getFirestore, collection, getDocs } = fbFsMod;
    const apps = getApps();
    const fbApp = apps.length ? apps[0] : initializeApp(CAPTAIN_FB_CFG);
    const db = getFirestore(fbApp);

    // Get all captains from Firestore
    const snap = await getDocs(collection(db, 'captains'));
    let matchedCaptain = null;
    snap.forEach(d => {
      const data = { _fbId: d.id, ...d.data() };
      if (
        data.username && data.password &&
        data.username.toLowerCase() === u.toLowerCase() &&
        data.password === p &&
        data.status !== 'inactive'
      ) {
        matchedCaptain = data;
      }
    });

    if (!matchedCaptain) {
      showToast('❌ Galat username ya password', 'error');
      document.getElementById('loginUser').style.borderColor = 'var(--red)';
      document.getElementById('loginPass').style.borderColor = 'var(--red)';
      setTimeout(() => {
        document.getElementById('loginUser').style.borderColor = '';
        document.getElementById('loginPass').style.borderColor = '';
      }, 1500);
      if (btn) { btn.textContent = '🔐 Sign In as Captain'; btn.disabled = false; }
      return;
    }

    // Save logged in captain globally
    window._loggedInCaptain = matchedCaptain;

    // Update UI with captain name & area
    const nameEl = document.querySelector('.captain-name');
    const roleEl = document.querySelector('.captain-role');
    const avatarEl = document.querySelector('.captain-avatar');
    if (nameEl) nameEl.textContent = matchedCaptain.name || u;
    if (roleEl) roleEl.textContent = 'Captain · ' + (matchedCaptain.area || 'Area');
    if (avatarEl) {
      const initials = (matchedCaptain.name || u).split(' ').map(w => w[0]).join('').toUpperCase().slice(0,2);
      avatarEl.textContent = initials;
    }

    // Hide login overlay
    document.getElementById('loginOverlay').classList.add('hidden');
    showToast('✅ Welcome ' + (matchedCaptain.name || u) + '! ' + (matchedCaptain.area || '') + ' area ready.');

    // Re-init order listener with captain filter
    if (typeof startCaptainOrderListener === 'function') {
      startCaptainOrderListener();
    }
    // Re-init tables listener so only assigned tables show
    if (typeof window._captainRestartTablesListener === 'function') {
      window._captainRestartTablesListener();
    }

  } catch(e) {
    console.error('[Login] Error:', e);
    showToast('❌ Login error: ' + e.message, 'error');
    if (btn) { btn.textContent = '🔐 Sign In as Captain'; btn.disabled = false; }
  }
}

// ═══════════════════════════════════════════════════
// CAPTAIN ASSIGNED TABLES FILTER
// tableFrom/tableTo range (billing file se assign hota hai)
// ya tables[] array — dono support karta hai
// ═══════════════════════════════════════════════════

// Filter function — har jagah use hoti hai
window._captainFilterTables = function(allTables) {
  var cap = window._loggedInCaptain;
  if (!cap) {
    console.log('[TableFilter] Captain login nahi — saari', allTables.length, 'tables dikh rahi hain');
    return allTables; // login nahi — saari tables
  }

  // METHOD 1: tableFrom / tableTo range (billing file wala system)
  var tFrom = cap.tableFrom !== undefined && cap.tableFrom !== '' ? parseInt(cap.tableFrom) : null;
  var tTo   = cap.tableTo   !== undefined && cap.tableTo   !== '' ? parseInt(cap.tableTo)   : null;
  if (tFrom !== null && tTo !== null && !isNaN(tFrom) && !isNaN(tTo)) {
    console.log('[TableFilter] Range filter:', tFrom, 'to', tTo);
    return allTables.filter(function(t) {
      // Try: doc ID number, ya "Table X" se number nikalte hain
      var n = parseInt(t._docId) || parseInt(String(t.no || '').replace(/\D/g, ''));
      var match = !isNaN(n) && n >= tFrom && n <= tTo;
      return match;
    });
  }

  // METHOD 2: tables[] array
  var assignedList = cap.tables || cap.assignedTables;
  if (assignedList && Array.isArray(assignedList) && assignedList.length > 0) {
    return allTables.filter(function(t) {
      return assignedList.indexOf(t.no) !== -1;
    });
  }

  // Koi assignment nahi — saari tables (admin)
  return allTables;
};

// Login ke baad call hota hai — filtered tables reload karo
window._captainRestartTablesListener = function() {
  var cap = window._loggedInCaptain;
  if (!cap) return;

  console.log('[TablesLogin] Captain login hua:', cap.name || cap.username, '| tableFrom:', cap.tableFrom, '| tableTo:', cap.tableTo);

  // Agar Firebase data already aa chuka hai toh filter lagao
  if (window._captainAllTablesData && window._captainAllTablesData.length > 0) {
    tableData = window._captainFilterTables(window._captainAllTablesData);
    console.log('[TablesLogin] Filter ke baad tables:', tableData.map(function(t){ return t.no; }));
    buildTables();
    if (typeof refreshCartTableSelect === 'function') refreshCartTableSelect();
    if (typeof captainToast === 'function') {
      captainToast('🪑 ' + tableData.length + ' tables — ' + (cap.name || cap.username), '#059669');
    }
  } else {
    // Firebase data abhi nahi aaya — wait karke retry karo
    console.log('[TablesLogin] Firebase data abhi nahi aaya — 2s baad retry karunga');
    setTimeout(function() {
      if (window._captainAllTablesData && window._captainAllTablesData.length > 0) {
        tableData = window._captainFilterTables(window._captainAllTablesData);
        buildTables();
        if (typeof refreshCartTableSelect === 'function') refreshCartTableSelect();
        if (typeof captainToast === 'function') {
          captainToast('🪑 ' + tableData.length + ' tables — ' + (cap.name || cap.username), '#059669');
        }
      }
    }, 2000);
  }
};

