// ===== SETTINGS — AI VOICE LANGUAGE =====
function settingsSetLang(lang) {
  ariaChangeLang(lang);
  settingsRefreshLangUI();
  // Animate the selected card
  ['hi','mr','en'].forEach(l => {
    const card = document.getElementById('settLang' + l.charAt(0).toUpperCase() + l.slice(1));
    if(card) card.style.transform = (l === lang) ? 'scale(1.04)' : 'scale(1)';
  });
}

function settingsRefreshLangUI() {
  const cur = ARIA_VOICE.lang || 'hi';
  const cfg = ARIA_VOICE.langConfig || {};
  const colors = { hi: {border:'#059669', bg:'#ecfdf5', shadow:'rgba(5,150,105,.2)'}, mr: {border:'#c2410c', bg:'#fff7ed', shadow:'rgba(194,65,12,.2)'}, en: {border:'#1d4ed8', bg:'#eff6ff', shadow:'rgba(29,78,216,.2)'} };
  ['hi','mr','en'].forEach(l => {
    const key = l.charAt(0).toUpperCase() + l.slice(1);
    const card  = document.getElementById('settLang' + key);
    const badge = document.getElementById('settLang' + key + 'Badge');
    if(!card) return;
    const active = (l === cur);
    const c = colors[l];
    card.style.borderColor  = active ? c.border : '#e5e7eb';
    card.style.background   = active ? c.bg     : '#fff';
    card.style.boxShadow    = active ? '0 4px 16px ' + c.shadow : 'none';
    if(badge) badge.style.display = active ? 'block' : 'none';
  });
  // Update status bar
  const flagEl = document.getElementById('settLangStatusFlag');
  const txtEl  = document.getElementById('settLangStatusTxt');
  const c = cfg[cur];
  if(flagEl) flagEl.textContent = c?.flag || '🇮🇳';
  if(txtEl)  txtEl.textContent  = (c ? c.label + ' (' + c.name + ')' : 'Hindi') + ' — Active hai';
}

function settingsTestVoice() {
  const cur = ARIA_VOICE.lang || 'hi';
  const testMsg = { hi: 'नमस्ते Captain! मैं हिंदी में बोल रही हूँ। आज का काम अच्छा चल रहा है।', mr: 'नमस्कार Captain! मी मराठीत बोलत आहे. आजचा महसूल चांगला आहे. सर्व टेबल व्यवस्थित आहेत.', en: 'Hello Captain! I am now speaking in English. Today the restaurant is running smoothly!' };
  ARIA_VOICE.say(testMsg[cur] || testMsg.hi);
  showToast('🔊 Voice test chal rahi hai...');
}

// ── SETTINGS FIREBASE SYNC ──
async function saveAllSettings() {
  // Collect all setting values
  const inputs = document.querySelectorAll('#page-settings .setting-input');
  const toggles = document.querySelectorAll('#page-settings .toggle');
  const settingsData = {
    restaurantName: inputs[0]?.value || '',
    gstNumber:      inputs[1]?.value || '',
    currency:       inputs[2]?.value || '',
    gstRate:        inputs[3]?.value || '',
    autoPrintBills: toggles[0]?.classList.contains('on') || false,
    darkMode:       toggles[1]?.classList.contains('on') || false,
    soundAlerts:    toggles[2]?.classList.contains('on') || false,
    ariaLang:       window.ARIA_VOICE?.lang || 'hi',
    savedAt:        Date.now()
  };

  // Local feedback immediately
  showToast('💾 Settings save ho rahi hai...');
  const msg = document.getElementById('settingsSavedMsg');

  // Firebase mein save karo
  if (_captainDb && _captainCollection && _captainAddDoc) {
    try {
      // setDoc with fixed ID 'restaurantSettings' — overwrite karo har baar
      const { doc, setDoc } = await import("https://www.gstatic.com/firebasejs/10.12.2/firebase-firestore.js");
      await setDoc(doc(_captainDb, 'captainSettings', 'restaurantSettings'), settingsData);
      showToast('✅ Settings Firebase mein save ho gayi!');
      // console.log('✅ Settings saved to Firebase');
    } catch(e) {
      console.warn('Settings save error:', e);
      showToast('⚠️ Firebase settings save failed: ' + e.message);
    }
  } else {
    // Firebase ready nahi — localStorage mein save karo
    try { localStorage.setItem('captainSettings', JSON.stringify(settingsData)); } catch(e) {}
    showToast('✅ Settings saved! (Firebase sync hogi jab connect ho)');
  }

  if(msg) { msg.style.opacity = '1'; setTimeout(() => msg.style.opacity = '0', 2500); }
}

// -- SETTINGS LOAD FROM FIREBASE (FIXED: restaurantInfo/main collection) --
async function _loadSettingsFromFirebase() {
  if (!_captainDb) return;
  try {
    const { doc, getDoc, onSnapshot, collection, getDocs } = await import("https://www.gstatic.com/firebasejs/10.12.2/firebase-firestore.js");

    // -- 1. Captain UI settings (toggles, currency etc.) --
    const snap = await getDoc(doc(_captainDb, 'captainSettings', 'restaurantSettings'));
    if (snap.exists()) {
      const d = snap.data();
      const inputs = document.querySelectorAll('#page-settings .setting-input');
      const toggles = document.querySelectorAll('#page-settings .toggle');
      if (inputs[0] && d.restaurantName) inputs[0].value = d.restaurantName;
      if (inputs[1] && d.gstNumber)      inputs[1].value = d.gstNumber;
      if (inputs[2] && d.currency)       inputs[2].value = d.currency;
      if (inputs[3] && d.gstRate)        inputs[3].value = d.gstRate;
      if (toggles[0]) { toggles[0].classList.toggle('on', !!d.autoPrintBills); }
      if (toggles[1]) { toggles[1].classList.toggle('on', !!d.darkMode); }
      if (toggles[2]) { toggles[2].classList.toggle('on', !!d.soundAlerts); }
      if (d.ariaLang && typeof settingsSetLang === 'function') settingsSetLang(d.ariaLang);
    }

    // -- 2. Restaurant Info (name, GST, FSSAI, phone, addr) --
    // Priority: restaurantInfo/main (billing syncs here) > lum_settings localStorage > settings collection

    function _applyRS(data) {
      if (!data || (!data.name && !data.restaurantName)) return false;
      window._captainRS = {
        name:    data.name    || data.restaurantName || '',
        addr:    data.addr    || data.address        || '',
        phone:   data.phone   || '',
        gst:     data.gst     || data.gstNo          || data.gstin || '',
        fssai:   data.fssai   || data.fssaiNo        || '',
        gstRate: parseFloat(data.gstRate) || 5,
        service: parseFloat(data.service) || 10,
      };
      // console.log('[Captain] Restaurant info loaded:', window._captainRS.name);
      return true;
    }

    // A. Real-time listener on restaurantInfo/main (billing saves here)
    onSnapshot(doc(_captainDb, 'restaurantInfo', 'main'), function(riSnap) {
      if (riSnap.exists()) {
        _applyRS(riSnap.data());
        // console.log('[Captain] restaurantInfo/main live update:', window._captainRS.name);
      }
    });

    // B. Try localStorage lum_settings (same device fallback)
    if (!window._captainRS || !window._captainRS.name) {
      try {
        const _ls = localStorage.getItem('lum_settings');
        if (_ls) _applyRS(JSON.parse(_ls));
      } catch(e2) {}
    }

    // C. Fallback: scan 'settings' collection
    if (!window._captainRS || !window._captainRS.name) {
      try {
        const settingsSnap = await getDocs(collection(_captainDb, 'settings'));
        settingsSnap.forEach(function(d2) { _applyRS(d2.data()); });
      } catch(e3) {}
    }

    // D. Last resort: scan 'captainSettings' for name/gst
    if (!window._captainRS || !window._captainRS.name) {
      try {
        const csSnap = await getDocs(collection(_captainDb, 'captainSettings'));
        csSnap.forEach(function(d4) { _applyRS(d4.data()); });
      } catch(e4) {}
    }

    showToast('Settings load hui!');
  } catch(e) {
    console.warn('Settings load error:', e);
  }
}

