// ===========================
// ===== TABLE DATA — BILLING FIREBASE REAL-TIME =====
// ===========================
// Billing.html ki 'tables' collection se real-time data aata hai
// tableData ab sirf local cache hai — Firebase se override hota hai

let tableData = [];
let _billingLiveOrders = {}; // tableNum -> order data from 'orders' collection

const statusLabel = {occupied:'Occupied', available:'Available', reserved:'Reserved', cleaning:'Cleaning'};
const tableIcons  = {occupied:'🍽️', available:'🍽️', reserved:'📋', cleaning:'🧹'};

function getTableColor(status){
  return {occupied:'var(--orange)', available:'var(--G600)', reserved:'var(--purple)', cleaning:'var(--blue)'}[status] || 'var(--ink3)';
}

function updateTableCounts(){
  const cnts = {available:0, occupied:0, reserved:0, cleaning:0};
  tableData.forEach(t => cnts[t.status] = (cnts[t.status]||0)+1);
  const s = id => { const el=document.getElementById(id); if(el) el.textContent=cnts[id.replace('tbl','').replace('Count','').toLowerCase()]||0; };
  document.getElementById('tblAvailCount')    && (document.getElementById('tblAvailCount').textContent    = cnts.available||0);
  document.getElementById('tblOccupiedCount') && (document.getElementById('tblOccupiedCount').textContent = cnts.occupied||0);
  document.getElementById('tblReservedCount') && (document.getElementById('tblReservedCount').textContent = cnts.reserved||0);
  document.getElementById('tblCleaningCount') && (document.getElementById('tblCleaningCount').textContent = cnts.cleaning||0);
  const dashEl = document.getElementById('dashTableCount');
  if(dashEl) dashEl.textContent = (cnts.occupied||0)+'/'+tableData.length;
}

function buildTables(){
  const g = document.getElementById('tablesGrid'); if(!g) return;
  if(!tableData.length){
    // Agar Firebase data aa chuka hai lekin assigned tables 0 hain
    if (window._captainAllTablesData && window._captainAllTablesData.length > 0) {
      const cap = window._loggedInCaptain;
      const capName = cap ? (cap.name || cap.username || 'Captain') : '';
      const fromTo = cap ? (cap.tableFrom && cap.tableTo ? ' (Table ' + cap.tableFrom + ' – ' + cap.tableTo + ')' : '') : '';
      g.innerHTML = '<div style="grid-column:1/-1;text-align:center;padding:40px;color:var(--ink3);font-size:13px"><div style="font-size:36px;margin-bottom:10px">⚠️</div>' +
        '<b style="color:var(--orange)">' + (cap ? capName + ' ko koi table assign nahi' + fromTo : 'Koi assigned table nahi') + '</b><br>' +
        '<span style="font-size:11px;margin-top:6px;display:block">Billing dashboard mein captain ka tableFrom/tableTo set karo</span></div>';
    } else {
      g.innerHTML = '<div style="grid-column:1/-1;text-align:center;padding:40px;color:var(--ink3);font-size:13px"><div style="font-size:36px;margin-bottom:10px">🔄</div>Firebase se tables load ho rahi hain...</div>';
    }
    updateTableCounts();
    return;
  }
  // Sort by table number
  const sorted = tableData.slice().sort((a,b)=>{
    const na = parseInt(String(a.no||'').replace(/\D/g,''))||0;
    const nb = parseInt(String(b.no||'').replace(/\D/g,''))||0;
    return na - nb;
  });

  g.innerHTML = sorted.map(t => {
    // Live order data for this table
    const tNum = parseInt(String(t.no||'').replace(/\D/g,'')) || 0;
    const liveOrder = _billingLiveOrders[tNum] || null;
    const custName  = liveOrder ? (liveOrder.customerName || liveOrder.name || '') : (t.customerName || '');
    const custPhone = liveOrder ? (liveOrder.customerPhone || liveOrder.phone || '') : (t.customerPhone || '');
    const items     = liveOrder ? (liveOrder.items || liveOrder.currentOrder || []) : (t.order || t.currentOrder || []);
    const itemCount = items.reduce ? items.reduce((s,i)=>s+(i.qty||1),0) : 0;
    const amount    = items.reduce ? items.reduce((s,i)=>s+((parseFloat(i.price)||parseFloat(i.rate)||0)*(parseInt(i.qty)||parseInt(i.quantity)||1)),0) : 0;
    const status    = t.status || 'available';
    const orderStatus = liveOrder ? (liveOrder.status||'') : '';

    const orderStatusBadge = orderStatus
      ? `<div style="font-size:9px;font-weight:700;padding:2px 7px;border-radius:4px;margin-top:3px;display:inline-block;background:${
          orderStatus==='pending'?'#fef3c7':orderStatus==='accepted'?'#dbeafe':orderStatus==='ready'?'#dcfce7':'#f3f4f6'
        };color:${
          orderStatus==='pending'?'#92400e':orderStatus==='accepted'?'#1e40af':orderStatus==='ready'?'#166534':'#374151'
        }">${
          orderStatus==='pending'?'🔴 New Order':orderStatus==='accepted'?'🍳 Cooking':orderStatus==='ready'?'✅ Ready!':orderStatus==='confirmed_by_captain'?'👨‍✈️ Confirmed':orderStatus
        }</div>` : '';

    const extraInfo = status==='occupied'
      ? `<div style="font-size:9px;color:var(--ink3);margin-top:2px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-width:100%">
          ${custName?'👤 '+custName:''}
          ${itemCount?` · ${itemCount} items`:''}
          ${amount?` · ₹${amount}`:''}
        </div>${orderStatusBadge}`
      : '';

    return `<div class="table-card ${status}" onclick="tableAction('${t.no}','${status}')" style="cursor:pointer;position:relative">
      <div class="table-icon">${tableIcons[status]}</div>
      <div class="table-no">${t.no}</div>
      <div class="table-seats">${t.seats||4} seats</div>
      <span class="table-status-badge ${status}">${statusLabel[status]||status}</span>
      ${extraInfo}
    </div>`;
  }).join('');

  buildBillingTablesGrid();
  updateTableCounts();
}
buildTables();

// ═══════════════════════════════════════════════════
// FIREBASE — Tables Collection Real-time Listener
// Tables load + auto-sync + save on add
// ═══════════════════════════════════════════════════
(function bootTablesFirebase() {
  var _tablesListenerStarted = false;

  function tryBoot() {
    if (!window._captainDb || !window._captainCollection || !window._captainOnSnapshot) {
      setTimeout(tryBoot, 800);
      return;
    }
    if (_tablesListenerStarted) return;
    _tablesListenerStarted = true;

    console.log('[Tables] Firebase ready — tables listener start kar raha hoon');

    window._captainOnSnapshot(
      window._captainCollection(window._captainDb, 'tables'),
      function(snap) {
        console.log('[Tables] Snapshot aaya — total docs:', snap.size);

        if (snap.empty) {
          console.log('[Tables] Collection empty hai — seeding default tables');
          _seedDefaultTables();
          return;
        }

        var allTables = [];
        snap.forEach(function(d) {
          var t = d.data();
          // Billing file: doc ID = table number (e.g. "1","2"), t.no field nahi hoti
          // Captain file: t.no field hoti hai (e.g. "Table 1")
          var tableNo = t.no || t.name || t.tableNo || t.tableNumber || null;
          if (!tableNo && d.id) {
            // Doc ID se table name banao
            var parsed = parseInt(d.id);
            tableNo = !isNaN(parsed) ? 'Table ' + parsed : d.id;
          }
          if (tableNo) {
            allTables.push({
              no: tableNo,
              _docId: d.id,
              seats: t.seats || t.capacity || 4,
              status: t.status || 'available',
              customerName: t.customerName || t.customer || '',
              customerPhone: t.customerPhone || t.phone || '',
              currentOrder: t.currentOrder || t.order || []
            });
          }
        });

        console.log('[Tables] Firebase se aayi saari tables:', allTables.map(function(t){ return t.no + '(id:' + t._docId + ')'; }));

        // Full list save karo
        window._captainAllTablesData = allTables;

        // Captain filter lagao (tableFrom/tableTo range ya tables array)
        tableData = window._captainFilterTables(allTables);

        var cap = window._loggedInCaptain;
        console.log('[Tables] Logged in captain:', cap ? (cap.name || cap.username) : 'NONE (login nahi hua)');
        console.log('[Tables] Captain tableFrom:', cap && cap.tableFrom, '| tableTo:', cap && cap.tableTo);
        console.log('[Tables] Filter ke baad tables:', tableData.map(function(t){ return t.no; }));

        buildTables();
        if (typeof refreshCartTableSelect === 'function') refreshCartTableSelect();
      },
      function(err) {
        console.error('[Tables] Listener error:', err);
        if (typeof captainToast === 'function') captainToast('❌ Tables load error: ' + err.message, '#dc2626');
        // Retry on error
        _tablesListenerStarted = false;
        setTimeout(tryBoot, 3000);
      }
    );
  }

  function _seedDefaultTables() {
    import('https://www.gstatic.com/firebasejs/10.12.2/firebase-firestore.js').then(function(fb) {
      for (var i = 1; i <= 10; i++) {
        var t = { no: 'Table ' + i, seats: 4, status: 'available', createdAt: Date.now() };
        fb.setDoc(fb.doc(window._captainDb, 'tables', t.no), t).catch(function(){});
      }
      if (typeof showToast === 'function') showToast('🪑 10 default tables Firebase mein add ki!');
    });
  }

  // Firebase init ke baad start karo — window load event ke saath sync
  window.addEventListener('load', function() {
    setTimeout(tryBoot, 500);
  });
  // Fallback agar already loaded
  setTimeout(tryBoot, 2000);
})();

function buildBillingTablesGrid(){
  const g=document.getElementById('billingTablesGrid'); if(!g) return;
  g.innerHTML=tableData.map(t=>`
    <div class="table-card ${t.status}" onclick="selectTableForBill('${t.no}')">
      <div class="table-icon" style="font-size:16px">${tableIcons[t.status]}</div>
      <div class="table-no" style="font-size:11px">${t.no.replace('Table ','T')}</div>
      <div class="table-seats">${t.seats}💺</div>
      <span class="table-status-badge ${t.status}" style="font-size:8px">${statusLabel[t.status]}</span>
    </div>`).join('');
}

// ===== TABLE ACTION — BILLING FIREBASE REAL DATA =====
function tableAction(name, status){
  const tNum = parseInt(String(name).replace(/\D/g,'')) || 0;
  const liveOrder = _billingLiveOrders[tNum] || null;
  const tObj = tableData.find(x=>x.no===name) || {};

  // Customer & order data from Firebase
  const custName  = liveOrder ? (liveOrder.customerName||liveOrder.name||'') : (tObj.customerName||'');
  const custPhone = liveOrder ? (liveOrder.customerPhone||liveOrder.phone||'') : (tObj.customerPhone||'');
  const rawItems  = liveOrder ? (liveOrder.items||liveOrder.currentOrder||[]) : (tObj.order||tObj.currentOrder||[]);

  // ── PRICE FIX: price=0 items ke liye billing menu se price lookup ──
  const items = rawItems.map(function(i){
    const p = parseFloat(i.price)||parseFloat(i.rate)||0;
    if(p > 0) return i;
    const key = (i.name||i.dish||'').toLowerCase().trim();
    const mappedPrice = (window._billingMenuPriceMap && window._billingMenuPriceMap[key]) || 0;
    if(mappedPrice > 0) return Object.assign({}, i, {price: mappedPrice, rate: mappedPrice});
    return i;
  });

  const orderStatus = liveOrder ? (liveOrder.status||'') : '';
  const fbOrderId = liveOrder ? (liveOrder._fbId||'') : '';
  const billNum   = liveOrder ? (liveOrder.billNumber||liveOrder.billNum||liveOrder.orderNumber||'') : '';

  const statusColors = {
    pending:    {bg:'#fef3c7', color:'#92400e', label:'🔴 New Order'},
    confirmed_by_captain: {bg:'#dbeafe', color:'#1e40af', label:'👨‍✈️ Confirmed'},
    accepted:   {bg:'#dbeafe', color:'#1e40af', label:'🍳 Cooking'},
    ready:      {bg:'#dcfce7', color:'#166534', label:'✅ Ready!'},
    served:     {bg:'#f3f4f6', color:'#374151', label:'🏁 Served'},
  };
  const sc = statusColors[orderStatus] || {bg:'#f3f4f6', color:'#6b7280', label:orderStatus||'—'};

  let _rsInfo = window._captainRS || {};
  let bodyHtml = `
    ${_rsInfo.name ? `<div style="text-align:center;margin-bottom:8px;padding-bottom:8px;border-bottom:1px dashed var(--line)">
      <div style="font-size:13px;font-weight:900;color:var(--ink)">${_rsInfo.name}</div>
      ${_rsInfo.addr ? `<div style="font-size:10px;color:var(--ink3)">${_rsInfo.addr}</div>` : ''}
      ${_rsInfo.phone ? `<div style="font-size:10px;color:var(--ink3)">Ph: ${_rsInfo.phone}</div>` : ''}
      ${_rsInfo.gst ? `<div style="font-size:10px;color:var(--ink3)">GSTIN: ${_rsInfo.gst}</div>` : ''}
      ${_rsInfo.fssai ? `<div style="font-size:10px;color:var(--ink3)">FSSAI: ${_rsInfo.fssai}</div>` : ''}
    </div>` : ''}
    <div style="font-size:16px;font-weight:800;margin-bottom:12px;color:${getTableColor(status)}">🪑 ${name} — ${statusLabel[status]||status}</div>`;

  if(status === 'occupied' || (liveOrder && items.length)){
    // Show full order details
    const subtotal = items.reduce ? items.reduce((s,i)=>s+((parseFloat(i.price)||parseFloat(i.rate)||0)*(parseInt(i.qty)||parseInt(i.quantity)||1)),0) : 0;
    const gst  = Math.round(subtotal * 0.05);
    const svc  = Math.round(subtotal * 0.10);
    const total = subtotal + gst + svc;

    bodyHtml += `
    <div style="background:var(--G50);border:1.5px solid var(--G100);border-radius:10px;padding:12px;margin-bottom:12px">
      <div style="display:flex;gap:8px;align-items:center;margin-bottom:8px;flex-wrap:wrap">
        ${custName ? `<span style="font-size:12px;font-weight:700;color:var(--ink)">👤 ${custName}</span>` : ''}
        ${custPhone ? `<span style="font-size:11px;color:var(--ink3)">📞 ${custPhone}</span>` : ''}
        ${orderStatus ? `<span style="font-size:10px;font-weight:700;padding:3px 9px;border-radius:5px;background:${sc.bg};color:${sc.color}">${sc.label}</span>` : ''}
        ${billNum ? `<span style="font-size:10px;color:var(--ink3)">Bill #${billNum}</span>` : ''}
      </div>
      <div style="font-size:10px;color:var(--ink3);margin-bottom:6px">
        📅 ${new Date().toLocaleDateString('en-IN',{day:'2-digit',month:'short',year:'numeric'})}
        &nbsp;&nbsp;
        ⏰ ${new Date().toLocaleTimeString('en-IN',{hour:'2-digit',minute:'2-digit'})}
      </div>
      ${items.length ? `
      <div style="font-size:11px;font-weight:700;color:var(--ink2);margin-bottom:6px">📋 Order Details:</div>
      <div style="background:var(--white);border:1px solid var(--line);border-radius:8px;padding:8px;font-size:11px;font-family:monospace;line-height:1.9;max-height:200px;overflow-y:auto">
        ${items.map((i,idx)=>{
          const iPrice=parseFloat(i.price)||parseFloat(i.rate)||0;
          const iQty=parseInt(i.qty)||parseInt(i.quantity)||1;
          const iAmt=iPrice*iQty;
          const isZero=iPrice===0;
          return `<div style="display:flex;justify-content:space-between;align-items:center;gap:4px">
            <span style="${isZero?'color:#dc2626;font-weight:700':''}">${i.name||i.dish||'Item'} ×${iQty}${isZero?' ⚠️':''}</span>
            <span style="display:flex;align-items:center;gap:6px">
              ${isZero?`<input type="number" min="1" placeholder="Price?" onchange="(function(el,nm,fbId){var v=parseFloat(el.value)||0;if(v>0){var orders=_billingLiveOrders;Object.keys(orders).forEach(function(k){var o=orders[k];if(o&&o._fbId===fbId&&o.items){o.items.forEach(function(it){if((it.name||it.dish||'')===nm){it.price=v;it.rate=v;}});} });showToast('✅ '+nm+' price ₹'+v+' set! Bill Dekho pe click karo');el.style.background='#dcfce7';}else{showToast('⚠️ Sahi price daalo')}})(this,'${(i.name||i.dish||'').replace(/'/g,"\\'")}','${fbOrderId||''}')" style="width:70px;padding:2px 4px;border:1.5px solid #dc2626;border-radius:5px;font-size:11px;font-family:monospace" />`:''}
              <span style="font-weight:700;color:${isZero?'#dc2626':'inherit'}">₹${iAmt}</span>
            </span>
          </div>`;
        }).join('')}
        <div style="border-top:1px dashed #ccc;margin:6px 0"></div>
        <div style="display:flex;justify-content:space-between"><span>Subtotal</span><span>₹${subtotal}</span></div>
        <div style="display:flex;justify-content:space-between"><span>CGST 2.5%</span><span>₹${Math.round(subtotal*0.025)}</span></div>
        <div style="display:flex;justify-content:space-between"><span>SGST 2.5%</span><span>₹${Math.round(subtotal*0.025)}</span></div>
        <div style="display:flex;justify-content:space-between;font-weight:800;font-size:13px;margin-top:4px"><span>TOTAL</span><span style="color:var(--G700)">₹${subtotal+Math.round(subtotal*0.05)}</span></div>
      </div>
      ${items.some(i=>(parseFloat(i.price)||parseFloat(i.rate)||0)===0)?`<div style="background:#fef2f2;border:1px solid #fca5a5;border-radius:7px;padding:7px 10px;font-size:11px;color:#dc2626;margin-top:6px">⚠️ Kuch items ki price ₹0 hai — upar price box mein price daalo phir Bill Dekho pe click karo!</div>`:''}` : '<div style="font-size:11px;color:var(--ink3);padding:6px 0">Koi items nahi — order place karo</div>'}
    </div>
    ${items.length ? `
    <style>
      .cap-wa-btn {
        display:flex;align-items:center;justify-content:center;gap:6px;
        background:linear-gradient(135deg,#25D366 0%,#128C7E 100%);
        color:#fff;border:none;border-radius:9px;
        padding:9px 8px;font-size:12px;font-weight:800;
        cursor:pointer;font-family:Outfit,sans-serif;letter-spacing:.2px;
        box-shadow:0 2px 8px rgba(37,211,102,.35);
        transition:transform .13s cubic-bezier(.34,1.56,.64,1), box-shadow .13s ease, filter .13s ease;
        position:relative;overflow:hidden;width:100%;
        -webkit-tap-highlight-color:transparent;
      }
      .cap-wa-btn:hover { transform:translateY(-1px) scale(1.02); box-shadow:0 5px 14px rgba(37,211,102,.45); filter:brightness(1.05); }
      .cap-wa-btn:active { transform:scale(.93) translateY(1px); box-shadow:0 1px 4px rgba(37,211,102,.2); filter:brightness(.96); }
      .cap-wa-btn::after { content:''; position:absolute;inset:0;background:rgba(255,255,255,0);transition:background .1s; border-radius:9px; }
      .cap-wa-btn:active::after { background:rgba(255,255,255,.15); }

      .cap-paid-btn {
        display:flex;align-items:center;justify-content:center;gap:6px;
        background:#fff;color:#059669;
        border:2px solid #059669;border-radius:9px;
        padding:9px 8px;font-size:12px;font-weight:800;
        cursor:pointer;font-family:Outfit,sans-serif;letter-spacing:.2px;
        box-shadow:0 1px 6px rgba(5,150,105,.10);
        transition:transform .13s cubic-bezier(.34,1.56,.64,1), box-shadow .13s ease, background .15s ease, color .15s ease, border-color .15s ease;
        position:relative;overflow:hidden;width:100%;
        -webkit-tap-highlight-color:transparent;
      }
      .cap-paid-btn:hover { background:linear-gradient(135deg,#059669 0%,#047857 100%);color:#fff;border-color:transparent;transform:translateY(-1px) scale(1.02);box-shadow:0 5px 14px rgba(5,150,105,.32); }
      .cap-paid-btn:active { transform:scale(.93) translateY(1px);box-shadow:0 1px 4px rgba(5,150,105,.15);background:linear-gradient(135deg,#047857 0%,#065f46 100%);color:#fff;border-color:transparent; }

      .cap-sub-btn {
        flex:1;display:flex;align-items:center;justify-content:center;gap:5px;
        background:#f8fafb;color:#374151;border:1.5px solid #e5e7eb;border-radius:7px;
        padding:8px 6px;font-size:11px;font-weight:700;
        cursor:pointer;font-family:Outfit,sans-serif;
        transition:transform .12s cubic-bezier(.34,1.56,.64,1), background .12s ease;
        -webkit-tap-highlight-color:transparent;
      }
      .cap-sub-btn:hover { background:#fff;border-color:#059669;color:#059669; }
      .cap-sub-btn:active { transform:scale(.93);background:#ecfdf5; }
    </style>
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:7px;margin-bottom:8px">
      <button class="cap-wa-btn"
        onclick="(function(){
          var tNum=parseInt('${name}'.replace(/\D/g,''))||0;
          var lo=_billingLiveOrders[tNum]||null;
          var ph=lo?(lo.customerPhone||lo.phone||''):'';
          var nm=lo?(lo.customerName||'Customer'):'Customer';
          var its=lo?(lo.items||lo.currentOrder||[]):[];
          var rs=(function(){try{return JSON.parse(localStorage.getItem('lum_settings')||'{}').name||'Restaurant';}catch(e){return 'Restaurant';}})();
          var sub=its.reduce(function(s,i){return s+((parseFloat(i.price)||parseFloat(i.rate)||0)*(parseInt(i.qty)||parseInt(i.quantity)||1));},0);
          var gst=Math.round(sub*0.025);var tot=sub+gst+gst;
          var bn=lo?(lo.billNumber||lo.orderNumber||'—'):'—';
          var msg='🍽️ *'+rs+'*\n━━━━━━━━━━━━━━━━━\n📋 Bill Receipt\n${name} · Bill #'+bn+'\n👤 '+nm+'\n━━━━━━━━━━━━━━━━━\n'+its.map(function(i){return (i.name||i.dish||'Item')+' ×'+(parseInt(i.qty)||1)+' ........... ₹'+((parseFloat(i.price)||parseFloat(i.rate)||0)*(parseInt(i.qty)||1));}).join('\n')+'\n━━━━━━━━━━━━━━━━━\nSubtotal: ₹'+sub+'\nCGST 2.5%: ₹'+gst+'\nSGST 2.5%: ₹'+gst+'\n*TOTAL: ₹'+tot+'*\n━━━━━━━━━━━━━━━━━\nThank you for dining!';
          var cp=ph.replace(/[^0-9]/g,'');
          var url=cp?(('https://wa.me/'+(cp.startsWith('91')?cp:'91'+cp)+'?text='+encodeURIComponent(msg))):('https://wa.me/?text='+encodeURIComponent(msg));
          window.open(url,'_blank');
          showToast('Bill WhatsApp pe bheja gaya!','#25D366');
        })()">
        <svg style="vertical-align:middle;display:inline-block;font-size:15px" style="font-size:15px" xmlns="http://www.w3.org/2000/svg" width="1em" height="1em" viewBox="0 0 24 24" fill="currentColor"><path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 0 1-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 0 1-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 0 1 2.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0 0 12.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 0 0 5.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 0 0-3.48-8.413Z"/></svg>
        <span>WhatsApp</span>
      </button>
      <button class="cap-paid-btn"
        onclick="(function(){
          _activeBillTableName='${name}';
          _activeBillFbOrderId=(function(){var tNum=parseInt('${name}'.replace(/\D/g,''))||0;var lo=_billingLiveOrders[tNum]||null;return lo?(lo._fbId||''):'';})();
          captainFreeTableOnFirebase('${name}');
          closeModal('tableModal');
          showToast('Bill Paid — ${name} free ho gaya!','#059669');
        })()">
        <svg style="vertical-align:middle;display:inline-block;font-size:14px" style="font-size:14px" xmlns="http://www.w3.org/2000/svg" width="1em" height="1em" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><polyline points="9 12 11 14 15 10"/></svg>
        <span>Mark as Paid</span>
      </button>
    </div>
    <div style="display:flex;gap:6px">
      <button class="cap-sub-btn" onclick="closeModal('tableModal');openNewOrderForTable('${name}')"><svg style="vertical-align:middle;display:inline-block;font-size:10px" style="font-size:10px" xmlns="http://www.w3.org/2000/svg" width="1em" height="1em" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg> Items Add</button>
      <button class="cap-sub-btn" onclick="closeModal('tableModal');showToast('Table merge mode!')"><svg style="vertical-align:middle;display:inline-block;font-size:10px" style="font-size:10px" xmlns="http://www.w3.org/2000/svg" width="1em" height="1em" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M10 13a5 5 0 0 0 7.54.54l3-3a5 5 0 0 0-7.07-7.07l-1.72 1.71"/><path d="M14 11a5 5 0 0 0-7.54-.54l-3 3a5 5 0 0 0 7.07 7.07l1.71-1.71"/></svg> Merge</button>
    </div>
    ` : `
    <div style="display:flex;gap:8px">
      <button class="cap-sub-btn" onclick="closeModal('tableModal');openNewOrderForTable('${name}')"><svg style="vertical-align:middle;display:inline-block;font-size:12px" style="font-size:12px" xmlns="http://www.w3.org/2000/svg" width="1em" height="1em" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg> Items Add</button>
      <button class="cap-sub-btn" onclick="closeModal('tableModal');showToast('Table merge mode!')"><svg style="vertical-align:middle;display:inline-block;font-size:12px" style="font-size:12px" xmlns="http://www.w3.org/2000/svg" width="1em" height="1em" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M10 13a5 5 0 0 0 7.54.54l3-3a5 5 0 0 0-7.07-7.07l-1.72 1.71"/><path d="M14 11a5 5 0 0 0-7.54-.54l-3 3a5 5 0 0 0 7.07 7.07l1.71-1.71"/></svg> Merge</button>
    </div>
    `}`;
  } else if(status === 'available'){
    bodyHtml += `<div style="font-size:12px;color:var(--ink2);margin-bottom:13px">${name} abhi <b style="color:var(--G600)">Available ✅</b> hai.</div>
    <div style="display:flex;gap:7px;flex-wrap:wrap">
      <button class="btn btn-green" style="flex:1" onclick="closeModal('tableModal');openNewOrderForTable('${name}')">🚀 Order Open Karo</button>
      <button class="btn btn-outline" style="flex:1" onclick="closeModal('tableModal');openModal('bookingModal')">📋 Reserve Karo</button>
    </div>`;
  } else if(status === 'reserved'){
    bodyHtml += `<div style="font-size:12px;color:var(--ink2);margin-bottom:13px">${name} <b style="color:var(--purple)">Reserved 📋</b> hai.</div>
    <div style="display:flex;gap:7px;flex-wrap:wrap">
      <button class="btn btn-green" style="flex:1" onclick="closeModal('tableModal');setTableStatus('${name}','occupied');showToast('✅ Customer seated!')">🪑 Seat Now</button>
      <button class="btn btn-red" style="flex:1" onclick="closeModal('tableModal');setTableStatus('${name}','available');showToast('❌ Reservation cancelled!')">Cancel</button>
    </div>`;
  } else if(status === 'cleaning'){
    bodyHtml += `<div style="font-size:12px;color:var(--ink2);margin-bottom:13px">${name} <b style="color:var(--blue)">Cleaning 🧹</b> chal raha hai.</div>
    <div style="display:flex;gap:7px">
      <button class="btn btn-green" style="flex:1" onclick="closeModal('tableModal');setTableStatus('${name}','available');showToast('✅ Table marked available!')">✅ Mark Available</button>
    </div>`;
  }

  document.getElementById('tableModalBody').innerHTML = bodyHtml;
  openModal('tableModal');
}

function setTableStatus(name, newStatus){
  const t=tableData.find(x=>x.no===name);
  if(t){ t.status=newStatus; buildTables(); refreshCartTableSelect(); }
}

// ===== ADD NEW TABLE =====
function doAddTable(){
  const name=document.getElementById('newTableName').value.trim();
  const seats=parseInt(document.getElementById('newTableSeats').value)||4;
  const status=document.getElementById('newTableStatus').value;
  if(!name){ showToast('⚠️ Table ka naam dalo!'); return; }
  if(tableData.find(t=>t.no===name)){ showToast('⚠️ Ye table already exist karta hai!'); return; }

  // Firebase mein save karo
  if(window._captainDb){
    import('https://www.gstatic.com/firebasejs/10.12.2/firebase-firestore.js').then(function(fb){
      var tableObj = {no:name, seats:seats, status:status, createdAt: Date.now()};
      fb.setDoc(fb.doc(window._captainDb, 'tables', name), tableObj)
        .then(function(){ showToast('✅ '+name+' Firebase mein save ho gaya! ('+seats+' seats)'); })
        .catch(function(e){ showToast('⚠️ Firebase error: '+e.message); });
    });
  } else {
    // Firebase ready nahi — sirf local
    tableData.push({no:name,seats:seats,status:status});
    buildTables();
    if(typeof refreshCartTableSelect==='function') refreshCartTableSelect();
    showToast('✅ '+name+' add ho gaya! ('+seats+' seats · '+statusLabel[status]+')');
  }
  closeModal('addTableModal');
  document.getElementById('newTableName').value='';
  document.getElementById('newTableSeats').value='';
}

// ===== MERGE TABLES =====
let mergeSelected=[];
function buildMergePicker(){
  const g=document.getElementById('mergeTablePicker'); if(!g)return;
  mergeSelected=[];
  g.innerHTML=tableData.slice(0,10).map((t)=>`
    <div onclick="toggleMerge(this,'${t.no}')" style="background:var(--white);border:2px solid var(--line);border-radius:8px;padding:8px;text-align:center;cursor:pointer;transition:.2s;font-size:11px;font-weight:600">
      ${t.no.replace('Table ','')}
    </div>`).join('');
}
function toggleMerge(el,name){
  if(mergeSelected.includes(name)){mergeSelected=mergeSelected.filter(x=>x!==name);el.style.borderColor='var(--line)';el.style.background='var(--white)';el.style.color='';}
  else{mergeSelected.push(name);el.style.borderColor='var(--G600)';el.style.background='rgba(34,197,94,.1)';el.style.color='var(--G600)';}
}
function doMerge(){
  if(mergeSelected.length<2){showToast('⚠️ Kam se kam 2 tables select karo!');return;}
  closeModal('mergeModal');
  showToast('🔗 Merged: '+mergeSelected.join(' + '));
}

