// Selected spicy levels per item
const selectedSpicy={};
// Selected portion (Full/Half) per item
const selectedPortion={};

// Per-dish instructions store
var dishInstructions = {};

// ── SPICE DROPDOWN ──
function toggleSpiceDropdown(id, event){
  event && event.stopPropagation();
  var dd = document.getElementById('spice-dd-'+id);
  if(!dd) return;
  // Close all other open dropdowns first
  document.querySelectorAll('.spice-dropdown-menu').forEach(function(el){
    if(el.id !== 'spice-dd-'+id) { el.style.display='none'; el.classList.remove('open'); }
  });
  var isOpen = dd.classList.contains('open');
  if(isOpen){ dd.style.display='none'; dd.classList.remove('open'); }
  else { dd.style.display='block'; dd.classList.add('open'); }
}

function selectSpiceDd(id, val, event){
  event && event.stopPropagation();
  selectedSpicy[id] = val;
  // Update trigger button label
  var label = document.getElementById('spice-label-'+id);
  var dot   = document.getElementById('spice-dot-'+id);
  if(label) label.textContent = val;
  // Update dots/checkmarks inside dropdown
  var dd = document.getElementById('spice-dd-'+id);
  if(dd){
    dd.querySelectorAll('.spice-dd-option').forEach(function(opt){
      var sel = opt.getAttribute('data-val') === val;
      opt.style.background = sel ? 'var(--G50)' : '';
      opt.style.color = sel ? 'var(--G700)' : 'var(--ink2)';
      opt.style.fontWeight = sel ? '800' : '600';
      var check = opt.querySelector('.spice-check');
      if(check) check.style.display = sel ? 'inline' : 'none';
    });
    dd.style.display='none'; dd.classList.remove('open');
  }
}

// Close dropdown on outside click
document.addEventListener('click', function(){ 
  document.querySelectorAll('.spice-dropdown-menu.open').forEach(function(el){
    el.style.display='none'; el.classList.remove('open');
  });
});

function toggleDishNote(id){
  var box = document.getElementById('dish-note-box-'+id);
  var arrow = document.getElementById('dish-note-arrow-'+id);
  var btn = document.getElementById('dish-note-btn-'+id);
  if(!box) return;
  var open = box.style.display === 'block';
  box.style.display = open ? 'none' : 'block';
  if(arrow) arrow.style.transform = open ? 'rotate(0deg)' : 'rotate(180deg)';
  if(btn){
    btn.style.background = open ? 'rgba(217,119,6,.08)' : 'rgba(217,119,6,.18)';
    btn.style.borderColor = open ? 'rgba(217,119,6,.3)' : 'rgba(217,119,6,.7)';
  }
  if(!open) setTimeout(()=>{ var t=document.getElementById('dish-note-txt-'+id); if(t) t.focus(); },80);
}

function saveDishNote(id){
  var t = document.getElementById('dish-note-txt-'+id);
  if(!t) return;
  dishInstructions[id] = t.value.trim();
  var indicator = document.getElementById('dish-note-indicator-'+id);
  if(indicator) indicator.style.display = dishInstructions[id] ? 'block' : 'none';
}

function renderOrderItem(item){
  const portion=selectedPortion[item.id]||'Full';
  const dispPrice=portion==='Half'?item.halfPrice:item.price;
  const curSpice=selectedSpicy[item.id]||item.spicy[0]||'Normal';
  const imgHtml = item._capImage
    ? `<img src="${item._capImage}" style="width:100%;height:90px;object-fit:cover;border-radius:10px 10px 0 0;display:block" onerror="this.style.display='none'">`
    : `<div class="order-item-img-placeholder">${item.emoji}</div>`;
  const savedNote = dishInstructions[item.id] || '';

  // Build spice options for dropdown
  const spiceOptions = item.spicy.map(s => {
    const selected = s === curSpice;
    return `<div class="spice-dd-option" data-val="${s}" onclick="selectSpiceDd(${item.id},'${s}',event)"
      style="display:flex;align-items:center;gap:7px;padding:7px 11px;cursor:pointer;border-radius:6px;font-size:12px;font-weight:${selected?'800':'600'};color:${selected?'var(--G700)':'var(--ink2)'};background:${selected?'var(--G50)':''};transition:.12s">
      <span>${getSpiceIcon(s)} ${s}</span>
      <span class="spice-check" style="display:${selected?'inline':'none'};margin-left:auto;color:var(--G600);font-size:13px">✓</span>
    </div>`;
  }).join('');

  return `<div class="order-item" data-cat="${item.cat}" data-id="${item.id}" style="position:relative">
    ${item.offer?`<div class="order-offer-badge">${item.offer}</div>`:''}
    ${imgHtml}
    <div class="order-item-body">
      <div class="order-item-name">${item.name}</div>
      <div class="order-item-price" id="price-disp-${item.id}">₹${dispPrice} ${item.discount?`<span style="font-size:10px;color:var(--red);margin-left:4px">${item.discount}</span>`:''}</div>
      <div style="font-size:10px;color:var(--ink3);margin-bottom:6px">${item.desc}</div>

      <!-- Portion + Spice row — same line pe compact -->
      <div style="display:flex;gap:5px;margin-bottom:8px;align-items:stretch">
        <button id="portion-full-${item.id}" onclick="selectPortion(${item.id},'Full',${item.price},${item.halfPrice},this)" style="flex:1;padding:4px 6px;border-radius:8px;border:1.5px solid ${portion==='Full'?'var(--G600)':'var(--line2)'};background:${portion==='Full'?'var(--G50)':'#fff'};color:${portion==='Full'?'var(--G700)':'var(--ink3)'};font-size:11px;font-weight:700;cursor:pointer;font-family:'Outfit',sans-serif;transition:.15s">🍽️ Full<br><span style="font-size:10px;font-weight:600">₹${item.price}</span></button>
        <button id="portion-half-${item.id}" onclick="selectPortion(${item.id},'Half',${item.price},${item.halfPrice},this)" style="flex:1;padding:4px 6px;border-radius:8px;border:1.5px solid ${portion==='Half'?'var(--amber)':'var(--line2)'};background:${portion==='Half'?'var(--amber-bg)':'#fff'};color:${portion==='Half'?'var(--amber)':'var(--ink3)'};font-size:11px;font-weight:700;cursor:pointer;font-family:'Outfit',sans-serif;transition:.15s">🥣 Half<br><span style="font-size:10px;font-weight:600">₹${item.halfPrice}</span></button>

        <!-- 🌶️ SPICE DROPDOWN — compact, corner -->
        <div style="position:relative;flex-shrink:0" onclick="event.stopPropagation()">
          <button onclick="toggleSpiceDropdown(${item.id},event)" title="Spice Level"
            style="height:100%;min-height:42px;padding:4px 8px;border-radius:8px;border:1.5px solid rgba(239,68,68,.3);background:rgba(239,68,68,.06);cursor:pointer;font-family:'Outfit',sans-serif;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:2px;transition:.15s;min-width:46px">
            <span style="font-size:14px;line-height:1">${getSpiceIcon(curSpice)||'🌶️'}</span>
            <span id="spice-label-${item.id}" style="font-size:9px;font-weight:800;color:#dc2626;max-width:42px;overflow:hidden;white-space:nowrap;text-overflow:ellipsis">${curSpice}</span>
            <span style="font-size:8px;color:#dc2626;line-height:1">▼</span>
          </button>
          <!-- Dropdown menu -->
          <div id="spice-dd-${item.id}" class="spice-dropdown-menu" style="display:none;position:absolute;bottom:calc(100% + 5px);right:0;min-width:148px;background:#fff;border:1.5px solid rgba(0,0,0,.1);border-radius:10px;box-shadow:0 8px 24px rgba(0,0,0,.13);z-index:999;overflow:hidden;padding:4px">
            <div style="font-size:10px;font-weight:800;color:var(--ink4);padding:6px 11px 4px;text-transform:uppercase;letter-spacing:.8px">🌶️ Spice Level</div>
            ${spiceOptions}
          </div>
        </div>
      </div>

      <!-- ── CHEF NOTE DROPDOWN ── -->
      <div style="margin-bottom:7px">
        <button id="dish-note-btn-${item.id}" onclick="toggleDishNote(${item.id})" style="width:100%;display:flex;align-items:center;gap:5px;padding:5px 9px;border-radius:8px;border:1.5px dashed rgba(217,119,6,.3);background:rgba(217,119,6,.06);cursor:pointer;font-family:'Outfit',sans-serif;transition:.18s;position:relative">
          <span style="font-size:12px">📝</span>
          <span style="font-size:11px;font-weight:700;color:var(--amber);flex:1;text-align:left">Chef Note</span>
          <span id="dish-note-indicator-${item.id}" style="display:${savedNote?'block':'none'};width:7px;height:7px;border-radius:50%;background:var(--amber);flex-shrink:0"></span>
          <span id="dish-note-arrow-${item.id}" style="font-size:10px;color:var(--amber);transition:transform .22s;transform:${savedNote?'rotate(180deg)':'rotate(0deg)'}">▼</span>
        </button>
        <div id="dish-note-box-${item.id}" style="display:${savedNote?'block':'none'};margin-top:5px;animation:dishNoteSlide .2s ease">
          <textarea id="dish-note-txt-${item.id}" oninput="saveDishNote(${item.id})" placeholder="e.g. Extra cheese, No onion, Less spicy..." style="width:100%;border:1.5px solid rgba(217,119,6,.35);border-radius:8px;padding:7px 9px;font-size:11px;font-family:'Outfit',sans-serif;color:var(--ink);background:#fffbeb;resize:none;height:54px;outline:none;box-sizing:border-box;line-height:1.4">${savedNote}</textarea>
        </div>
      </div>

      <button class="order-item-add" onclick="addToCart('${item.name}',${item.price},${item.halfPrice},${item.id})">+ Add</button>
    </div>
  </div>`;
}

function getSpiceIcon(s){
  const icons={'Jain':'🌱','Normal':'😊','Spicy':'🌶️','Medium':'🌶️','Extra Spicy':'🔥🔥','Mild':'🌿','Extra Sweet':'🍯'};
  return icons[s]||'';
}

function selectSpicy(id,val,btn){
  selectedSpicy[id]=val;
  const parent=btn.closest('.order-item-spice');
  parent.querySelectorAll('.spice-btn').forEach(b=>b.classList.remove('selected'));
  btn.classList.add('selected');
}

function selectPortion(id,portion,fullPrice,halfPrice,btn){
  selectedPortion[id]=portion;
  const price=portion==='Half'?halfPrice:fullPrice;
  // Update price display
  const pd=document.getElementById('price-disp-'+id);
  if(pd){ const disc=pd.querySelector('span'); pd.innerHTML='₹'+price+(disc?` <span style="font-size:10px;color:var(--red);margin-left:4px">${disc.textContent}</span>`:''); }
  // Update Full button style
  const fullBtn=document.getElementById('portion-full-'+id);
  const halfBtn=document.getElementById('portion-half-'+id);
  if(fullBtn){
    fullBtn.style.borderColor=portion==='Full'?'var(--G600)':'var(--line2)';
    fullBtn.style.background=portion==='Full'?'var(--G50)':'#fff';
    fullBtn.style.color=portion==='Full'?'var(--G700)':'var(--ink3)';
  }
  if(halfBtn){
    halfBtn.style.borderColor=portion==='Half'?'var(--amber)':'var(--line2)';
    halfBtn.style.background=portion==='Half'?'var(--amber-bg)':'#fff';
    halfBtn.style.color=portion==='Half'?'var(--amber)':'var(--ink3)';
  }
}

function buildOrderMenu(items){
  const g=document.getElementById('orderMenu'); if(!g) return;
  g.innerHTML=items.map(renderOrderItem).join('');
  if(typeof _updateMenuCountBadge==='function') _updateMenuCountBadge();
}

function filterCat(cat, btn){
  document.querySelectorAll('#catBtns .btn').forEach(b=>{b.className='btn btn-outline';});
  btn.className='btn btn-green';
  const filtered=cat==='all'?menuItems:menuItems.filter(i=>i.cat===cat);
  buildOrderMenu(filtered);
}
buildOrderMenu(menuItems);

// ===== LIVE MENU BUILD =====
function buildLiveMenu(items){
  const g=document.getElementById('liveMenuGrid'); if(!g) return;
  const active=items.filter(i=>i.active!==false);
  g.innerHTML=active.map(item=>{
    const imgHtml = item._capImage
      ? `<img src="${item._capImage}" style="width:100%;height:110px;object-fit:cover;border-radius:10px 10px 0 0;display:block" onerror="this.style.display='none'">`
      : `<div class="menu-item-img-placeholder">${item.emoji}</div>`;
    return `
    <div class="menu-item" data-menucat="${item.cat}">
      ${item.offer?`<div class="menu-offer-tag">${item.offer}</div>`:''}
      ${item.discount?`<div class="menu-discount-tag">${item.discount}</div>`:''}
      ${imgHtml}
      <div class="menu-item-body">
        <div class="menu-item-info">
          <div class="menu-cat">${item.cat.charAt(0).toUpperCase()+item.cat.slice(1)}</div>
          <div class="menu-name">${item.name}</div>
          <div style="font-size:10px;color:var(--ink3);margin:2px 0 4px">${item.desc}</div>
          <div style="display:flex;gap:6px;margin-bottom:4px;align-items:center">
            <span style="font-size:12px;font-weight:900;color:var(--G700);font-family:'JetBrains Mono',monospace">🍽️ ₹${item.price}</span>
            <span style="font-size:10px;color:var(--ink4);font-weight:500">Full</span>
            <span style="font-size:11px;color:var(--ink4)">|</span>
            <span style="font-size:12px;font-weight:900;color:var(--amber);font-family:'JetBrains Mono',monospace">🥣 ₹${item.halfPrice}</span>
            <span style="font-size:10px;color:var(--ink4);font-weight:500">Half</span>
          </div>
          <div style="display:flex;gap:4px;margin-top:4px;flex-wrap:wrap">
            ${item.spicy.map(s=>`<span style="font-size:9px;padding:2px 6px;border-radius:20px;background:var(--bg2);border:1px solid var(--line);color:var(--ink3)">${getSpiceIcon(s)} ${s}</span>`).join('')}
          </div>
        </div>
        <div class="menu-avail"><div class="toggle on" onclick="this.classList.toggle('on')"></div></div>
      </div>
    </div>`;
  }).join('');
}
buildLiveMenu(menuItems);

function filterMenuCat(cat, btn){
  document.querySelectorAll('#page-livemenu .btn').forEach(b=>b.className='btn btn-outline');
  btn.className='btn btn-green';
  const items=cat==='all'?menuItems:menuItems.filter(i=>i.cat===cat);
  // Use _capRebuildLiveMenu so images (added by captain) bhi dikhen
  if(typeof _capRebuildLiveMenu==='function') _capRebuildLiveMenu(items);
  else buildLiveMenu(items);
}

// ===== CART =====
let cart=[];
function addToCart(name,fullPrice,halfPrice,id){
  const spice=selectedSpicy[id]||'Normal';
  const portion=selectedPortion[id]||'Full';
  const price=portion==='Half'?halfPrice:fullPrice;
  const note=(dishInstructions&&dishInstructions[id])||'';
  const key=name+'|'+spice+'|'+portion;
  const ex=cart.find(i=>i.key===key);
  if(ex){ ex.qty++; if(note) ex.note=note; }
  else cart.push({key,name,price,qty:1,spice,portion,note,menuId:id});
  renderCart(); showToast('✅ '+name+' ('+portion+', '+spice+') added!');
}
function renderCart(){
  const el=document.getElementById('cartItems');
  const cnt=document.getElementById('cartCount');
  const tot=document.getElementById('cartTotal');
  if(!cart.length){el.innerHTML='<div style="text-align:center;padding:18px;color:var(--ink3);font-size:12px">No items added yet</div>';cnt.textContent='(0 items)';tot.textContent='₹0';document.getElementById('gstAmt').textContent='₹0';document.getElementById('svcAmt').textContent='₹0';document.getElementById('grandTotal').textContent='₹0';return;}
  let sub=0;
  el.innerHTML=cart.map((it,i)=>{sub+=it.price*it.qty;return`<div class="cart-item"><div class="cart-item-qty"><div class="qty-btn" onclick="changeQty(${i},-1)">−</div><span style="font-size:12px;font-weight:600;min-width:16px;text-align:center">${it.qty}</span><div class="qty-btn" onclick="changeQty(${i},1)">+</div></div><div class="cart-item-name">${it.name}<br><span style="font-size:10px;color:var(--ink3)">${it.portion==='Half'?'🥣 Half':'🍽️ Full'} · ${getSpiceIcon(it.spice)} ${it.spice}</span>${it.note?`<br><span style="font-size:10px;color:var(--amber);display:inline-flex;align-items:center;gap:3px;margin-top:1px">📝 <i>${it.note}</i></span>`:''}</div><div class="cart-item-price">₹${it.price*it.qty}</div></div>`;}).join('');
  const gst=Math.round(sub*0.05); const svc=Math.round(sub*0.10);
  cnt.textContent=`(${cart.reduce((a,i)=>a+i.qty,0)} items)`;
  tot.textContent='₹'+sub;
  document.getElementById('gstAmt').textContent='₹'+gst;
  document.getElementById('svcAmt').textContent='₹'+svc;
  document.getElementById('grandTotal').textContent='₹'+(sub+gst+svc);
}
function changeQty(i,d){
  cart[i].qty+=d;
  if(cart[i].qty<=0) cart.splice(i,1);
  renderCart();
}

// Cart table select — only available tables
function refreshCartTableSelect(){
  const sel=document.getElementById('cartTableSelect'); if(!sel) return;
  const avail=tableData.filter(t=>t.status==='available');
  sel.innerHTML='<option value="">-- Table Select Karo --</option>'+avail.map(t=>`<option value="${t.no}">${t.no} (${t.seats} seats)</option>`).join('');
}
refreshCartTableSelect();

function openNewOrderForTable(tableName){
  showPage('orderplace',null);
  const sel=document.getElementById('cartTableSelect');
  if(sel){
    const found=[...sel.options].find(o=>o.value===tableName);
    if(found) sel.value=tableName;
  }
}

// ── DUPLICATE ORDER GUARD — same table pe 10 sec mein dobara order nahi ──
let _lastOrderTableTime = {};

async function placeOrder(){
  if(!cart.length){showToast('⚠️ Cart me items add karo pehle!');return;}
  const tbl = (typeof getSelectedTable==='function') ? getSelectedTable() : document.getElementById('cartTableSelect')?.value;
  if(!tbl){showToast('⚠️ Table select karo ya manually type karo!');return;}
  const instruct = document.getElementById('chefInstructions')?.value || '';
  const custName = document.getElementById('cartCustomerName')?.value?.trim() || 'Dine-In Customer';
  const num = 1050 + Math.floor(Math.random()*50);

  // ── DUPLICATE PREVENTION: same table ke liye 10 seconds mein dobara order nahi ──
  const now = Date.now();
  if(_lastOrderTableTime[tbl] && (now - _lastOrderTableTime[tbl]) < 10000){
    showToast('⚠️ Is table ka order abhi process ho raha hai. Thoda wait karo!', '#f59e0b');
    return;
  }
  _lastOrderTableTime[tbl] = now;

  // Mark table as occupied
  const td = tableData.find(t=>t.no===tbl);
  if(td) setTableStatus(tbl,'occupied');

  // ── SNAPSHOT: cart clear hone se pehle save kar lo ──
  const cartSnapshot = [...cart];

  // ── BUILD ITEMS ARRAY ──
  const firebaseItems = cartSnapshot.map(i=>{
    let resolvedPrice = parseFloat(i.price) || 0;
    if(resolvedPrice === 0 && window._billingMenuPriceMap){
      const key = (i.name||'').toLowerCase().trim();
      resolvedPrice = window._billingMenuPriceMap[key] || 0;
    }
    return {
      name: i.name, qty: i.qty, price: resolvedPrice,
      spice: i.spice||'Normal', portion: i.portion||'Full',
      spiceLevel: i.spice||'Normal',
      customInstruction: i.note || (i.portion&&i.portion!=='Full'?`Portion: ${i.portion}`:'')
    };
  });
  const total = firebaseItems.reduce((a,i)=>a+(i.price*i.qty),0);

  const orderPayload = {
    tableNumber:    String(tbl),
    customerName:   custName,
    items:          firebaseItems,
    notes:          instruct||'',
    status:         'pending',
    source:         'captain',
    _source:        'captain',
    orderNumber:    '#'+num,
    totalAmount:    total,
    timestamp:      new Date().toISOString(),
    createdAt:      Date.now(),
    _chefAlerted:   false,
    chefReadyNotified: false,
    chefNotified:   true,
    chefPanelAlert: true,
    sentToChef:     true,
    chefAlertTime:  new Date().toISOString()
  };

  // Cart clear + UI reset — Firebase save se PEHLE karo
  cart=[]; renderCart();
  if(document.getElementById('chefInstructions')) document.getElementById('chefInstructions').value='';
  if(document.getElementById('cartTableManual')) document.getElementById('cartTableManual').value='';
  if(document.getElementById('cartCustomerName')) document.getElementById('cartCustomerName').value='';
  if(document.getElementById('selectedTableShow')) document.getElementById('selectedTableShow').textContent='📍 Koi table select nahi';
  const cartTableSel = document.getElementById('cartTableSelect');
  if(cartTableSel) cartTableSel.value = '';
  if(typeof refreshCartTableSelect==='function') refreshCartTableSelect();

  // ── FIREBASE SAVE + RETRY LOGIC ──
  async function _doFirebaseSave(){
    const db  = window._captainDb  || _captainDb;
    const col = window._captainCollection || _captainCollection;
    const add = window._captainAddDoc     || _captainAddDoc;
    if(!db || !col || !add) throw new Error('Firebase not ready');

    const docRef = await add(col(db,'orders'), orderPayload);
    // chefOrders collection mein bhi save karo
    try{
      await add(col(db,'chefOrders'), Object.assign({}, orderPayload, {
        orderId: docRef.id,
        chefStatus: 'new',
        priority: 'normal',
        chefReceivedAt: Date.now()
      }));
    }catch(ce){ console.warn('chefOrders save failed:', ce.message); }
    return docRef;
  }

  // ── FIREBASE INIT WAIT: max 6 seconds, 500ms interval ──
  let fbReady = !!(window._captainDb || _captainDb);
  if(!fbReady){
    showToast('⏳ Firebase connect ho raha hai... (2 sec)','#f59e0b');
    await new Promise(resolve=>{
      let tries=0;
      const poll = setInterval(()=>{
        tries++;
        if(window._captainDb || _captainDb){ clearInterval(poll); resolve(); }
        else if(tries>=12){ clearInterval(poll); resolve(); } // 6 sec max
      },500);
    });
  }

  // ── ATTEMPT SAVE ──
  try{
    await _doFirebaseSave();
    showToast('✅ Order #'+num+' — Firebase mein save! Chef ko bhej diya 🍳','#059669');
    _autoPointsFromOrder && _autoPointsFromOrder(custName, total);
    // ── GIRL VOICE: order place hone pe bolta hai ──
    captainSpeak('New order aaya hai! ' + custName + ' ka order place ho gaya. Table ' + tbl + ', Order number ' + num + '.');
  }catch(e){
    console.error('[PlaceOrder] Firebase error:', e.message);
    showToast('⚠️ Firebase error: '+e.message+' — Local mein save kiya','#f59e0b');
    // ── LOCAL FALLBACK: customer name + items ke saath ──
    _placeOrderLocalFallback(num, tbl, custName, instruct, cartSnapshot, total);
    // ── GIRL VOICE: local save hone pe bhi bolegi ──
    captainSpeak('New order aaya hai! ' + custName + ' ka order number ' + num + ', Table ' + tbl + ' local mein save ho gaya.');
  }

  // Captain kitchen card locally bhi add karo (turant feedback)
  addKitchenCard(num, tbl, cartSnapshot.map(i=>`${i.name} ×${i.qty} [${i.spice||'Normal'}]`).join(', '), custName, cartSnapshot);
}

function _placeOrderLocalFallback(num, tbl, custName, instruct, cartItems, total){
  // Firebase nahi — local array + table mein add karo WITH customer name + items
  cartItems = cartItems || [];
  total = total || cartItems.reduce((a,i)=>a+(i.price*i.qty),0);

  // _captainFirebaseOrders mein bhi add karo taaki renderCaptainLiveOrders() mein dikhe
  const localOrder = {
    _fbId: 'local-'+num,
    _isLocal: true,
    tableNumber: String(tbl),
    customerName: custName,
    items: cartItems.map(i=>({ name:i.name, qty:i.qty, price:i.price||0, spiceLevel:i.spice||'Normal', customInstruction:i.portion&&i.portion!=='Full'?'Portion: '+i.portion:'' })),
    notes: instruct||'',
    status: 'pending',
    source: 'captain',
    _source: 'captain',
    orderNumber: '#'+num,
    totalAmount: total,
    timestamp: new Date().toISOString(),
    createdAt: Date.now()
  };
  // Array ke shuru mein add karo
  _captainFirebaseOrders.unshift(localOrder);
  // Live Orders table refresh karo
  if(typeof renderCaptainLiveOrders==='function') renderCaptainLiveOrders();
  if(typeof updateCaptainDashboardCounts==='function') updateCaptainDashboardCounts();

  showToast('⚠️ Order #'+num+' local mein save hua (Firebase sync pending)','#f59e0b');
}

// ══════════════════════════════════════════════════════════
// SHARED HELPER — Kitchen dish image rows build karo
// Ultra-pro design: real image left, premium detail right
// Works for BOTH local cart orders AND Firebase orders
// ══════════════════════════════════════════════════════════

// Food image map — curated Unsplash food photos per item keyword
const _kitchenFoodImages = {
  'margherita':  'https://images.unsplash.com/photo-1574071318508-1cdbab80d002?w=200&h=200&fit=crop',
  'pepperoni':   'https://images.unsplash.com/photo-1565299624946-b28f40a0ae38?w=200&h=200&fit=crop',
  'pizza':       'https://images.unsplash.com/photo-1513104890138-7c749659a591?w=200&h=200&fit=crop',
  'burger':      'https://images.unsplash.com/photo-1568901346375-23c9450c58cd?w=200&h=200&fit=crop',
  'pasta':       'https://images.unsplash.com/photo-1621996346565-e3dbc646d9a9?w=200&h=200&fit=crop',
  'alfredo':     'https://images.unsplash.com/photo-1621996346565-e3dbc646d9a9?w=200&h=200&fit=crop',
  'arrabbiata':  'https://images.unsplash.com/photo-1598866594230-a7c12756260f?w=200&h=200&fit=crop',
  'salad':       'https://images.unsplash.com/photo-1512621776951-a57141f2eefd?w=200&h=200&fit=crop',
  'wrap':        'https://images.unsplash.com/photo-1626700051175-6818013e1d4f?w=200&h=200&fit=crop',
  'chicken':     'https://images.unsplash.com/photo-1598103442097-8b74394b95c2?w=200&h=200&fit=crop',
  'fries':       'https://images.unsplash.com/photo-1630431341973-02e1b662ec35?w=200&h=200&fit=crop',
  'cheesecake':  'https://images.unsplash.com/photo-1567171466295-4afa63d45416?w=200&h=200&fit=crop',
  'cake':        'https://images.unsplash.com/photo-1563729784474-d77dbb933a9e?w=200&h=200&fit=crop',
  'ice cream':   'https://images.unsplash.com/photo-1497034825429-c343d7c6a68f?w=200&h=200&fit=crop',
  'juice':       'https://images.unsplash.com/photo-1600271886742-f049cd451bba?w=200&h=200&fit=crop',
  'coffee':      'https://images.unsplash.com/photo-1517701550927-30cf4ba1dba5?w=200&h=200&fit=crop',
  'combo':       'https://images.unsplash.com/photo-1504674900247-0877df9cc836?w=200&h=200&fit=crop',
};

function _kitchenGetFoodImage(name, menuItem) {
  // 1. Priority: real uploaded image from menu
  if (menuItem && menuItem._capImage) return menuItem._capImage;
  // 2. Keyword match in curated map
  const nameLow = (name||'').toLowerCase();
  for (const key in _kitchenFoodImages) {
    if (nameLow.includes(key)) return _kitchenFoodImages[key];
  }
  // 3. No image — return null (emoji fallback)
  return null;
}

function buildKitchenDishRows(cartItems, itemsStr) {
  function spiceLabelIcon(s){
    if(s==='Extra Spicy') return {icon:'🔥',label:'Extra Spicy',color:'#dc2626',bg:'rgba(220,38,38,.08)'};
    if(s==='Spicy')       return {icon:'🌶️',label:'Spicy',      color:'#f97316',bg:'rgba(249,115,22,.08)'};
    if(s==='Medium')      return {icon:'🌶️',label:'Medium',     color:'#f59e0b',bg:'rgba(245,158,11,.08)'};
    if(s==='Jain')        return {icon:'🌱',label:'Veg',         color:'#16a34a',bg:'rgba(22,163,74,.08)'};
    return                       {icon:'😊',label:'Normal',      color:'#6b7280',bg:'rgba(107,114,128,.08)'};
  }
  function findMenuItem(name, id){
    if(typeof menuItems === 'undefined') return null;
    return menuItems.find(m => m.name===name || (id && m.id===id) || (name && m.name && m.name.toLowerCase()===name.toLowerCase()));
  }
  function buildDishCard(name, qty, spice, portion, price, menuItem){
    const sl = spiceLabelIcon(spice || 'Normal');
    const portionText = portion==='Half' ? '🥣 Half Portion' : '🍽️ Classic · Full Size';
    const priceText = (price && price > 0) ? `₹${(price * (qty||1)).toLocaleString('en-IN')}` : '';
    const emoji = menuItem ? (menuItem.emoji||'🍽️') : '🍽️';
    const realImg = _kitchenGetFoodImage(name, menuItem);

    const thumbHtml = realImg
      ? `<img src="${realImg}" alt="${name}" style="width:100%;height:100%;object-fit:cover;display:block;border-radius:0"
           onerror="this.style.display='none';this.nextElementSibling.style.display='flex'">`
        + `<div class="kitchen-dish-thumb-emoji" style="display:none;position:absolute;inset:0;align-items:center;justify-content:center">${emoji}</div>`
      : `<div class="kitchen-dish-thumb-emoji">${emoji}</div>`;

    return `<div class="kitchen-dish-row">
      <div class="kitchen-dish-thumb">${thumbHtml}</div>
      <div class="kitchen-dish-body">
        <div>
          <div class="kitchen-dish-name">${name}</div>
          <div class="kitchen-dish-sub">${portionText}</div>
        </div>
        <div class="kitchen-dish-tags">
          <span class="kitchen-dish-qty">${qty||1}x</span>
          <span class="kitchen-dish-spice-tag" style="color:${sl.color};background:${sl.bg};border-color:${sl.color}40">${sl.icon} ${sl.label}</span>
          ${priceText ? `<span class="kitchen-dish-price">${priceText}</span>` : ''}
        </div>
      </div>
    </div>`;
  }

  let html = '<div class="kitchen-dish-list">';
  if(cartItems && cartItems.length){
    html += cartItems.map(i => {
      const mi = findMenuItem(i.name, i.id);
      return buildDishCard(i.name, i.qty, i.spice, i.portion, i.price, mi);
    }).join('');
  } else if(itemsStr){
    html += itemsStr.split(',').map(part => {
      part = part.trim();
      const m = part.match(/^(.*?)\s*[×x](\d+)$/i);
      const rawName = m ? m[1] : part;
      const name = rawName.replace(/^[\s🍕🍔🍜🥗🌯🍰🥤☕🍟🍱🍲🥘🫕]+/,'').trim();
      const qty  = m ? parseInt(m[2]) : 1;
      const mi = findMenuItem(name);
      return buildDishCard(name||part, qty, 'Normal', 'Full', 0, mi);
    }).join('');
  }
  html += '</div>';
  return html;
}

function addKitchenCard(orderNum, tableNo, itemsStr, customerName, cartItems){
  const grid = document.getElementById('kitchenCardsGrid');
  if(!grid){ console.warn('kitchenCardsGrid not found'); return; }
  const cardId = 'kc-new'+orderNum;

  // Use shared helper — screenshot-exact dish image rows
  const itemRowsHtml = buildKitchenDishRows(cartItems, itemsStr);

  const div = document.createElement('div');
  div.className = 'kitchen-card';
  div.id = cardId;
  div.setAttribute('data-order','#'+orderNum);
  div.setAttribute('data-table',tableNo);
  div.setAttribute('data-customer', customerName||'Customer');
  div.setAttribute('data-set-time','0');
  div.innerHTML = `
    <div class="kitchen-card-head">
      <div>
        <div class="kitchen-order-no">#${orderNum}</div>
        <div style="font-size:10px;color:var(--G600);font-weight:700;margin-top:2px">🪑 ${tableNo}</div>
        <div style="font-size:10px;color:var(--ink3);font-weight:600;margin-top:1px">👤 ${customerName||'Customer'}</div>
      </div>
      <div class="kitchen-timer ok kc-timer" id="kt-new${orderNum}" style="display:none"></div>
    </div>
    <div class="kitchen-items">${itemRowsHtml}</div>
    <div class="kitchen-actions">
      <button class="btn btn-outline" style="font-size:10px" onclick="openKitTimeModal('${cardId}')">⏱️ Time Set</button>
      <button class="btn btn-outline" onclick="kitDelay('${cardId}')">⚠️ Delay</button>
      <button class="btn btn-green kit-ready-btn" onclick="kitMarkReady('${cardId}')">✅ Mark Ready</button>
    </div>`;
  grid.insertBefore(div, grid.firstChild);
  kitStartTimer(cardId);
  updateKitchenCounts();

  // ── TIMER REMINDER: 40 seconds baad check karo — agar timer set nahi toh girl bolegi ──
  (function(cId, tbl, cust) {
    setTimeout(function() {
      var c = document.getElementById(cId);
      if (c && (!c.getAttribute('data-set-time') || c.getAttribute('data-set-time') === '0')) {
        if (typeof captainSpeak === 'function') {
          captainSpeak('Captain! Table ' + tbl + ' ka timer abhi tak set nahi hua. ' + cust + ' wait kar rahe hain. Please timer set karein.');
        }
        // Doosra reminder 40 sec baad
        setTimeout(function() {
          var c2 = document.getElementById(cId);
          if (c2 && (!c2.getAttribute('data-set-time') || c2.getAttribute('data-set-time') === '0')) {
            if (typeof captainSpeak === 'function') {
              captainSpeak('Captain ji! Table ' + tbl + ' ke liye timer set karna zaroori hai. ' + cust + ' ka order kitchen mein pending hai.');
            }
          }
        }, 40000);
      }
    }, 40000);
  })(cardId, tableNo, customerName || 'Customer');

  // ── ORDER CONFIRMATION POPUP ──
  _showOrderConfirmPopup(orderNum, tableNo, customerName, cartItems||[], itemsStr);
}

function _showOrderConfirmPopup(orderNum, tableNo, customerName, cartItems, itemsStr){
  // Remove any existing popup
  var old = document.getElementById('_orderConfirmPopup');
  if(old) old.remove();

  var total = cartItems.length ? cartItems.reduce(function(a,i){return a+i.price*i.qty;},0) : 0;
  var itemList = cartItems.length
    ? cartItems.map(function(i){
        var spiceIcon = i.spice==='Extra Spicy'?'🔥🔥':i.spice==='Spicy'?'🌶️':i.spice==='Medium'?'🌶️':i.spice==='Jain'?'🌱':'😊';
        return '<div style="display:flex;justify-content:space-between;padding:5px 0;border-bottom:1px solid #f3f4f6;font-size:12px;gap:8px">'
          +'<span style="flex:1;font-weight:600">'+i.name+' ×'+i.qty+'</span>'
          +'<span style="color:#6b7280;font-size:11px">'+spiceIcon+' '+i.spice+'</span>'
          +'<span style="font-weight:700;color:#059669;min-width:50px;text-align:right">₹'+(i.price*i.qty)+'</span>'
          +'</div>';
      }).join('')
    : itemsStr.split(', ').map(function(i){return '<div style="padding:5px 0;border-bottom:1px solid #f3f4f6;font-size:12px">'+i+'</div>';}).join('');

  var popup = document.createElement('div');
  popup.id = '_orderConfirmPopup';
  popup.style.cssText = 'position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,.45);backdrop-filter:blur(6px);z-index:99999;display:flex;align-items:center;justify-content:center;animation:fadeIn .2s ease';
  popup.innerHTML = '<div style="background:#fff;border-radius:20px;padding:28px;max-width:420px;width:90%;box-shadow:0 20px 60px rgba(0,0,0,.2);animation:slideUp .3s cubic-bezier(.34,1.56,.64,1)">'
    +'<div style="text-align:center;margin-bottom:18px">'
      +'<div style="width:56px;height:56px;background:#ecfdf5;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:28px;margin:0 auto 10px">✅</div>'
      +'<div style="font-size:18px;font-weight:900;color:#0f172a;letter-spacing:-.4px">Order Placed!</div>'
      +'<div style="font-size:12px;color:#6b7280;margin-top:3px">Kitchen Command mein add ho gaya</div>'
    +'</div>'
    +'<div style="background:#f9fafb;border-radius:12px;padding:14px;margin-bottom:14px">'
      +'<div style="display:flex;justify-content:space-between;margin-bottom:8px">'
        +'<span style="font-size:12px;font-weight:800;color:#047857">Order #'+orderNum+'</span>'
        +'<span style="font-size:12px;font-weight:700;color:#374151">🪑 '+tableNo+'</span>'
      +'</div>'
      +'<div style="font-size:11px;color:#6b7280;margin-bottom:8px">👤 '+customerName+'</div>'
      +itemList
      +(total>0?'<div style="display:flex;justify-content:space-between;padding-top:8px;font-size:13px;font-weight:800;color:#059669"><span>Total</span><span>₹'+total+'</span></div>':'')
    +'</div>'
    +'<div style="display:flex;gap:8px">'
      +'<button onclick="document.getElementById(\'_orderConfirmPopup\').remove()" style="flex:1;padding:11px;background:#f3f4f6;border:none;border-radius:10px;font-size:13px;font-weight:700;cursor:pointer;font-family:\'Outfit\',sans-serif;color:#374151">Close</button>'
      +'<button onclick="document.getElementById(\'_orderConfirmPopup\').remove();showPage(\'kitchen\',document.querySelector(\'.nav-item[onclick*=kitchen]\')||null)" style="flex:2;padding:11px;background:#047857;color:#fff;border:none;border-radius:10px;font-size:13px;font-weight:800;cursor:pointer;font-family:\'Outfit\',sans-serif">🍳 Kitchen dekhein</button>'
    +'</div>'
  +'</div>';

  // Add slide-up animation style if not already
  if(!document.getElementById('_confirmAnimStyle')){
    var s = document.createElement('style');
    s.id = '_confirmAnimStyle';
    s.textContent = '@keyframes fadeIn{from{opacity:0}to{opacity:1}}@keyframes slideUp{from{opacity:0;transform:translateY(30px) scale(.95)}to{opacity:1;transform:translateY(0) scale(1)}}';
    document.head.appendChild(s);
  }

  // Close on backdrop click
  popup.addEventListener('click', function(e){ if(e.target===popup) popup.remove(); });
  document.body.appendChild(popup);

  // Auto close after 8 seconds
  setTimeout(function(){ if(document.getElementById('_orderConfirmPopup')) document.getElementById('_orderConfirmPopup').remove(); }, 8000);
}

// ===== KOT =====
function openKOT(){
  const num='#10'+Math.floor(40+Math.random()*10);
  const tbl=document.getElementById('cartTableSelect')?document.getElementById('cartTableSelect').value||'Table 4':'Table 4';
  const instruct=document.getElementById('chefInstructions')?document.getElementById('chefInstructions').value:'';
  const time=new Date().toLocaleTimeString();
  document.getElementById('kotBody').innerHTML=`<b>KOT — Kitchen Order Ticket</b><br>
──────────────────────<br>
Order: <b>${num}</b> · ${tbl}<br>
Time: ${time}<br>
Captain: Muhammad Farhan<br>
──────────────────────<br>
${cart.length?cart.map(i=>`${i.name} × ${i.qty} [${i.spice}]`).join('<br>'):
'🍕 Margherita × 2 [Spicy]<br>🥤 Fresh Juice × 2 [Normal]'}
<br>──────────────────────<br>
Chef Note: <b>${instruct||'None'}</b>`;
  openModal('kotModal');
}

// ===== BILL PRINT + AUTO TABLE FREE =====
let billActiveTable='';
// ===== FULL BILL MODAL — FIREBASE REAL DATA =====
let _activeBillTableName = '';
let _activeBillFbOrderId = '';

function captainOpenFullBill(tableName){
  _activeBillTableName = tableName;
  const tNum = parseInt(String(tableName).replace(/\D/g,'')) || 0;
  const liveOrder = _billingLiveOrders[tNum] || null;
  const tObj = tableData.find(x=>x.no===tableName) || {};

  const custName  = liveOrder ? (liveOrder.customerName||liveOrder.name||'Walk-in') : (tObj.customerName||'Walk-in');
  const custPhone = liveOrder ? (liveOrder.customerPhone||liveOrder.phone||'') : (tObj.customerPhone||'');
  const rawItems  = liveOrder ? (liveOrder.items||liveOrder.currentOrder||[]) : (tObj.order||tObj.currentOrder||[]);

  // ── PRICE FIX: price=0 items ke liye billing menu se price lookup ──
  const items = rawItems.map(function(i){
    const p = parseFloat(i.price)||parseFloat(i.rate)||0;
    if(p > 0) return i;
    const key = (i.name||i.dish||'').toLowerCase().trim();
    const mappedPrice = (window._billingMenuPriceMap && window._billingMenuPriceMap[key]) || 0;
    if(mappedPrice > 0) return Object.assign({}, i, {price: mappedPrice, rate: mappedPrice});
    return i;
  });
  const billNum   = liveOrder ? (liveOrder.billNumber||liveOrder.billNum||liveOrder.orderNumber||'—') : '—';
  const orderTime = liveOrder ? (liveOrder.timestamp||liveOrder.time||liveOrder.createdAt||'') : '';
  _activeBillFbOrderId = liveOrder ? (liveOrder._fbId||'') : '';

  const now = new Date();
  const timeStr = orderTime ? new Date(orderTime).toLocaleTimeString('en-IN',{hour:'2-digit',minute:'2-digit'}) : now.toLocaleTimeString('en-IN',{hour:'2-digit',minute:'2-digit'});
  const dateStr = now.toLocaleDateString('en-IN',{day:'2-digit',month:'short',year:'numeric'});

  const subtotal = items.reduce ? items.reduce((s,i)=>s+((parseFloat(i.price)||parseFloat(i.rate)||0)*(parseInt(i.qty)||parseInt(i.quantity)||1)),0) : 0;
  const gst  = Math.round(subtotal * (_gstRate||0.05));
  const svc  = Math.round(subtotal * (_svcRate||0.10));
  const total = subtotal + gst + svc;

  // Build bill HTML
  // Restaurant info — window._captainRS se (loaded by _loadSettingsFromFirebase)
  let _RS = window._captainRS || window.RS || {};
  if(!_RS.name) {
    // Fallback: direct localStorage read
    try {
      const _lsData = localStorage.getItem('lum_settings');
      if(_lsData) { const _p = JSON.parse(_lsData); _RS = { name:_p.name||'Restaurant', addr:_p.addr||_p.address||'', phone:_p.phone||'', gst:_p.gst||_p.gstNo||'', fssai:_p.fssai||_p.fssaiNo||'', gstRate:parseFloat(_p.gstRate)||5, service:parseFloat(_p.service)||10 }; }
    } catch(e) {}
  }
  if(!_RS.name) _RS = { name:'Restaurant', addr:'', phone:'', gst:'', fssai:'', gstRate:5, service:10 };
  const restaurantName = _RS.name;
  const _gstRate  = (_RS.gstRate || 5) / 100;
  const _svcRate  = (_RS.service || 10) / 100;

  document.getElementById('billTableName').textContent = tableName;

  const billLines = items.length
    ? items.map(i => {
        const iName  = i.name||i.dish||i.item||i.dishName||'Item';
        const iQty   = parseInt(i.qty)||parseInt(i.quantity)||1;
        const iPrice = parseFloat(i.price)||parseFloat(i.rate)||parseFloat(i.unitPrice)||0;
        const iAmt   = iPrice * iQty;
        return `<div style="display:flex;justify-content:space-between;margin-bottom:4px;font-size:12px"><span>${iName} ×${iQty}</span><span>₹${iAmt.toLocaleString('en-IN')}</span></div>`;
      }).join('')
    : '<div style="color:#a09070;text-align:center;padding:8px">Koi items nahi</div>';

  // CGST/SGST split (2.5% each = 5% total GST)
  const cgst = Math.round(subtotal * 0.025);
  const sgst = Math.round(subtotal * 0.025);
  const gstTotal = cgst + sgst;
  const totalFinal = subtotal + gstTotal;
  const guests = liveOrder ? (liveOrder.guests||liveOrder.guestCount||liveOrder.covers||'') : (tObj.guests||'');

  const _billNo = billNum!=='—'&&billNum ? billNum : Math.floor(1000+Math.random()*8999);
  const _gstPct = Math.round((_RS.gstRate||9));
  const _cgstPct = _gstPct/2; const _sgstPct = _gstPct/2;
  const _cgstAmt = +(subtotal * _cgstPct/100).toFixed(2);
  const _sgstAmt = +(subtotal * _sgstPct/100).toFixed(2);
  const _foodTotal = +(subtotal + _cgstAmt + _sgstAmt).toFixed(2);
  const _itemRows = items.length ? items.map(i=>{
    const nm=i.name||i.dish||i.item||'Item';
    const qt=parseInt(i.qty)||parseInt(i.quantity)||1;
    const rt=parseFloat(i.price)||parseFloat(i.rate)||parseFloat(i.unitPrice)||0;
    const amt=(rt*qt).toFixed(2);
    return `<tr><td style="padding:3px 4px;border:1px solid #ccc">${nm}</td><td style="padding:3px 4px;border:1px solid #ccc;text-align:center">${qt}</td><td style="padding:3px 4px;border:1px solid #ccc;text-align:right">₹${rt.toFixed(2)}</td><td style="padding:3px 4px;border:1px solid #ccc;text-align:right">₹${amt}</td></tr>`;
  }).join('') : `<tr><td colspan="4" style="padding:8px;text-align:center;color:#888;border:1px solid #ccc">Koi items nahi</td></tr>`;
  document.getElementById('billPrintBody').innerHTML = `
    <div style="background:#fff;color:#111;font-family:'Courier New',Courier,monospace;padding:18px 20px;max-width:340px;margin:0 auto;border:1px solid #ddd;border-radius:4px">
      <!-- Restaurant Header -->
      <div style="text-align:center;margin-bottom:6px">
        <div style="font-size:16px;font-weight:900;letter-spacing:1px;text-transform:uppercase">${_RS.name||'Restaurant'}</div>
        ${_RS.addr?`<div style="font-size:11px;margin-top:2px">${_RS.addr}</div>`:''}
        ${_RS.phone?`<div style="font-size:11px">Ph: ${_RS.phone}</div>`:''}
        ${_RS.gst?`<div style="font-size:10px">GSTIN: ${_RS.gst}</div>`:''}
        ${_RS.fssai?`<div style="font-size:10px">FSSAI: ${_RS.fssai}</div>`:''}
      </div>
      <div style="border-top:2px dashed #555;border-bottom:2px dashed #555;text-align:center;padding:4px 0;margin:6px 0;font-size:14px;font-weight:700;letter-spacing:3px">Cash Memo</div>
      <!-- Bill Info Row -->
      <div style="display:flex;justify-content:space-between;font-size:11px;margin-bottom:4px">
        <span>Date: ${dateStr}</span>
        <span>Bill No: <b>${_billNo}</b></span>
      </div>
      <div style="display:flex;justify-content:space-between;font-size:11px;margin-bottom:8px">
        <span>T.No.: ${tableName}</span>
        <span>${custName&&custName!=='Walk-in'?'Guest: '+custName:''}</span>
      </div>
      <!-- Items Table -->
      <table style="width:100%;border-collapse:collapse;font-size:11px;margin-bottom:6px">
        <thead>
          <tr style="background:#f0f0f0">
            <th style="padding:4px;border:1px solid #ccc;text-align:left">Particulars</th>
            <th style="padding:4px;border:1px solid #ccc;text-align:center">Qty</th>
            <th style="padding:4px;border:1px solid #ccc;text-align:right">Rate</th>
            <th style="padding:4px;border:1px solid #ccc;text-align:right">Amount</th>
          </tr>
        </thead>
        <tbody>${_itemRows}</tbody>
      </table>
      <!-- Totals -->
      <div style="font-size:11px">
        <div style="display:flex;justify-content:space-between;padding:2px 4px"><span>Sub Total :</span><span>₹${subtotal.toFixed(2)}</span></div>
        <div style="display:flex;justify-content:space-between;padding:2px 4px"><span>CGST @${_cgstPct}% on ₹${subtotal.toFixed(2)} :</span><span>₹${_cgstAmt.toFixed(2)}</span></div>
        <div style="display:flex;justify-content:space-between;padding:2px 4px;margin-bottom:4px"><span>SGST @${_sgstPct}% on ₹${subtotal.toFixed(2)} :</span><span>₹${_sgstAmt.toFixed(2)}</span></div>
        <div style="display:flex;justify-content:space-between;padding:3px 4px;border-top:1px dashed #555"><span>Food Total :</span><span><b>₹${_foodTotal.toFixed(2)}</b></span></div>
        <div style="border-top:2px dashed #555;border-bottom:2px dashed #555;display:flex;justify-content:space-between;padding:6px 4px;margin-top:4px">
          <span style="font-size:14px;font-weight:900">Total :</span>
          <span style="font-size:14px;font-weight:900">₹${_foodTotal.toFixed(2)}</span>
        </div>
        <div style="display:flex;justify-content:space-between;padding:3px 4px;font-size:10px">
          <span>E.&amp;O.E.</span>
          <span>${timeStr}</span>
        </div>
      </div>
      <!-- Footer -->
      <div style="text-align:center;margin-top:10px;font-size:12px;border-top:1px dashed #555;padding-top:8px">
        <b>Thank You</b> &nbsp;&nbsp; Visit Again
      </div>

      <!-- ACTION BUTTONS — Bill ke andar -->
      <div style="display:flex;gap:8px;margin-top:12px;padding-top:10px;border-top:2px dashed #ccc">
        <button onclick="captainWhatsAppBillFromModal()" style="flex:1;display:flex;align-items:center;justify-content:center;gap:6px;background:#25D366;color:#fff;border:none;border-radius:8px;padding:10px 8px;font-size:13px;font-weight:800;cursor:pointer;font-family:Outfit,sans-serif;box-shadow:0 3px 10px rgba(37,211,102,.4)">
          <svg style="vertical-align:middle;display:inline-block;font-size:16px" style="font-size:16px" xmlns="http://www.w3.org/2000/svg" width="1em" height="1em" viewBox="0 0 24 24" fill="currentColor"><path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 0 1-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 0 1-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 0 1 2.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0 0 12.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 0 0 5.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 0 0-3.48-8.413Z"/></svg> WhatsApp Send
        </button>
        <button onclick="captainMarkPaidOnly()" style="flex:1;display:flex;align-items:center;justify-content:center;gap:6px;background:#059669;color:#fff;border:none;border-radius:8px;padding:10px 8px;font-size:13px;font-weight:800;cursor:pointer;font-family:Outfit,sans-serif;box-shadow:0 3px 10px rgba(5,150,105,.4)">
          <svg style="vertical-align:middle;display:inline-block;font-size:15px" style="font-size:15px" xmlns="http://www.w3.org/2000/svg" width="1em" height="1em" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><polyline points="9 12 11 14 15 10"/></svg> Mark Paid ✅
        </button>
      </div>

    </div>`;

  // Store customer data globally for WhatsApp one-click send
  window._activeBillCustPhone = custPhone;
  window._activeBillTotal = totalFinal;
  window._activeBillNum = billNum;

  // WhatsApp button tooltip update
  const _waBtn = document.getElementById('billWaBtn');
  if(_waBtn){
    const _hp = custPhone && custPhone.replace(/[^0-9]/g,'').length >= 10;
    _waBtn.title = _hp ? ('Send to ' + custPhone) : 'Number nahi hai — WhatsApp Web khulega';
    _waBtn.style.opacity = '1';
  }

  openModal('billPrintModal');
}

// ── ONE-CLICK WhatsApp from Bill Modal ──
function captainWhatsAppBillFromModal(){
  const phone = window._activeBillCustPhone || '';
  const total = window._activeBillTotal || 0;
  const billNum = window._activeBillNum || '';
  const tableName = _activeBillTableName || '';
  captainWhatsAppBill(tableName, phone, total, billNum);
}

// ── MARK PAID (without auto-freeing via WhatsApp) ──
function captainMarkPaidOnly(){
  const tableName = _activeBillTableName || '';
  // Update paid icon on bill
  const paidIcon = document.getElementById('billPaidIcon');
  if(paidIcon){ paidIcon.style.background='#064e3b'; paidIcon.innerHTML='<svg style="vertical-align:middle;display:inline-block;font-size:12px" style="font-size:12px" xmlns="http://www.w3.org/2000/svg" width="1em" height="1em" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><circle cx="12" cy="12" r="10"/><polyline points="9 12 11 14 15 10"/></svg> PAID ✅'; }
  settleBillAndFreeTable();
  showToast('✅ Bill Paid! Table free ho gaya!', '#059669');
}

// WhatsApp bill send function
function captainWhatsAppBill(tableName, phone, total, billNum){
  const tNum = parseInt(String(tableName).replace(/\D/g,'')) || 0;
  const liveOrder = _billingLiveOrders[tNum] || null;
  const items = liveOrder ? (liveOrder.items||liveOrder.currentOrder||[]) : [];
  const custName = liveOrder ? (liveOrder.customerName||'Customer') : 'Customer';
  const restaurantName = (() => { try{ return JSON.parse(localStorage.getItem('lum_settings')||'{}').name || 'LUMIÈRE Restaurant'; }catch(e){ return 'LUMIÈRE Restaurant'; } })();

  const subtotal = items.reduce((s,i)=>s+((parseFloat(i.price)||parseFloat(i.rate)||0)*(parseInt(i.qty)||parseInt(i.quantity)||1)),0);
  const gst  = Math.round(subtotal * 0.05);
  const svc  = Math.round(subtotal * 0.10);
  const totalAmt = subtotal + gst + svc;

  const msg = `🍽️ *${restaurantName}*\n` +
    `━━━━━━━━━━━━━━━━━\n` +
    `📋 Bill Receipt\n` +
    `${tableName} · Bill #${billNum}\n` +
    `👤 ${custName}\n` +
    `━━━━━━━━━━━━━━━━━\n` +
    items.map(i=>`${i.name||i.dish||i.item||'Item'} ×${parseInt(i.qty)||parseInt(i.quantity)||1} ........... ₹${((parseFloat(i.price)||parseFloat(i.rate)||0)*(parseInt(i.qty)||parseInt(i.quantity)||1))}`).join('\n') +
    `\n━━━━━━━━━━━━━━━━━\n` +
    `Subtotal: ₹${subtotal}\n` +
    `GST 5%: ₹${gst}\n` +
    `Service 10%: ₹${svc}\n` +
    `*TOTAL: ₹${totalAmt}*\n` +
    `━━━━━━━━━━━━━━━━━\n` +
    `Thank you for dining with us! ⭐⭐⭐⭐⭐`;

  const cleanPhone = (phone||'').replace(/[^0-9]/g,'');
  const waUrl = cleanPhone
    ? `https://wa.me/${cleanPhone.startsWith('91')?cleanPhone:'91'+cleanPhone}?text=${encodeURIComponent(msg)}`
    : `https://wa.me/?text=${encodeURIComponent(msg)}`;

  window.open(waUrl, '_blank');

  // Auto free table after WhatsApp send
  setTimeout(()=>{
    captainFreeTableOnFirebase(tableName);
    closeModal('billPrintModal');
    showToast('💬 Bill WhatsApp pe gaya! '+tableName+' FREE ho gaya! 🟢', '#25d366');
  }, 1000);
}

// Free table on Firebase (billing.html ki 'tables' collection update karo)
async function captainFreeTableOnFirebase(tableName){
  const tNum = parseInt(String(tableName).replace(/\D/g,'')) || 0;
  try {
    const { doc, setDoc, updateDoc, collection, getDocs, query, where } = await import('https://www.gstatic.com/firebasejs/10.12.2/firebase-firestore.js');
    if(!window._captainDb) return;
    const db = window._captainDb;

    // 1. Update billing 'tables' collection
    await setDoc(doc(db, 'tables', String(tNum)), {
      status: 'available',
      currentOrder: [],
      customerName: '',
      customerPhone: '',
      paidAt: new Date().toISOString()
    }, { merge: true });

    // 2. Mark active order as 'paid' in 'orders' collection
    if(_activeBillFbOrderId){
      await updateDoc(doc(db, 'orders', _activeBillFbOrderId), {
        status: 'paid',
        paidAt: new Date().toISOString()
      }).catch(()=>{});
    }

    // 3. Local update
    const t = tableData.find(x=>x.no===tableName);
    if(t){ t.status='available'; t.order=[]; t.customerName=''; t.customerPhone=''; }
    delete _billingLiveOrders[tNum];
    buildTables();
    showToast('✅ '+tableName+' FREE ho gaya! Firebase update ho gaya!', '#059669');
  } catch(e){
    console.error('Free table error:', e);
    // Fallback: local only
    const t = tableData.find(x=>x.no===tableName);
    if(t){ t.status='available'; t.order=[]; }
    delete _billingLiveOrders[tNum];
    buildTables();
    showToast('✅ '+tableName+' locally free kiya (Firebase error)', '#f59e0b');
  }
}

function openBillPrint(tableName){
  captainOpenFullBill(tableName);
}

function settleBillAndFreeTable(){
  closeModal('billPrintModal');
  if(_activeBillTableName){
    captainFreeTableOnFirebase(_activeBillTableName);
  }
  cart=[]; renderCart(); refreshCartTableSelect();
}

