let currentBillingTable = '';
let currentBillType = 'digital';
let currentPayMethod = 'cash';

function selectBillType(type){
  currentBillType = type;
  ['digital','print','manual'].forEach(t => {
    const tab = document.getElementById('billTab-'+t);
    if(tab) tab.classList.toggle('active', t===type);
  });
  const btn = document.getElementById('billMainBtn');
  if(btn){
    if(type==='digital') { btn.textContent='💻 Digital Bill Generate'; btn.style.background='var(--G600)'; }
    else if(type==='print') { btn.textContent='🖨️ Print Bill Now'; btn.style.background='var(--blue)'; }
    else { btn.textContent='✍️ Manual Bill View'; btn.style.background='var(--orange)'; }
  }
  if(currentBillingTable) generateBillPreview(currentBillingTable);
}

function selectPayment(el, method){
  currentPayMethod = method;
  document.querySelectorAll('.pay-opt').forEach(p => {
    p.style.borderColor = 'var(--line)';
    p.style.background = 'var(--white)';
  });
  el.style.borderColor = 'var(--G600)';
  el.style.background = 'rgba(34,197,94,.1)';
}

function selectTableForBill(tableName){
  currentBillingTable = tableName;
  generateBillPreview(tableName);
  document.getElementById('billActionBtns').style.display = 'block';
  showToast('🧾 ' + tableName + ' ka bill load ho gaya!');
}

