const themes = ['dark-forest','midnight-ruby','ocean-deep','golden-dusk','cosmic-purple','simi-grocery'];
let currentTheme = localStorage.getItem('captainTheme') || 'dark-forest';

function applyTheme(theme) {
  themes.forEach(t => document.body.classList.remove('theme-' + t));
  document.body.classList.add('theme-' + theme);
  currentTheme = theme;
  localStorage.setItem('captainTheme', theme);
  // Update active pill
  themes.forEach(t => {
    const el = document.getElementById('tp-' + t);
    if (el) el.classList.toggle('active', t === theme);
  });
  showToast('🎨 Theme: ' + theme.replace(/-/g,' ').replace(/\b\w/g,c=>c.toUpperCase()));
}

function toggleThemePanel() {
  const p = document.getElementById('themePanel');
  if (p.style.display === 'none') {
    p.style.display = 'flex';
  } else {
    p.style.display = 'none';
  }
}

// Close theme panel on outside click
document.addEventListener('click', (e) => {
  if (!document.getElementById('themeSwitcher').contains(e.target)) {
    const p = document.getElementById('themePanel');
    if (p) p.style.display = 'none';
  }
});

// Apply saved theme on load
applyTheme(currentTheme);

// ===========================
// ===== PARTICLES =====
// ===========================
function createParticles() {
  const container = document.getElementById('particleContainer');
  if (!container) return;
  const count = 30;
  for (let i = 0; i < count; i++) {
    const p = document.createElement('div');
    p.className = 'particle';
    p.style.left = Math.random() * 100 + 'vw';
    p.style.width = p.style.height = (Math.random() * 3 + 1) + 'px';
    p.style.animationDuration = (Math.random() * 15 + 10) + 's';
    p.style.animationDelay = (Math.random() * 10) + 's';
    p.style.opacity = Math.random() * 0.5;
    container.appendChild(p);
  }
}
createParticles();

