// ===== KITCHEN TIME SET SYSTEM — FINAL FIXED =====
// ===========================
let currentKitTimeCard = null;
let selectedTimeMinutes = 0;
const kitchenTimerSet = {}; // cardId → { interval, remaining, orderNo, tableNo }

/* ---------- FLOATING WIDGET REMOVED ---------- */
function ensureFloatingWidget(){ /* removed */ }
function refreshFloatingWidget(){ /* removed */ }

/* ---------- OPEN TIME MODAL ---------- */
function openKitTimeModal(cardId){
  const card = document.getElementById(cardId);
  if(!card) return;
  currentKitTimeCard = cardId;
  selectedTimeMinutes = 0;
  const orderNo  = card.getAttribute('data-order')   || '';
  const tableNo  = card.getAttribute('data-table')   || '';
  const customer = card.getAttribute('data-customer')|| 'Customer';
  document.getElementById('kitTimeOrderInfo').textContent =
    orderNo + ' — ' + tableNo + ' | 👤 ' + customer;
  document.getElementById('kitCustomTime').value = '';
  document.getElementById('kitTimePreview').textContent = '⏱️ Set time — countdown card ke andar + corner me shuru hoga';
  document.querySelectorAll('.time-preset-btn').forEach(b => b.classList.remove('btn-green'));
  openModal('kitTimeModal');
}

function selectTimePreset(mins){
  selectedTimeMinutes = mins;
  document.getElementById('kitCustomTime').value = '';
  document.getElementById('kitTimePreview').textContent = '⏱️ ' + mins + ':00 se countdown shuru hoga';
  document.querySelectorAll('.time-preset-btn').forEach(b => b.classList.remove('btn-green'));
  event.target.classList.add('btn-green');
}

function highlightCustomTime(){
  const val = parseInt(document.getElementById('kitCustomTime').value);
  if(val > 0){
    selectedTimeMinutes = val;
    document.getElementById('kitTimePreview').textContent = '⏱️ ' + val + ':00 se countdown shuru hoga';
    document.querySelectorAll('.time-preset-btn').forEach(b => b.classList.remove('btn-green'));
  }
}

/* ---------- CONFIRM TIME → START COUNTDOWN ---------- */
function confirmKitTime(){
  const customVal = parseInt(document.getElementById('kitCustomTime').value);
  const mins = customVal > 0 ? customVal : selectedTimeMinutes;
  if(!mins || mins < 1){ showToast('⚠️ Koi time select ya type karo!'); return; }
  closeModal('kitTimeModal');

  const card = document.getElementById(currentKitTimeCard);
  if(!card) return;
  const cardId   = currentKitTimeCard;
  const orderNo  = card.getAttribute('data-order')   || '';
  const tableNo  = card.getAttribute('data-table')   || '';
  const customer = card.getAttribute('data-customer')|| 'Customer';
  const suffix   = cardId.replace('kc-','');

  card.setAttribute('data-set-time', mins);

  // ── VOICE CONFIRMATION: Timer set ho gaya ──
  if (typeof captainSpeak === 'function') {
    setTimeout(function() {
      captainSpeak('Captain! ' + tableNo + ' ke liye ' + mins + ' minute ka timer set ho gaya hai. Main aapko batati rahungi.');
    }, 400);
  }

  // Stop any existing countdown for THIS card only
  if(kitchenTimerSet[cardId]){
    clearInterval(kitchenTimerSet[cardId].interval);
    delete kitchenTimerSet[cardId];
  }

  // Disable Mark Ready button for this card (enable after timer ends)
  const readyBtn = card.querySelector('.kit-ready-btn');
  if(readyBtn){
    readyBtn.disabled = true;
    readyBtn.style.opacity = '0.45';
    readyBtn.style.cursor  = 'not-allowed';
    readyBtn.title = 'Timer khatam hone ke baad available hoga';
  }

  // Show countdown display inside card
  let dispEl = document.getElementById('kitTimeDisplay-'+suffix);
  if(!dispEl){
    dispEl = document.createElement('div');
    dispEl.id = 'kitTimeDisplay-'+suffix;
    const actions = card.querySelector('.kitchen-actions');
    if(actions) card.insertBefore(dispEl, actions);
  }
  dispEl.style.cssText = 'display:flex;align-items:center;justify-content:space-between;background:#064e3b;border-radius:10px;padding:8px 14px;margin:8px 0 4px;';
  dispEl.innerHTML = `
    <span style="font-size:11px;color:rgba(255,255,255,.75);font-weight:600">⏱️ Customer wait</span>
    <span id="kitCardTimer-${suffix}" style="font-family:'JetBrains Mono',monospace;font-size:22px;font-weight:800;color:#34d399;letter-spacing:1px">${String(mins).padStart(2,'0')}:00</span>`;

  // Register in global store
  const totalSecs = mins * 60;
  kitchenTimerSet[cardId] = { remaining: totalSecs, orderNo, tableNo, customer, interval: null };

  // Start interval — ONLY for this card
  kitchenTimerSet[cardId].interval = setInterval(()=>{
    if(!kitchenTimerSet[cardId]) return;
    kitchenTimerSet[cardId].remaining = Math.max(0, kitchenTimerSet[cardId].remaining - 1);
    const rem = kitchenTimerSet[cardId].remaining;
    const mm  = String(Math.floor(rem / 60)).padStart(2,'0');
    const ss  = String(rem % 60).padStart(2,'0');

    // Update card timer display
    const cardTimerEl = document.getElementById('kitCardTimer-'+suffix);
    if(cardTimerEl){
      cardTimerEl.textContent = mm + ':' + ss;
      if(rem <= 30) cardTimerEl.style.color = '#fbbf24';  // amber last 30s
      if(rem === 0) cardTimerEl.style.color = '#ef4444';  // red at 0
    }

    // Update floating corner widget
    refreshFloatingWidget();

    // When countdown ends → enable Mark Ready
    if(rem === 0){
      clearInterval(kitchenTimers[cardId] ? kitchenTimers[cardId].interval : null);
      clearInterval(kitchenTimerSet[cardId].interval);

      // Enable Mark Ready button
      const rb = card.querySelector('.kit-ready-btn');
      if(rb){
        rb.disabled = false;
        rb.style.opacity = '1';
        rb.style.cursor  = 'pointer';
        rb.style.animation = 'heartbeat 1.2s ease-in-out infinite';
        rb.removeAttribute('title');
      }

      // Flash the card
      card.style.boxShadow = '0 0 0 3px #34d399';
      setTimeout(()=>{ card.style.boxShadow = ''; }, 3000);

      showToast('🔔 ' + orderNo + ' — ' + tableNo + ' ka time khatam! Chef Ready mark kare!');
      addNotification('⏰ Timer Done: '+orderNo, tableNo+' — Mark Ready karo!', 'orange');
    }
  }, 1000);

  refreshFloatingWidget();
  showToast('⏱️ ' + orderNo + ' — ' + mins + ':00 countdown shuru! Corner me bhi dikh raha hai.');
}

/* ---------- REMOVE CARD FROM FLOATING WIDGET ---------- */
function removeKitFloatEntry(cardId){
  if(kitchenTimerSet[cardId]){
    clearInterval(kitchenTimerSet[cardId].interval);
    delete kitchenTimerSet[cardId];
  }
  refreshFloatingWidget();
}


