// ===========================
// ===== WAITER LIST FEATURE =====
// ===========================
function buildWaiterListTable(filter, statusFilter){
  const tbody = document.getElementById('waiterListTbody');
  if(!tbody) return;
  let data = waitersData;
  if(filter) data = data.filter(w=>w.name.toLowerCase().includes(filter.toLowerCase()) || w.phone.includes(filter) || w.floor.toLowerCase().includes(filter.toLowerCase()));
  if(statusFilter && statusFilter!=='all') data = data.filter(w=>w.status===statusFilter);
  const statusLabels = {active:'<span class="status-pill delivered"><span class="status-dot"></span>Active</span>', break:'<span class="status-pill pending"><span class="status-dot"></span>Break</span>', off:'<span style="background:var(--bg2);border:1px solid var(--line2);border-radius:20px;padding:3px 10px;font-size:10px;font-weight:700;color:var(--ink3)">Off</span>'};
  const shiftLabels = {morning:'🌅 Morning',evening:'🌆 Evening',night:'🌙 Night'};
  function getShiftLabelForW(w){
    if(w.shift==='custom'){
      function fmt(t){ if(!t) return '?'; const [h,m]=t.split(':'); const hr=parseInt(h); return (hr>12?hr-12:hr||12)+':'+m+(hr>=12?'PM':'AM'); }
      return '✏️ '+(w.shiftCustomName||'Custom')+' ('+(w.shiftCustomStart?fmt(w.shiftCustomStart):'?')+'-'+(w.shiftCustomEnd?fmt(w.shiftCustomEnd):'?')+')';
    }
    return shiftLabels[w.shift]||w.shift;
  }
  tbody.innerHTML = data.map((w,i)=>`
    <tr>
      <td style="font-weight:700;color:var(--ink3)">${i+1}</td>
      <td><div style="display:flex;align-items:center;gap:10px"><div style="width:32px;height:32px;border-radius:50%;background:${w.color};display:flex;align-items:center;justify-content:center;font-size:12px;font-weight:800;color:#fff;flex-shrink:0">${w.avatar}</div><div><div style="font-size:13px;font-weight:700">${w.name}</div></div></div></td>
      <td><span style="font-family:'JetBrains Mono',monospace;font-size:12px;font-weight:600">📞 ${w.phone}</span></td>
      <td style="font-size:12px;font-weight:600;color:var(--ink2)">${w.floor}</td>
      <td>${statusLabels[w.status]||statusLabels.off}</td>
      <td style="font-size:11px;font-weight:600;color:var(--ink3)">${getShiftLabelForW(w)}</td>
      <td style="font-size:12px;font-weight:700">${w.rating}</td>
      <td><span style="font-weight:800;color:var(--G600)">${w.orders}</span></td>
      <td><div style="display:flex;gap:5px;flex-wrap:wrap"><button class="btn btn-outline" style="font-size:9px;padding:3px 8px" onclick="callWaiterDirect(${waitersData.indexOf(w)})">📞 Call</button><button class="btn btn-outline" style="font-size:9px;padding:3px 8px" onclick="openWaiterWhatsApp(${waitersData.indexOf(w)})">💬 WA</button><button class="btn btn-outline" style="font-size:9px;padding:3px 8px" onclick="openWaiterShiftModal(${waitersData.indexOf(w)})">📅 Shift</button></div></td>
    </tr>`).join('');
  document.getElementById('waiterListCount').textContent = data.length + ' waiters';
  // Update stats
  const active = waitersData.filter(w=>w.status==='active').length;
  const brk = waitersData.filter(w=>w.status==='break').length;
  const off = waitersData.filter(w=>w.status==='off').length;
  const ael=document.getElementById('wlActiveCount'); if(ael) ael.textContent=active;
  const bel=document.getElementById('wlBreakCount'); if(bel) bel.textContent=brk;
  const oel=document.getElementById('wlOffCount'); if(oel) oel.textContent=off;
  const tel=document.getElementById('wlTotalCount'); if(tel) tel.textContent=waitersData.length;
}

function filterWaiterList(searchVal){
  const statusFilter = document.getElementById('waiterStatusFilter')?.value || 'all';
  buildWaiterListTable(searchVal, statusFilter);
}

function editWaiterStatus(idx){
  const w = waitersData[idx];
  if(!w) return;
  const statuses = ['active','break','off'];
  const nextStatus = statuses[(statuses.indexOf(w.status)+1)%statuses.length];
  const labels = {active:'🟢 Active',break:'🔴 Break',off:'🟡 Off',};
  waitersData[idx].status = nextStatus;
  buildWaiterListTable('','all');
  showToast('✅ ' + w.name + ' — Status: ' + labels[nextStatus]);
  // Also rebuild waiter assign modal options
  buildWaiterAssignOptions();
}

function openAddWaiterModal(){ openModal('addWaiterModal'); }

function doAddWaiter(){
  const name = document.getElementById('newWaiterName').value.trim();
  const phone = document.getElementById('newWaiterPhone').value.trim();
  const floor = document.getElementById('newWaiterFloor').value;
  const shift = document.getElementById('newWaiterShift').value;
  if(!name){ showToast('⚠️ Naam dalo!'); return; }
  if(!phone){ showToast('⚠️ Phone number dalo!'); return; }
  const initials = name.split(' ').map(n=>n[0]).join('').substring(0,2).toUpperCase();
  const colors = ['linear-gradient(135deg,var(--G600),var(--teal))','linear-gradient(135deg,var(--blue),var(--sky))','linear-gradient(135deg,var(--violet),var(--indigo))','linear-gradient(135deg,var(--orange),var(--amber))'];
  const color = colors[waitersData.length % colors.length];
  waitersData.push({name, phone, floor, shift, status:'active', rating:'⭐ New', orders:0, avatar:initials, color});
  buildWaiterListTable('','all');
  buildWaiterAssignOptions();
  closeModal('addWaiterModal');
  document.getElementById('newWaiterName').value='';
  document.getElementById('newWaiterPhone').value='';
  showToast('✅ ' + name + ' added! Waiter list me show hoga.');
}

// Build waiter assign modal options dynamically from waitersData
function buildWaiterAssignOptions(){
  const list = document.querySelector('.waiter-list');
  if(!list) return;
  let html = '';
  waitersData.forEach(function(w){
    const isOff = w.status !== 'active';
    const statusText = w.status==='active' ? '🟢 Available' : w.status==='break' ? '🔴 On Break' : '🟡 Off Shift';
    const btnStyle = isOff ? 'background:var(--bg2);color:var(--ink3);cursor:not-allowed' : '';
    const btnLabel = w.status==='active' ? 'Assign' : 'Busy';
    const opacity = w.status==='off' ? 'opacity:.4;' : '';
    const safeName = w.name.replace(/"/g, '&quot;');
    html += '<div class="waiter-option" style="' + opacity + '">';
    html += '<div class="w-avatar" style="background:' + w.color + '">' + w.avatar + '</div>';
    html += '<div class="w-info"><div class="w-name">' + w.name + '</div>';
    html += '<div class="w-status">' + statusText + ' · ' + w.floor + ' · ' + w.rating + ' · ' + w.orders + ' orders today</div></div>';
    html += '<button class="w-assign-btn" ' + (isOff ? 'disabled style="' + btnStyle + '"' : 'onclick="assignWaiter(\'' + safeName + '\')"') + '>' + btnLabel + '</button>';
    html += '</div>';
  });
  list.innerHTML = html;
}

// Rebuild waiter list and assign options when waiterlist page is shown
const origShowPage2 = window.showPage;
window.showPage = function(id, el){
  origShowPage2(id, el);
  if(id==='waiterlist') buildWaiterListTable('','all');
  if(id==='kitchen') updateKitchenCounts();
  if(id==='watermgmt') { setTimeout(buildRtsDishGrid, 80); }
};

// Init on load
document.addEventListener('DOMContentLoaded', function(){
  buildWaiterListTable('','all');
  buildWaiterAssignOptions();
});

