// ===================================================
// HINDI GIRL VOICE — Web Speech API
// ===================================================
// ================================================================
//  ARIA VOICE ENGINE  — ElevenLabs (Shreya-style) + Zira fallback
// ================================================================
// Pre-load ElevenLabs API key
// ── Siplora Custom Voice — Uploaded MP3 ──
const SIPLORA_AUDIO_SRC = "data:audio/mp3;base64,";

function playSiploraVoice(done) {
  const au = new Audio(SIPLORA_AUDIO_SRC);
  au.volume = 1;
  const fab = document.getElementById('ariaFab');
  const mouth = document.querySelector('.aria-mouth');
  if(fab) fab.classList.add('speaking');
  if(mouth) mouth.classList.add('talking');
  au.onended = au.onerror = () => {
    if(fab) fab.classList.remove('speaking');
    if(mouth) mouth.classList.remove('talking');
    done && done();
  };
  au.play().catch(() => { done && done(); });
}

const _ARIA_DEFAULT_KEY = 'sk_dc9deb65cfb14ac4cd91d1b323113eb08fba9bb4c617a409';
if(!localStorage.getItem('aria_el_key')) {
  localStorage.setItem('aria_el_key', _ARIA_DEFAULT_KEY);
  localStorage.setItem('aria_el_vid', 'plZ9JnLSXj1tLnvpUX6s');
  localStorage.setItem('aria_el_on', 'true');
}

const ARIA_VOICE = {
  key   : localStorage.getItem('aria_el_key')   || _ARIA_DEFAULT_KEY,
  vid   : localStorage.getItem('aria_el_vid')   || 'plZ9JnLSXj1tLnvpUX6s', // Custom cloned voice
  useEL : (localStorage.getItem('aria_el_on') === 'true') || true,
  lang  : localStorage.getItem('aria_lang')     || 'hi', // 'hi' = Hindi, 'mr' = Marathi, 'en' = English
  busy  : false,
  q     : [],

  // Language config map
  langConfig: {
    'hi': { code:'hi-IN', label:'हिंदी', flag:'🇮🇳', name:'Hindi' },
    'mr': { code:'mr-IN', label:'मराठी', flag:'🟠', name:'Marathi' },
    'en': { code:'en-US', label:'English', flag:'🇬🇧', name:'English' }
  },

  setLang(l) {
    this.lang = l || 'hi';
    localStorage.setItem('aria_lang', this.lang);
    // Update recognition lang too
    if(typeof ariaRecognition !== 'undefined' && ariaRecognition) {
      ariaRecognition.lang = this.langConfig[this.lang]?.code || 'hi-IN';
    }
  },

  getLangCode() {
    return this.langConfig[this.lang]?.code || 'hi-IN';
  },

  clean(raw) {
    return String(raw||'')
      .replace(/<[^>]*>/g,' ')
      .replace(/[\*#_~`\u2022]/g,' ')
      .replace(/\s+/g,' ').trim().slice(0,350);
  },

  // Google Translate TTS — proper Marathi/Hindi/English (free, no key)
  async gTransSpeak(txt, langCode, done) {
    try {
      const glang = langCode === 'mr-IN' ? 'mr' : langCode === 'hi-IN' ? 'hi' : 'en';
      // Split into <=190 char chunks at sentence boundaries
      const chunks = [];
      const sentences = txt.match(/[^।.!?]+[।.!?]*/g) || [txt];
      let cur = '';
      for(const s of sentences) {
        if((cur + s).length > 190) { if(cur) chunks.push(cur.trim()); cur = s; }
        else cur += s;
      }
      if(cur.trim()) chunks.push(cur.trim());
      const fab   = document.getElementById('ariaFab');
      const mouth = document.querySelector('.aria-mouth');
      if(fab)   fab.classList.add('speaking');
      if(mouth) mouth.classList.add('talking');
      let failed = false;
      const playChunk = (i) => {
        if(i >= chunks.length) {
          if(fab)   fab.classList.remove('speaking');
          if(mouth) mouth.classList.remove('talking');
          done && done(); return;
        }
        // Use Google TTS endpoint — clearer female voice
        const url = 'https://translate.google.com/translate_tts?ie=UTF-8&q='
          + encodeURIComponent(chunks[i])
          + '&tl=' + glang
          + '&total=1&idx=0&textlen=' + chunks[i].length
          + '&client=tw-ob&prev=input&ttsspeed=0.9';
        const au = new Audio(url);
        au.volume = 1.0;
        au.playbackRate = 1.0;
        au.crossOrigin = 'anonymous';
        au.onended = () => playChunk(i + 1);
        au.onerror = () => {
          if(!failed){
            failed = true;
            if(fab) fab.classList.remove('speaking');
            if(mouth) mouth.classList.remove('talking');
            // Fallback to browser TTS
            this.hindiBrowserSpeak(txt, done);
          }
        };
        au.play().catch(() => {
          if(!failed){
            failed = true;
            if(fab) fab.classList.remove('speaking');
            if(mouth) mouth.classList.remove('talking');
            this.hindiBrowserSpeak(txt, done);
          }
        });
      };
      playChunk(0);
    } catch(e) { this.hindiBrowserSpeak(txt, done); }
  },

  // Best voice for given language
  bestVoice(langCode) {
    const vv = window.speechSynthesis ? window.speechSynthesis.getVoices() : [];
    if(langCode === 'hi-IN') {
      return vv.find(v=>v.lang==='hi-IN')
          || vv.find(v=>v.lang&&v.lang.startsWith('hi'))
          || vv.find(v=>/hindi/i.test(v.name))
          || this.winVoice();
    }
    if(langCode === 'mr-IN') {
      return vv.find(v=>v.lang==='mr-IN')
          || vv.find(v=>v.lang&&v.lang.startsWith('mr'))
          || vv.find(v=>/marathi/i.test(v.name))
          || vv.find(v=>v.lang==='hi-IN') // fallback to Hindi
          || this.winVoice();
    }
    return this.winVoice(); // English
  },

  // Best Windows female voice
  winVoice() {
    const vv = window.speechSynthesis ? window.speechSynthesis.getVoices() : [];
    const want = [
      'Microsoft Zira - English (United States)',
      'Microsoft Zira Desktop - English (United States)',
      'Microsoft Hazel Desktop - English (Great Britain)',
      'Google UK English Female','Samantha','Karen','Moira','Tessa'
    ];
    for (const n of want) { const v = vv.find(x=>x.name===n); if(v) return v; }
    return vv.find(v=>/zira|hazel|female/i.test(v.name))
          || vv.find(v=>v.lang==='en-US')
          || vv.find(v=>v.lang&&v.lang.startsWith('en'))
          || null;
  },

  // Browser TTS with language support
  browserSpeak(txt, done) {
    if(!window.speechSynthesis){done&&done();return;}
    window.speechSynthesis.cancel();
    // Small delay after cancel so browser clears buffer
    setTimeout(() => {
      const u = new SpeechSynthesisUtterance(txt);
      u.volume = 1;
      u.rate   = 0.82;   // slower = clearer
      u.pitch  = 1.1;    // natural, not too high
      const langCode = this.getLangCode();
      const v = this.bestVoice(langCode);
      if(v){ u.voice = v; u.lang = v.lang; } else { u.lang = langCode; }
      const fab   = document.getElementById('ariaFab');
      const mouth = document.querySelector('.aria-mouth');
      if(fab)   fab.classList.add('speaking');
      if(mouth) mouth.classList.add('talking');
      const end = () => {
        if(fab)   fab.classList.remove('speaking');
        if(mouth) mouth.classList.remove('talking');
        done && done();
      };
      u.onend  = end;
      u.onerror = end;
      // Chrome bug workaround — resume if paused
      setTimeout(() => { if(window.speechSynthesis.paused) window.speechSynthesis.resume(); }, 80);
      window.speechSynthesis.speak(u);
    }, 60);
  },

  // ── Animate mouth & FAB ──
  _startAnim() {
    const fab=document.getElementById('ariaFab'), mouth=document.querySelector('.aria-mouth');
    if(fab) fab.classList.add('speaking');
    if(mouth) mouth.classList.add('talking');
  },
  _stopAnim() {
    const fab=document.getElementById('ariaFab'), mouth=document.querySelector('.aria-mouth');
    if(fab) fab.classList.remove('speaking');
    if(mouth) mouth.classList.remove('talking');
  },

  // ── ElevenLabs TTS — multilingual cute girl voice ──
  async elSpeak(txt, done) {
    // Phone performance fix: skip ElevenLabs if no key set
    if (!this.key || this.key.trim() === '') {
      this.hindiBrowserSpeak(txt, done);
      return;
    }
    try {
      // eleven_turbo_v2_5 = best for Hindi/Marathi/English multilingual
      const r = await fetch(`https://api.elevenlabs.io/v1/text-to-speech/${this.vid}`,{
        method:'POST',
        headers:{'xi-api-key':this.key,'Content-Type':'application/json','Accept':'audio/mpeg'},
        body:JSON.stringify({
          text: txt,
          model_id: 'eleven_turbo_v2_5',
          language_code: this.lang === 'hi' ? 'hi' : this.lang === 'mr' ? 'hi' : 'en',
          voice_settings: {stability:0.42, similarity_boost:0.90, style:0.40, use_speaker_boost:true}
        })
      });
      if(!r.ok) throw new Error(r.status);
      const blob = await r.blob();
      const url  = URL.createObjectURL(blob);
      const au   = new Audio(url);
      this._startAnim();
      au.onended = au.onerror = () => { URL.revokeObjectURL(url); this._stopAnim(); done&&done(); };
      au.play();
    } catch(e) {
      console.warn('ElevenLabs failed →', e.message);
      if(String(e.message).match(/401|403/)) {
        this.useEL=false; localStorage.setItem('aria_el_on','false');
        typeof showToast !== 'undefined' && showToast('⚠️ ElevenLabs key check karo — browser voice use ho rahi hai');
      }
      this.hindiBrowserSpeak(txt, done);
    }
  },

  // ── Hindi/Marathi browser TTS — uses best available voice ──
  hindiBrowserSpeak(txt, done) {
    if(!window.speechSynthesis){ done&&done(); return; }
    window.speechSynthesis.cancel();
    const trySpeak = () => {
      const vv = window.speechSynthesis.getVoices();
      const u  = new SpeechSynthesisUtterance(txt);
      u.volume = 1;
      u.rate   = 0.78;  // slower = much clearer
      u.pitch  = 1.0;   // natural pitch, not too high

      if(this.lang === 'hi' || this.lang === 'mr') {
        // Best Hindi voices priority list
        const hiVoice = vv.find(v=>v.lang==='hi-IN' && /google/i.test(v.name))
                     || vv.find(v=>v.lang==='hi-IN')
                     || vv.find(v=>v.lang&&v.lang.startsWith('hi'))
                     || vv.find(v=>/hindi/i.test(v.name));
        if(hiVoice) { u.voice = hiVoice; u.lang = 'hi-IN'; }
        else { u.lang = 'hi-IN'; } // force lang even without voice — OS may handle it
      } else {
        // English — sweet female voice
        const enVoice = vv.find(v=>/zira|hazel|samantha|karen|moira|tessa|google uk.*female/i.test(v.name))
                     || vv.find(v=>v.lang==='en-US' && v.name.toLowerCase().includes('female'))
                     || vv.find(v=>v.lang==='en-US')
                     || null;
        if(enVoice) { u.voice = enVoice; u.lang = enVoice.lang; }
        else { u.lang = 'en-US'; }
      }
      this._startAnim();
      u.onend = u.onerror = () => { this._stopAnim(); done&&done(); };
      setTimeout(()=>{ if(window.speechSynthesis.paused) window.speechSynthesis.resume(); }, 80);
      window.speechSynthesis.speak(u);
    };

    const vv = window.speechSynthesis.getVoices();
    if(vv.length === 0) {
      window.speechSynthesis.onvoiceschanged = () => { window.speechSynthesis.onvoiceschanged = null; trySpeak(); };
    } else { trySpeak(); }
  },

  next(){ this.busy=false; if(this.q.length){ const t=this.q.shift(); setTimeout(()=>this.say(t),150); } },

  say(raw) {
    const txt = this.clean(raw);
    if(!txt) return;
    if(this.busy){ this.q = [txt]; return; } // queue latest
    if(window.speechSynthesis && window.speechSynthesis.speaking) window.speechSynthesis.cancel();
    this.busy = true;
    const done = () => this.next();
    if(this.useEL && this.key) {
      // ElevenLabs handles all languages natively via multilingual model
      this.elSpeak(txt, done);
    } else {
      // Google Translate TTS — clear female voice, free, no key needed
      // Way better than browser TTS for Hindi/Marathi
      this.gTransSpeak(txt, this.getLangCode(), done);
    }
  },

  save(key,vid) {
    this.key=key||''; this.vid=vid||'plZ9JnLSXj1tLnvpUX6s';
    this.useEL=!!key;
    localStorage.setItem('aria_el_key', this.key);
    localStorage.setItem('aria_el_vid', this.vid);
    localStorage.setItem('aria_el_on',  this.useEL?'true':'false');
  }
};

// ── Language Change Helper ──
function ariaChangeLang(lang) {
  ARIA_VOICE.setLang(lang);
  // Update Voice Settings status label
  vsRefreshLangButtons&&vsRefreshLangButtons();
  // Update mic recognition language
  const cfg = ARIA_VOICE.langConfig[lang];
  // Announcement in chosen language
  const greetMap = {
    'hi': 'Hello Captain sir! Main Siplora hoon. Ab main Hindi mein boluungi!',
    'mr': 'Hello Captain sir! Mi Siplora ahe. Aata mi Marathi madhe bolein!',
    'en': 'Hello Captain sir! I am Siplora. I will now speak in English!'
  };
  ARIA_VOICE.say(greetMap[lang] || greetMap['hi']);
  showToast && showToast((cfg?.flag||'') + ' Language changed to ' + (cfg?.name||lang));
}

