// ── AUDIO AUTOPLAY UNLOCK — browser autoplay policy fix ──
// Pehli user interaction pe AudioContext + SpeechSynthesis unlock hota hai
let _audioUnlocked = false;
function _unlockAudio() {
  if (_audioUnlocked) return;
  _audioUnlocked = true;
  try {
    const ctx = new (window.AudioContext || window.webkitAudioContext)();
    const buf = ctx.createBuffer(1,1,22050);
    const src = ctx.createBufferSource(); src.buffer=buf;
    src.connect(ctx.destination); src.start(0);
    setTimeout(()=>ctx.close(),100);
  } catch(e){}
  if(window.speechSynthesis){ window.speechSynthesis.cancel(); }
}
['click','touchstart','keydown'].forEach(function(ev){ document.addEventListener(ev, _unlockAudio, {once:true, capture:true}); });

function speakHindi(t)    { ARIA_VOICE.say(t); }

// ── CAPTAIN NOTIFICATION VOICE — Cute Indian Girl (Google TTS, Free) ──
// Queue system — ek ke baad ek bolegi, overlap nahi hoga
const _captainVoiceQueue = [];
let   _captainVoiceBusy  = false;

function captainSpeak(text) {
  if (!text) return;
  const clean = text.replace(/[🛒✅👨‍🍳🧑‍🍽️🔥🍳🚨🔴🟡📝🔔⚠️ℹ️🎉🔄]/gu, '').replace(/\s+/g,' ').trim();
  if (!clean) return;
  _captainVoiceQueue.push(clean);
  if (!_captainVoiceBusy) _captainVoiceNext();
}

function _captainVoiceNext() {
  if (!_captainVoiceQueue.length) { _captainVoiceBusy = false; return; }
  _captainVoiceBusy = true;
  const txt = _captainVoiceQueue.shift();
  _captainVoicePlay(txt, () => { setTimeout(_captainVoiceNext, 400); });
}

function _captainVoicePlay(txt, done) {
  // ElevenLabs available hai toh wahi use karo — best quality
  if (typeof ARIA_VOICE !== 'undefined' && ARIA_VOICE.useEL && ARIA_VOICE.key) {
    const origNext = ARIA_VOICE.next.bind(ARIA_VOICE);
    ARIA_VOICE.next = function() { ARIA_VOICE.next = origNext; ARIA_VOICE.busy = false; done && done(); };
    if (ARIA_VOICE.busy) { setTimeout(() => _captainVoicePlay(txt, done), 500); return; }
    ARIA_VOICE.busy = true;
    ARIA_VOICE.elSpeak(ARIA_VOICE.clean(txt), () => { ARIA_VOICE.busy = false; ARIA_VOICE.next = origNext; done && done(); });
    return;
  }
  // Google Translate TTS — smooth Hindi female voice, free
  _captainGoogleSpeak(txt, done);
}

function _captainGoogleSpeak(txt, done) {
  // Short chunks pe Google TTS best lagti hai — natural aur clear
  const parts = txt.match(/[^।.!?,]+[।.!?,]*/g) || [txt];
  const chunks = [];
  let cur = '';
  for (const p of parts) {
    if ((cur + p).length > 120) { if (cur.trim()) chunks.push(cur.trim()); cur = p; }
    else cur += p;
  }
  if (cur.trim()) chunks.push(cur.trim());

  let ci = 0;
  function playNext() {
    if (ci >= chunks.length) { done && done(); return; }
    const chunk = chunks[ci];
    const url = 'https://translate.google.com/translate_tts?ie=UTF-8&tl=hi&client=tw-ob&slow=false&q=' + encodeURIComponent(chunk);
    const au = new Audio();
    au.preload = 'auto';
    au.volume = 1.0;
    au.playbackRate = 0.88;

    let played = false;
    let fallbackTimer = null;

    function onReady() {
      if (played) return;
      played = true;
      clearTimeout(fallbackTimer);
      au.play().catch(function() { _captainBrowserSpeak(chunk, function() { ci++; playNext(); }); });
    }

    au.onended = function() { ci++; setTimeout(playNext, 100); };
    au.onerror = function() {
      if (played) return;
      played = true;
      clearTimeout(fallbackTimer);
      _captainBrowserSpeak(chunk, function() { ci++; playNext(); });
    };

    // canplaythrough + canplay dono try karo — browsers alag behave karte hain
    au.addEventListener('canplaythrough', onReady, { once: true });
    au.addEventListener('canplay', onReady, { once: true });

    // Timeout fallback — 3.5s mein load na ho toh browser voice
    fallbackTimer = setTimeout(function() {
      if (!played) {
        played = true;
        _captainBrowserSpeak(chunk, function() { ci++; playNext(); });
      }
    }, 3500);

    au.src = url;
    au.load();
  }
  playNext();
}

function _captainBrowserSpeak(txt, done) {
  if (!window.speechSynthesis) { done && done(); return; }
  window.speechSynthesis.cancel();
  const tryIt = () => {
    const vv = window.speechSynthesis.getVoices();
    const u  = new SpeechSynthesisUtterance(txt);
    u.lang   = 'hi-IN';
    u.rate   = 0.82;   // slow = clear
    u.pitch  = 1.25;   // higher pitch = female sweet voice
    u.volume = 1.0;
    // Best Hindi female voice — priority order
    const v = vv.find(v => v.lang === 'hi-IN' && /google/i.test(v.name) && /female|woman/i.test(v.name))
           || vv.find(v => v.lang === 'hi-IN' && /google/i.test(v.name))
           || vv.find(v => v.lang === 'hi-IN')
           || vv.find(v => v.lang && v.lang.startsWith('hi'))
           || vv.find(v => /lekha|kalpana|heera|rishi/i.test(v.name)) // Indian voices
           || null;
    if (v) { u.voice = v; u.lang = v.lang; }
    u.onend = u.onerror = () => { done && done(); };
    setTimeout(() => { if (window.speechSynthesis.paused) window.speechSynthesis.resume(); }, 80);
    window.speechSynthesis.speak(u);
  };
  const vv = window.speechSynthesis.getVoices();
  if (!vv.length) { window.speechSynthesis.onvoiceschanged = () => { window.speechSynthesis.onvoiceschanged = null; tryIt(); }; }
  else tryIt();
}
function ariaSpeakGirl(t) { if(typeof ariaMuted!=='undefined'&&ariaMuted) return; ARIA_VOICE.say(t); }

// ===================================================
// ADVANCED NOTIFICATION POPUP SYSTEM
// ===================================================
let notifPopupCount = 0;

function showAdvancedNotif(title, message, type='green', voiceMsg='') {
  notifPopupCount++;
  const container = document.getElementById('advNotifPopupContainer');
  if(!container) return;
  
  const id = 'advnotif-' + Date.now();
  const icons = {green:'✅', red:'🚨', orange:'⚠️', blue:'🔔', purple:'⭐'};
  const icon = icons[type] || '🔔';
  
  const popup = document.createElement('div');
  popup.className = `adv-notif-popup ${type}`;
  popup.id = id;
  popup.innerHTML = `
    <button class="notif-close-btn" onclick="dismissNotifPopup('${id}')">✕</button>
    <div style="display:flex;align-items:flex-start;gap:10px">
      <div style="width:36px;height:36px;border-radius:var(--r8);background:${type==='green'?'rgba(5,150,105,.12)':type==='red'?'rgba(220,38,38,.12)':type==='orange'?'rgba(194,65,12,.12)':type==='blue'?'rgba(29,78,216,.12)':'rgba(109,40,217,.12)'};display:flex;align-items:center;justify-content:center;font-size:18px;flex-shrink:0">${icon}</div>
      <div style="flex:1;min-width:0">
        <div style="font-size:13px;font-weight:800;color:var(--ink);margin-bottom:3px;line-height:1.3">${title}</div>
        <div style="font-size:11.5px;color:var(--ink3);font-weight:600;line-height:1.4">${message}</div>
        <div style="font-size:10px;color:var(--ink4);margin-top:4px">${new Date().toLocaleTimeString()}</div>
      </div>
    </div>
    <div style="margin-top:8px;height:3px;background:var(--bg2);border-radius:3px;overflow:hidden">
      <div style="height:100%;background:${type==='green'?'var(--G600)':type==='red'?'var(--red)':type==='orange'?'var(--orange)':type==='blue'?'var(--blue)':'var(--violet)'};width:100%;animation:notifProgress 5s linear forwards" id="${id}-bar"></div>
    </div>`;
  
  container.appendChild(popup);
  
  // Add to dashboard notifications feed
  addDashNotif(icon, title, message, type);
  
  // Speak only if ARIA panel is closed AND ARIA didn't already handle this voice
  if(voiceMsg && voiceMsg !== '__ARIA_SPOKE__' && !(typeof ariaOpen !== 'undefined' && ariaOpen)) {
    speakHindi(voiceMsg);
  }
  
  // Auto dismiss after 5 seconds
  setTimeout(()=>dismissNotifPopup(id), 5200);
}

function dismissNotifPopup(id){
  const el = document.getElementById(id);
  if(!el) return;
  el.style.animation = 'notifSlideOut .3s cubic-bezier(0.4,0,1,1) forwards';
  setTimeout(()=>el.remove(), 320);
}

function addNotification(title, msg, color, voiceMsg) {
  color = color||'green';
  // ONLY Firebase mein save karo — showAdvancedNotif NAHI — wo duplicate popup banata tha
  const typeMap = {green:'success', orange:'warn', red:'alert', blue:'info', purple:'info'};
  if (typeof addNotificationToFirebase === 'function') {
    addNotificationToFirebase(title, msg, typeMap[color]||'info', '');
  }
  const dot = document.getElementById('notifDot');
  if(dot) dot.style.display = 'block';
}

