const dashNotifHistory = [];
function addDashNotif(icon, title, msg, type) {
  dashNotifHistory.unshift({icon, title, msg, type, time: new Date().toLocaleTimeString()});
  refreshDashNotifFeed();
}
function refreshDashNotifFeed(){
  const feed = document.getElementById('dashLiveNotifFeed');
  if(!feed) return;
  const colorMap = {green:'var(--G600)',red:'var(--red)',orange:'var(--orange)',blue:'var(--blue)',purple:'var(--violet)'};
  const last8 = dashNotifHistory.slice(0,8);
  feed.innerHTML = last8.map(n=>`
    <div class="dash-notif-item">
      <div class="dash-notif-dot" style="background:${colorMap[n.type]||'var(--G600)'}"></div>
      <div style="flex:1"><div style="font-size:12px;font-weight:700;color:var(--ink)">${n.icon} ${n.title}</div><div style="font-size:10.5px;color:var(--ink3)">${n.msg}</div></div>
      <div style="font-size:10px;color:var(--ink4);flex-shrink:0">${n.time}</div>
    </div>`).join('') || '<div style="text-align:center;color:var(--ink4);padding:16px;font-size:12px">Koi notification nahi abhi tak</div>';
}

