// ===================================================
let selectedReportPeriod = 'today', selectedReportFormat = 'pdf';

function selectReportPeriod(el, period) {
  selectedReportPeriod = period;
  document.querySelectorAll('.report-period-btn').forEach(b=>b.classList.remove('active'));
  el.classList.add('active');
}
function selectReportFormat(el, fmt) {
  selectedReportFormat = fmt;
  document.querySelectorAll('.report-format-btn').forEach(b=>b.classList.remove('active'));
  el.classList.add('active');
}
function openReportsDownload() { openModal('reportsDownloadModal'); }
function doDownloadReport() {
  const periodLabels = {today:'Aaj ka',week:'Is Hafte ka',month:'1 Mahine ka',twomonth:'2 Mahine ka'};
  const msg = periodLabels[selectedReportPeriod]+' report '+selectedReportFormat.toUpperCase()+' me download ho rahi hai!';
  closeModal('reportsDownloadModal');
  showToast('📥 '+msg);
  speakHindi('report download ho rahi hai');
  
  // Simulate file download
  const blob = new Blob([generateReportCSV()], {type:'text/csv'});
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `CaptainDash_Report_${selectedReportPeriod}_${new Date().toLocaleDateString('en-IN').replace(/\//g,'-')}.${selectedReportFormat==='excel'?'csv':selectedReportFormat}`;
  a.click();
  URL.revokeObjectURL(url);
}
function generateReportCSV(){
  return `CaptainDash Report — ${new Date().toLocaleDateString('en-IN')}
Period: ${selectedReportPeriod}

SALES SUMMARY
Today's Sales,₹48290
This Week,₹282400
This Month,₹941600

ORDER REPORT
Total Orders,184
Completed,168
Cancelled,6

MOST SOLD ITEMS
Margherita Pizza,142
Burger Deluxe,98
Fresh Juice,87

WAITER PERFORMANCE
Raju Sharma,18 orders,4.9 rating
Priya Desai,22 orders,4.7 rating
Salman Shaikh,14 orders,4.8 rating`;
}

