// ===================================================
// WAITER SHIFT FUNCTIONS
// ===================================================
function doAddWaiterShift(){
  const waiter = document.getElementById('shiftWaiterSelect').value;
  const shift = document.getElementById('shiftType').value;
  const floor = document.getElementById('shiftFloor').value;
  const shiftLabels = {morning:'🌅 Morning',evening:'🌆 Evening',night:'🌙 Night'};
  const shiftTimes = {morning:'7AM–3PM',evening:'3PM–11PM',night:'11PM–7AM'};
  
  // Update waiter shift data
  const existing = wmShiftData.find(w=>w.name===waiter);
  if(existing){ existing.shift=shiftLabels[shift]; existing.time=shiftTimes[shift]; existing.floor=floor; }
  else {
    const initials = waiter.split(' ').map(n=>n[0]).join('').substring(0,2);
    wmShiftData.push({name:waiter, shift:shiftLabels[shift], time:shiftTimes[shift], status:'active', floor:floor, color:'linear-gradient(135deg,var(--G600),var(--teal))', avatar:initials});
  }
  buildWaiterShiftBoard();
  closeModal('addWaiterShiftModal');
  showToast('✅ '+waiter+' ki shift add ho gayi!');
  speakHindi(waiter+' ki shift add ho gayi');
}

