// Override kitMarkReady for voice notification
const _origKitMarkReady = window.kitMarkReady;
window.kitMarkReady = function(cardId){
  if(_origKitMarkReady) _origKitMarkReady(cardId);
  const card = document.getElementById(cardId);
  if(card){
    const orderNo = card.querySelector('.kitchen-order-no').textContent;
    const tableNo = card.getAttribute('data-table') || 'table';
    addNotification('✅ Order Ready: '+orderNo, tableNo+' — Waiter ko serve karne bhejo', 'green', 
      tableNo+' ka order ready ho gaya hai, waiter serve karo');
  }
};

// Override lksMoveOrder for voice on delay
const _origLksMoveOrder = window.lksMoveOrder;
window.lksMoveOrder = function(btn, toStatus){
  const card = btn.closest('.lks-order-card');
  const orderNum = card ? card.querySelector('.lks-order-num').textContent : '';
  const tableInfo = card ? card.querySelector('.lks-order-table').textContent : '';
  
  if(_origLksMoveOrder) _origLksMoveOrder(btn, toStatus);
  
  if(toStatus === 'delayed'){
    const tableNum = tableInfo.match(/\d+/) ? tableInfo.match(/\d+/)[0] : tableInfo;
    addNotification('⚠️ Order Delayed: '+orderNum, 'Table '+tableNum+' — customer ko wait karna padega', 'red',
      'table number '+tableNum+' ka order late ho raha hai');
  } else if(toStatus === 'ready'){
    const tableNum = tableInfo.match(/\d+/) ? tableInfo.match(/\d+/)[0] : tableInfo;
    addNotification('✅ Order Ready: '+orderNum, 'Table '+tableNum+' — serve karo!', 'green',
      'table number '+tableNum+' ka order ready ho gaya hai');
  }
};

// New order notification (simulate for demo)
const _origLksAddOrder = window.lksAddOrder;
window.lksAddOrder = function(){
  if(_origLksAddOrder) _origLksAddOrder();
  setTimeout(()=>{
    const col = document.getElementById('lksNewCol');
    if(col){
      const cards = col.querySelectorAll('.lks-order-card');
      const lastCard = cards[cards.length-1];
      if(lastCard){
        const orderNum = lastCard.querySelector('.lks-order-num').textContent;
        const tableEl = lastCard.querySelector('.lks-order-table');
        const tableInfo = tableEl ? tableEl.textContent : '';
        const tableNum = tableInfo.match(/\d+/) ? tableInfo.match(/\d+/)[0] : '?';
        addNotification('🔔 Naya Order: '+orderNum, 'Table '+tableNum+' — Kitchen dekho!', 'blue',
          'table number '+tableNum+' ka naya order aaya hai');
      }
    }
  }, 200);
};

