    ariaAddBubble(revenueMsg, 'cmd-result');
    ariaSpeak('Aaj ki revenue ' + d.revenue + ' hai, ' + d.orders + ' orders complete hue', 'आजचा महसूल ' + d.revenue + ' आहे', 'Today revenue is ' + d.revenue);
