// ── Panel Activity Announcer (when panel is opened) ──
function ariaAnnounceCurrentStatus() {
  const d = ariaReadDashboard();
  const kitUrgent = document.querySelectorAll('.kitchen-card.urgent').length;
  setTimeout(() => {
    let statusMsg = '';
    const alerts = [];
    if(kitUrgent > 0) alerts.push(`${kitUrgent} urgent orders kitchen mein`);
    if(d.occupied > 8) alerts.push(`${d.occupied} tables occupied hain`);

    if(alerts.length > 0) {
      statusMsg = `Captain, dhyan dijiye: ${alerts.join(', ')}!`;
    } else {
      statusMsg = `Captain, sab kuch theek chal raha hai. Revenue ${d.revenue} hai, ${d.occupied} tables occupied hain.`;
    }
    ariaSpeakGirl(statusMsg);
    ariaAddBubble(`📊 <b>Status Update</b><br><span style="font-size:11px">Revenue: ${d.revenue} | Tables: ${d.occupied}/${d.total} | Orders: ${d.orders} | Kitchen urgent: ${kitUrgent}</span>`, 'cmd-result');
  }, 1000);
}

// ── Event Scheduler — Randomized Restaurant Events ──
let ariaEventTimers = [];

function ariaStartMonitoring() {
  // Clear existing
  ariaEventTimers.forEach(t => clearTimeout(t));
  ariaEventTimers = [];

  function scheduleNext() {
    // Random interval 18-40 seconds
    const delay = (18 + Math.floor(Math.random() * 22)) * 1000;
    const t = setTimeout(() => {
      const roll = Math.random();
      if(roll < 0.32) ariaSimulateNewOrder();
      else if(roll < 0.58) ariaSimulateChefReady();
      else if(roll < 0.76) ariaSimulateWaiterRequest();
      else if(roll < 0.88) ariaSimulateKitchenUrgent();
      else ariaSimulateTableUpdate();
      scheduleNext(); // chain next event
    }, delay);
    ariaEventTimers.push(t);
  }

  // First event after 12 seconds
  const firstT = setTimeout(() => {
    ariaSimulateNewOrder();
    scheduleNext();
  }, 12000);
  ariaEventTimers.push(firstT);
}

