function vsRefreshLangButtons() {
  const cur = ARIA_VOICE.lang || 'hi';
  const cfg = ARIA_VOICE.langConfig || {};
  ['hi','mr','en'].forEach(l => {
    const btn = document.getElementById('vsLang' + l.charAt(0).toUpperCase() + l.slice(1));
    if(!btn) return;
    if(l === cur) {
      btn.style.borderColor = l==='hi'?'#059669':l==='mr'?'#c2410c':'#1d4ed8';
      btn.style.background  = l==='hi'?'#ecfdf5':l==='mr'?'#fff7ed':'#eff6ff';
      btn.style.boxShadow   = l==='hi'?'0 2px 8px rgba(5,150,105,.2)':l==='mr'?'0 2px 8px rgba(194,65,12,.2)':'0 2px 8px rgba(29,78,216,.2)';
    } else {
      btn.style.borderColor = '#e5e7eb';
      btn.style.background  = '#fff';
      btn.style.boxShadow   = 'none';
    }
  });
  const note = document.getElementById('vsLangNote');
  if(note) {
    const c = cfg[cur];
    note.textContent = c ? (c.flag + ' Siplora ab ' + c.label + ' mein bolegi — Mic bhi usi bhasha mein sunegi!') : '';
  }
}
