async function saveVS(){
  const key = document.getElementById('vsKey').value.trim();
  const customVid = (document.getElementById('vsCustomVid')?.value || '').trim();
  const dropdownVid = document.getElementById('vsVid').value;
  const vid = customVid || dropdownVid; // custom ID takes priority
  const msg = document.getElementById('vsMsg');

  if(customVid) localStorage.setItem('aria_custom_vid', customVid);

  if(!key){
    ARIA_VOICE.save('', vid);
    vsRefreshStatus();
    msg.style.color='#047857'; msg.textContent='✅ Browser voice set ho gayi!';
    setTimeout(()=>ARIA_VOICE.hindiBrowserSpeak('Theek hai Captain sir! Main Siplora hoon. Browser voice use ho rahi hai.', ()=>{}),200);
    return;
  }

  msg.style.color='#6b7280'; msg.textContent='⏳ ElevenLabs voice test ho rahi hai...';
  ARIA_VOICE.save(key, vid);
  vsRefreshStatus();

  try {
    await new Promise((res, rej)=>{
      const testTxt = ARIA_VOICE.lang === 'hi'
        ? 'Hello Captain sir! Main Siplora hoon. Yeh meri nayi cute awaaz hai. Kaisi lagi?'
        : ARIA_VOICE.lang === 'mr'
        ? 'Hello Captain sir! Mi Siplora ahe. Hi majhi navin god awaaz ahe. Avadli ka?'
        : 'Hello Captain sir! I am Siplora. How do you like my new cute voice?';
      ARIA_VOICE.elSpeak(testTxt, ()=>res());
      setTimeout(()=>rej(new Error('timeout')), 12000);
    });
    msg.style.color='#047857';
    msg.textContent='✅ Voice save aur test ho gayi! ' + (customVid ? '🎤 Custom Voice active!' : '');
  } catch(e) {
    msg.style.color='#dc2626'; msg.textContent='❌ Error — API key ya Voice ID check karo.';
  }
}

function resetVS(){
  ARIA_VOICE.save('','plZ9JnLSXj1tLnvpUX6s');
  document.getElementById('vsKey').value='';
  document.getElementById('vsVid').value='plZ9JnLSXj1tLnvpUX6s';
  const customEl = document.getElementById('vsCustomVid');
  if(customEl) customEl.value = '';
  localStorage.removeItem('aria_custom_vid');
  document.getElementById('vsMsg').textContent='Reset ho gaya — default Siplora voice use hogi.';
  vsRefreshStatus();
}

