// ── 2. AI LATE ALERT SYSTEM ──
// Jab chef ne jo time diya tha us se 10 min zyada ho jaye → dono ko AI alert (voice + visual)
const _captainLateAlertedOrders = new Set();
const _captainOverdue10AlertedOrders = new Set();

function checkCaptainLateAlerts() {
  if (!_captainFirebaseOrders || !_captainFirebaseOrders.length) return;

  const now = Date.now();

  _captainFirebaseOrders.forEach(o => {
    if (['served', 'paid', 'cancelled'].includes(o.status)) return;

    const totalMins = o.estimatedMinutes || o.captainTimer || 0;
    if (!totalMins || !o.acceptedAt) return;

    const elapsedMins = (now - new Date(o.acceptedAt).getTime()) / 60000;
    const overdueMins = elapsedMins - totalMins;
    const tbl = o.tableNumber || o.table || '?';
    const custName = o.customerName || 'Customer';
    const orderKey = o._fbId || (tbl + '_' + totalMins);

    // Jab time 10 min se zyada over ho jaye — alert dono ko
    if (overdueMins >= 10 && !_captainOverdue10AlertedOrders.has(orderKey)) {
      _captainOverdue10AlertedOrders.add(orderKey);

      const overMinsRounded = Math.round(overdueMins);
      const alertMsg = `Chef ko aur ${custName} ko dhyan do! Table ${tbl} ka khana ${totalMins} minute mein ready hona tha. Ab ${overMinsRounded} minute extra ho gaye hain! Jo time diya tha customer ko, us se 10 minute jada ho gaye hain!`;

      // ARIA voice mein bolao
      if (typeof ARIA_VOICE !== 'undefined' && ARIA_VOICE.say) {
        ARIA_VOICE.say(alertMsg);
      } else if (typeof speakHindi === 'function') {
        speakHindi(alertMsg);
      }

      // Visual notification popup
      if (typeof showAdvancedNotif === 'function') {
        showAdvancedNotif(
          `⏰ KHANA LATE HO RAHA HAI! — Table ${tbl}`,
          `${custName} ko ${totalMins} min mein ready hona tha. Ab ${overMinsRounded} min over ho gaye! Chef se baat karo.`,
          'red',
          alertMsg
        );
      }

      // Captain notification banner
      if (typeof showCaptainNotifBanner === 'function') {
        showCaptainNotifBanner(`⏰ LATE ALERT — Table ${tbl} | ${custName} | ${totalMins} min set kiya tha — Ab ${overMinsRounded} min extra ho gaye!`);
      }

      // Beep sound
      if (typeof captainBeep === 'function') {
        captainBeep(440, 0.4);
        setTimeout(() => captainBeep(330, 0.3), 500);
        setTimeout(() => captainBeep(440, 0.4), 1000);
      }

      // Toast
      if (typeof captainToast === 'function') {
        captainToast(`⏰ Table ${tbl} — Khana ${overMinsRounded} min late! Jo time diya tha us se 10 min zyada ho gaye.`, '#dc2626');
      }

      // console.log(`[Late Alert] Table ${tbl} — ${overMinsRounded} min overdue (set: ${totalMins} min)`);
    }
  });
}

// Late alerts auto-check — har 30 second mein
setInterval(checkCaptainLateAlerts, 30000);
// Pehla check 5 seconds mein
setTimeout(checkCaptainLateAlerts, 5000);

