// ═══════════════════════════════════════════════
//  CAPTAIN MENU MANAGER — CLEAN ISOLATED SYSTEM
//  - Sirf Live Menu aur Place Order ko affect karta hai
//  - Koi bhi existing feature/function override nahi
// ═══════════════════════════════════════════════

// Custom categories added by captain (new ones only)
// Base categories pehle se Place Order + Live Menu mein hain
var _capExtraCats = []; // [{key, label}]
var _capImgData   = ''; // base64 or URL for current item being added

// ── IMAGE HANDLING ──
function capSwitchImg(tab) {
  var isFile = tab === 'file';
  document.getElementById('capImgFileDiv').style.display = isFile ? 'block' : 'none';
  document.getElementById('capImgUrlDiv').style.display  = isFile ? 'none'  : 'block';
  document.getElementById('capImgTabFile').className = isFile ? 'btn btn-green' : 'btn btn-outline';
  document.getElementById('capImgTabUrl').className  = isFile ? 'btn btn-outline' : 'btn btn-green';
  document.getElementById('capImgPreview').style.display = 'none';
  _capImgData = '';
}

function capPreviewFile(input) {
  if (!input.files || !input.files[0]) return;
  var reader = new FileReader();
  reader.onload = function(e) {
    _capImgData = e.target.result;
    document.getElementById('capImgEl').src = _capImgData;
    document.getElementById('capImgPreview').style.display = 'block';
  };
  reader.readAsDataURL(input.files[0]);
}

function capPreviewUrl(url) {
  if (!url) return;
  _capImgData = url;
  var img = document.getElementById('capImgEl');
  img.onload  = function() { document.getElementById('capImgPreview').style.display = 'block'; };
  img.onerror = function() { document.getElementById('capImgPreview').style.display = 'none'; _capImgData = ''; };
  img.src = url;
}

// ── OPEN ADD ITEM MODAL ──
function captainOpenAddItem() {
  // Reset
  _capImgData = '';
  ['capDishFile','capDishUrl','capDishName','capDishDesc','capDishPrice','capDishHalf','capDishOffer','capDishDiscount'].forEach(function(id){
    var el = document.getElementById(id);
    if (el) el.value = '';
  });
  document.getElementById('capDishSpicy').value = 'Jain, Normal, Medium, Spicy, Extra Spicy';
  document.getElementById('capImgPreview').style.display = 'none';
  capSwitchImg('file');

  // Populate category dropdown: base cats from menuItems + captain's extra cats
  var baseCats = [];
  var seen = {};
  menuItems.forEach(function(m) {
    if (!seen[m.cat]) {
      seen[m.cat] = true;
      // Try to get nice label from existing buttons
      var lbl = m.cat.charAt(0).toUpperCase() + m.cat.slice(1);
      baseCats.push({key: m.cat, label: lbl});
    }
  });
  var allCats = baseCats.concat(_capExtraCats);
  var sel = document.getElementById('capDishCat');
  sel.innerHTML = allCats.map(function(c) {
    return '<option value="' + c.key + '">' + c.label + '</option>';
  }).join('');

  openModal('captainAddItemModal');
}

// ── DO ADD ITEM ──
function capDoAddItem() {
  var name     = document.getElementById('capDishName').value.trim();
  var cat      = document.getElementById('capDishCat').value;
  var price    = parseInt(document.getElementById('capDishPrice').value);
  var halfP    = parseInt(document.getElementById('capDishHalf').value);
  var desc     = document.getElementById('capDishDesc').value.trim() || 'Delicious dish';
  var offer    = document.getElementById('capDishOffer').value.trim();
  var discount = document.getElementById('capDishDiscount').value.trim();
  var spicyRaw = document.getElementById('capDishSpicy').value;
  var spicy    = spicyRaw.split(',').map(function(s){ return s.trim(); }).filter(Boolean);
  if (spicy.length === 0) spicy = ['Jain','Normal','Medium','Spicy','Extra Spicy'];

  if (!name)             { showToast('⚠️ Dish ka naam dalo!'); return; }
  if (!price || price<=0){ showToast('⚠️ Sahi price dalo!'); return; }
  if (!halfP || halfP<=0){ showToast('⚠️ Sahi half price dalo!'); return; }

  // Emoji fallback by category
  var emojiMap = {pizza:'🍕',burger:'🍔',pasta:'🍜',drinks:'🥤',combos:'🎁',wraps:'🌯',dessert:'🍰'};
  var emoji = emojiMap[cat] || '🍽️';

  var newId = 0;
  menuItems.forEach(function(m){ if(m.id > newId) newId = m.id; });
  newId++;

  var newItem = {
    id: newId,
    name: name, cat: cat, price: price, halfPrice: halfP,
    emoji: emoji,
    _capImage: _capImgData || null,
    offer: offer, discount: discount, spicy: spicy, desc: desc,
    active: true
  };

  menuItems.push(newItem);
  closeModal('captainAddItemModal');
  showToast('✅ "' + name + '" menu mein add ho gaya!');

  // Refresh Live Menu
  _capRebuildLiveMenu(menuItems);
  // Refresh Place Order menu
  buildOrderMenu(menuItems);
  // Add category button if it's a new captain cat
  _capSyncNewCatButtons(cat);
}

// ── DELETE ITEM ──
function capDeleteItem(id) {
  var item = null;
  menuItems.forEach(function(m){ if(m.id===id) item=m; });
  if (!item) return;
  if (!confirm('"' + item.name + '" ko delete karna chahte ho?')) return;
  var idx = menuItems.indexOf(item);
  menuItems.splice(idx, 1);
  _capRebuildLiveMenu(menuItems);
  buildOrderMenu(menuItems);
  showToast('🗑️ "' + item.name + '" delete ho gaya!');
}

// ── REBUILD LIVE MENU (captain's version, with image + delete) ──
function _capRebuildLiveMenu(items) {
  var g = document.getElementById('liveMenuGrid');
  if (!g) return;
  var active = items.filter(function(i){ return i.active !== false; });
  g.innerHTML = active.map(function(item) {
    var imgHtml;
    if (item._capImage) {
      imgHtml = '<img src="' + item._capImage + '" style="width:100%;height:110px;object-fit:cover;border-radius:10px 10px 0 0;display:block" onerror="this.style.display=\'none\'">';
    } else {
      imgHtml = '<div class="menu-item-img-placeholder">' + item.emoji + '</div>';
    }
    var catLabel = item.cat.charAt(0).toUpperCase() + item.cat.slice(1);
    _capExtraCats.forEach(function(c){ if(c.key===item.cat) catLabel=c.label; });

    return '<div class="menu-item" data-menucat="' + item.cat + '">'
      + (item.offer    ? '<div class="menu-offer-tag">'    + item.offer    + '</div>' : '')
      + (item.discount ? '<div class="menu-discount-tag">' + item.discount + '</div>' : '')
      + imgHtml
      + '<div class="menu-item-body">'
        + '<div class="menu-item-info">'
          + '<div class="menu-cat">' + catLabel + '</div>'
          + '<div class="menu-name">' + item.name + '</div>'
          + '<div style="font-size:10px;color:var(--ink3);margin:2px 0 4px">' + item.desc + '</div>'
          + '<div style="display:flex;gap:6px;margin-bottom:4px;align-items:center">'
            + '<span style="font-size:12px;font-weight:900;color:var(--G700);font-family:\'JetBrains Mono\',monospace">🍽️ ₹' + item.price + '</span>'
            + '<span style="font-size:10px;color:var(--ink4)">Full</span>'
            + '<span style="font-size:11px;color:var(--ink4)">|</span>'
            + '<span style="font-size:12px;font-weight:900;color:var(--amber);font-family:\'JetBrains Mono\',monospace">🥣 ₹' + item.halfPrice + '</span>'
            + '<span style="font-size:10px;color:var(--ink4)">Half</span>'
          + '</div>'
          + '<div style="display:flex;gap:4px;margin-top:4px;flex-wrap:wrap">'
            + item.spicy.map(function(s){ return '<span style="font-size:9px;padding:2px 6px;border-radius:20px;background:var(--bg2);border:1px solid var(--line);color:var(--ink3)">' + (typeof getSpiceIcon==='function'?getSpiceIcon(s):'') + ' ' + s + '</span>'; }).join('')
          + '</div>'
        + '</div>'
        + '<div class="menu-avail" style="display:flex;flex-direction:column;gap:8px;align-items:flex-end">'
          + '<div class="toggle on" onclick="this.classList.toggle(\'on\')"></div>'
          + '<button onclick="capDeleteItem(' + item.id + ')" title="Delete" style="background:var(--red-bg);border:1px solid rgba(220,38,38,.25);color:var(--red);border-radius:6px;padding:3px 9px;font-size:11px;font-weight:700;cursor:pointer;line-height:1">🗑️</button>'
        + '</div>'
      + '</div>'
    + '</div>';
  }).join('');
}

// ── CATEGORY MANAGEMENT ──
function captainOpenManageCats() {
  _capRenderCatList();
  openModal('captainManageCatsModal');
}

function _capRenderCatList() {
  var c = document.getElementById('capCatList');
  if (!c) return;
  // Show only captain-added extra cats (base cats shouldn't be deleted as they have existing items)
  if (_capExtraCats.length === 0) {
    c.innerHTML = '<div style="font-size:12px;color:var(--ink4);padding:10px;text-align:center">Koi custom category nahi hai. Upar se add karo.</div>';
    return;
  }
  c.innerHTML = _capExtraCats.map(function(cat) {
    var count = menuItems.filter(function(m){ return m.cat===cat.key; }).length;
    return '<div style="display:flex;align-items:center;gap:10px;background:var(--bg);border:1px solid var(--line);border-radius:8px;padding:8px 11px">'
      + '<span style="font-size:15px">' + cat.label.split(' ')[0] + '</span>'
      + '<span style="flex:1;font-size:13px;font-weight:700;color:var(--ink)">' + cat.label.replace(/^\S+\s*/,'') + '</span>'
      + '<span style="font-size:10px;color:var(--ink4)">' + count + ' items</span>'
      + '<button onclick="capDeleteCategory(\'' + cat.key + '\')" style="background:var(--red-bg);border:1px solid rgba(220,38,38,.2);color:var(--red);border-radius:6px;padding:3px 9px;font-size:10px;font-weight:700;cursor:pointer">🗑️</button>'
    + '</div>';
  }).join('');
}

function capAddCategory() {
  var emoji = document.getElementById('capCatEmoji').value.trim();
  var name  = document.getElementById('capCatName').value.trim();
  if (!name) { showToast('⚠️ Category naam dalo!'); return; }
  var key = name.toLowerCase().replace(/\s+/g,'_');
  // Check not duplicate
  var dup = false;
  menuItems.forEach(function(m){ if(m.cat===key) dup=true; });
  _capExtraCats.forEach(function(c){ if(c.key===key) dup=true; });
  if (dup) { showToast('⚠️ Ye category already exist karti hai!'); return; }
  var label = (emoji ? emoji + ' ' : '') + name;
  _capExtraCats.push({key:key, label:label});
  document.getElementById('capCatEmoji').value = '';
  document.getElementById('capCatName').value  = '';
  _capSyncNewCatButtons(key);
  _capRenderCatList();
  showToast('✅ Category "' + label + '" add ho gayi!');
}

function capDeleteCategory(key) {
  var count = menuItems.filter(function(m){ return m.cat===key; }).length;
  if (count > 0) { showToast('⚠️ Pehle is category ke ' + count + ' items delete karo!'); return; }
  _capExtraCats = _capExtraCats.filter(function(c){ return c.key!==key; });
  // Remove dynamic buttons
  ['captainLiveMenuDynCats','captainOrderDynCats'].forEach(function(containerId){
    var cont = document.getElementById(containerId);
    if (!cont) return;
    var btns = cont.querySelectorAll('[data-capcat="'+key+'"]');
    btns.forEach(function(b){ b.remove(); });
  });
  _capRenderCatList();
  showToast('🗑️ Category delete ho gayi!');
}

// ── INJECT NEW CATEGORY BUTTON INTO BOTH FILTER ROWS ──
function _capSyncNewCatButtons(key) {
  // Check if this is an extra cat
  var catObj = null;
  _capExtraCats.forEach(function(c){ if(c.key===key) catObj=c; });
  if (!catObj) return; // base cat, already has button

  // Live Menu dynamic cats
  var lmCont = document.getElementById('captainLiveMenuDynCats');
  if (lmCont && !lmCont.querySelector('[data-capcat="'+key+'"]')) {
    var b1 = document.createElement('button');
    b1.className = 'btn btn-outline';
    b1.textContent = catObj.label;
    b1.setAttribute('data-capcat', key);
    b1.onclick = (function(k){ return function(){ filterMenuCat(k, this); }; })(key);
    lmCont.appendChild(b1);
  }
  // Place Order dynamic cats
  var poCont = document.getElementById('captainOrderDynCats');
  if (poCont && !poCont.querySelector('[data-capcat="'+key+'"]')) {
    var b2 = document.createElement('button');
    b2.className = 'btn btn-outline';
    b2.textContent = catObj.label;
    b2.setAttribute('data-capcat', key);
    b2.onclick = (function(k){ return function(){ filterCat(k, this); }; })(key);
    poCont.appendChild(b2);
  }
}

