// ═══════════════════════════════════════════════════════════════
// 🔔 NOTIFICATIONS — FIREBASE SYNC
// Collection: 'captainNotifications'
// ═══════════════════════════════════════════════════════════════

// ── Real-time notifications listener (duplicate-safe + auto-cleanup) ──
var _captainShownNotifIds = new Set();
var _captainNotifListenerStarted = false;
function startNotificationsListener() {
  if (!_captainDb || !_captainCollection || !_captainOnSnapshot) return;
  if (_captainNotifListenerStarted) return;
  _captainNotifListenerStarted = true;

  // Purani saari notifications delete karo — sirf 2 min ki chahiye
  _captainAutoCleanOldNotifications();

  var notifRef = _captainCollection(_captainDb, 'captainNotifications');
  import("https://www.gstatic.com/firebasejs/10.12.2/firebase-firestore.js").then(function(mod) {
    var cutoff2min = Date.now() - (2 * 60 * 1000);
    var q = mod.query(notifRef, mod.orderBy('createdAt','desc'), mod.limit(20));
    _captainOnSnapshot(q, function(snap) {
      var now2min = Date.now() - (2 * 60 * 1000); // har snapshot pe fresh cutoff
      var notifs = [];
      snap.forEach(function(d) {
        var n = d.data(); n._fbId = d.id;
        if ((n.createdAt || 0) >= now2min) notifs.push(n); // sirf 2 min wali
      });
      notifs.sort(function(a,b){ return (b.createdAt||0)-(a.createdAt||0); });
      _renderNotifications(notifs);

      // Sirf naye added docs ke liye banner — aur sirf ek baar
      snap.docChanges().forEach(function(change) {
        if (change.type === 'added') {
          var n = change.doc.data(); var nId = change.doc.id;
          var fresh2min = Date.now() - (2 * 60 * 1000);
          if (!n.read && !_captainShownNotifIds.has(nId) && (n.createdAt||0) >= fresh2min) {
            _captainShownNotifIds.add(nId);
            showCaptainNotifBanner((n.icon||'🔔') + ' ' + (n.title||'') + ' — ' + (n.body||''));
          }
          // 2 min se purani noti automatically delete karo
          if ((n.createdAt||0) < fresh2min) {
            mod.deleteDoc(change.doc.ref).catch(function(){});
          }
        }
      });
    });
  }).catch(function() {
    _startNotifListenerFallback();
  });
}

function _startNotifListenerFallback() {
  _captainOnSnapshot(_captainCollection(_captainDb, 'captainNotifications'), function(snap) {
    var now2min = Date.now() - (2 * 60 * 1000);
    var notifs = [];
    snap.forEach(function(d) {
      var n = d.data(); n._fbId = d.id;
      if ((n.createdAt || 0) >= now2min) notifs.push(n);
    });
    notifs.sort(function(a,b){ return (b.createdAt||0)-(a.createdAt||0); });
    _renderNotifications(notifs);
    snap.docChanges().forEach(function(change) {
      if (change.type === 'added') {
        var n = change.doc.data(); var nId = change.doc.id;
        var fresh2min = Date.now() - (2 * 60 * 1000);
        if (!n.read && !_captainShownNotifIds.has(nId) && (n.createdAt||0) >= fresh2min) {
          _captainShownNotifIds.add(nId);
          showCaptainNotifBanner((n.icon||'🔔') + ' ' + (n.title||'') + ' — ' + (n.body||''));
        }
      }
    });
  });
}

// ── Auto-cleanup: 2 min se purani saari notifications delete karo ──
async function _captainAutoCleanOldNotifications() {
  if (!_captainDb || !_captainCollection) return;
  try {
    var mod = await import("https://www.gstatic.com/firebasejs/10.12.2/firebase-firestore.js");
    var cutoff2min = Date.now() - (2 * 60 * 1000);
    var q = mod.query(
      _captainCollection(_captainDb, 'captainNotifications'),
      mod.orderBy('createdAt','asc'),
      mod.limit(500)
    );
    var snap = await mod.getDocs(q);
    var batch = mod.writeBatch(_captainDb);
    var count = 0;
    snap.forEach(function(d) {
      var n = d.data();
      if (!n.createdAt || n.createdAt < cutoff2min) { batch.delete(d.ref); count++; }
    });
    if (count > 0) await batch.commit();
  } catch(e) { /* silent */ }
}

// ── Notifications page mein render karo (Firebase se — no duplicates) ──
function _renderNotifications(notifs) {
  var list = document.getElementById('captainNotifList') || document.querySelector('#page-notifications .notif-list');
  if (!list) return;

  if (notifs.length === 0) {
    list.innerHTML = '<div style="text-align:center;padding:40px;color:var(--ink4);font-size:13px;font-weight:600">&#127881; Koi notification nahi &#8212; sab theek hai!</div>';
    var badgeC = document.querySelector('.nav-item[onclick*="notifications"] .nav-badge');
    if (badgeC) { badgeC.textContent = ''; badgeC.style.display = 'none'; }
    return;
  }

  var typeStyles = {
    alert:  { bg: 'rgba(248,113,113,.15)', icon: '&#128680;', cls: 'alert' },
    warn:   { bg: 'rgba(251,191,36,.15)',  icon: '&#9888;&#65039;', cls: 'warn' },
    info:   { bg: 'rgba(56,189,248,.15)',  icon: '&#8505;&#65039;', cls: '' },
    success:{ bg: 'rgba(34,197,94,.15)',   icon: '&#9989;', cls: 'unread' },
    order:  { bg: 'rgba(99,102,241,.15)',  icon: '&#128722;', cls: 'unread' },
    chef:   { bg: 'rgba(34,197,94,.15)',   icon: '&#128104;&#8205;&#127859;', cls: 'unread' },
  };

  list.innerHTML = notifs.map(function(n) {
    var s = typeStyles[n.type] || typeStyles.info;
    var icon = n.icon || s.icon;
    var bg   = s.bg;
    var cls  = n.read ? '' : s.cls;
    var timeAgo = _timeAgo(n.createdAt);
    var safeTitle = (n.title || '').replace(/</g,'&lt;').replace(/>/g,'&gt;');
    var safeBody  = (n.body  || '').replace(/</g,'&lt;').replace(/>/g,'&gt;');
    return '<div class="notif-item ' + cls + '" data-fbid="' + n._fbId + '" onclick="_markNotifRead(\'' + n._fbId + '\',this)">' +
      '<div class="notif-icon" style="background:' + bg + '">' + icon + '</div>' +
      '<div class="notif-text">' +
        '<div class="notif-title">' + safeTitle + '</div>' +
        '<div class="notif-sub">'  + safeBody  + '</div>' +
      '</div>' +
      '<div class="notif-time">' + timeAgo + '</div>' +
    '</div>';
  }).join('');

  var unread = notifs.filter(function(n){ return !n.read; }).length;
  var badge = document.querySelector('.nav-item[onclick*="notifications"] .nav-badge');
  if (badge) { badge.textContent = unread > 0 ? unread : ''; badge.style.display = unread > 0 ? '' : 'none'; }
  var dot = document.getElementById('notifDot');
  if (dot) dot.style.display = unread > 0 ? 'block' : 'none';
}

// ── Notification read mark karo Firebase mein ──
async function _markNotifRead(fbId, el) {
  if (el) el.classList.remove('alert','warn','unread');
  if (!_captainDb || !fbId) return;
  try {
    const { doc, updateDoc } = await import("https://www.gstatic.com/firebasejs/10.12.2/firebase-firestore.js");
    await updateDoc(doc(_captainDb, 'captainNotifications', fbId), { read: true });
  } catch(e) { console.warn('Notif read error:', e); }
}

// ── Naya notification Firebase mein save karo (duplicate-safe: 60s window) ──
var _captainNotifRateMap = {}; // title+body → last save timestamp
async function addNotificationToFirebase(title, body, type, icon) {
  if (!_captainDb || !_captainAddDoc || !_captainCollection) return;
  // Duplicate check: same title+body 5 minutes mein dobara mat save karo
  var key = (title||'') + '||' + (body||'');
  var now = Date.now();
  if (_captainNotifRateMap[key] && (now - _captainNotifRateMap[key]) < 300000) {
    // console.log('🔔 Duplicate notif skipped:', title);
    return;
  }
  _captainNotifRateMap[key] = now;
  // Purane entries clean karo (memory leak nahi chahiye)
  var keys = Object.keys(_captainNotifRateMap);
  if (keys.length > 100) {
    keys.slice(0, 50).forEach(function(k){ delete _captainNotifRateMap[k]; });
  }
  try {
    await _captainAddDoc(_captainCollection(_captainDb, 'captainNotifications'), {
      title: title || '',
      body:  body  || '',
      type:  type  || 'info',
      icon:  icon  || '',
      read:  false,
      createdAt: now
    });
  } catch(e) { console.warn('Notif add error:', e); }
}

// ── Time ago helper ──
function _timeAgo(ts) {
  if (!ts) return '';
  var diff = Math.floor((Date.now() - ts) / 1000);
  if (diff < 60)  return diff + 's ago';
  if (diff < 3600) return Math.floor(diff/60) + 'm ago';
  if (diff < 86400) return Math.floor(diff/3600) + 'h ago';
  return Math.floor(diff/86400) + 'd ago';
}

// ── Saari notifications Firebase se delete karo ──
async function clearAllNotifications() {
  if (!_captainDb) { showToast && showToast('Firebase connected nahi!', '#f59e0b'); return; }
  if (!confirm('Saari notifications delete karein? Ye undo nahi hoga.')) return;
  try {
    const { collection, getDocs, deleteDoc, doc } = await import("https://www.gstatic.com/firebasejs/10.12.2/firebase-firestore.js");
    const snap = await getDocs(collection(_captainDb, 'captainNotifications'));
    const delPromises = [];
    snap.forEach(function(d) { delPromises.push(deleteDoc(doc(_captainDb, 'captainNotifications', d.id))); });
    await Promise.all(delPromises);
    _captainNotifRateMap = {};
    _captainShownNotifIds = new Set();
    if (typeof showToast === 'function') showToast('🗑️ Saari notifications clear ho gayi!', '#059669');
    // console.log('[Captain] All notifications cleared:', delPromises.length);
  } catch(e) {
    if (typeof showToast === 'function') showToast('Error: ' + e.message, '#dc2626');
    console.error('Clear notifs error:', e);
  }
}

// ── markNotifRead global override (topbar bell ke liye) ──
window.markNotifRead = function() {
  document.getElementById('notifDot').style.display = 'none';
};

// console.log('  🔔 Notifications Firebase real-time sync ✓');

// ═══════════════════════════════════════════════════════════════
// 📊 REPORTS — FIREBASE SE LIVE DATA
// Orders collection se real sales data calculate karo
// ═══════════════════════════════════════════════════════════════

async function _loadReportsFromFirebase() {
  if (!_captainDb || !_captainCollection) return;
  try {
    const { getDocs, collection } = await import("https://www.gstatic.com/firebasejs/10.12.2/firebase-firestore.js");
    const snap = await getDocs(collection(_captainDb, 'orders'));

    var allOrders = [];
    snap.forEach(function(d) { allOrders.push(d.data()); });

    // Time filters
    var now = Date.now();
    var todayStart  = new Date(); todayStart.setHours(0,0,0,0); var todayTs = todayStart.getTime();
    var weekTs      = now - 7  * 24 * 60 * 60 * 1000;
    var monthTs     = now - 30 * 24 * 60 * 60 * 1000;

    // Sales calculation
    var todaySales = 0, weekSales = 0, monthSales = 0;
    var todayOrders = 0, completedOrders = 0, cancelledOrders = 0;
    var itemCount = {};

    allOrders.forEach(function(o) {
      var ts = o.createdAt || o.savedAt || 0;
      var total = o.totalAmount || o.total || o.grandTotal || 0;
      if (ts >= todayTs) {
        todaySales  += total;
        todayOrders += 1;
        if (o.status === 'cancelled') cancelledOrders++;
        else completedOrders++;
        // Item count
        if (o.items) o.items.forEach(function(item) {
          itemCount[item.name] = (itemCount[item.name] || 0) + (item.qty || 1);
        });
      }
      if (ts >= weekTs)  weekSales  += total;
      if (ts >= monthTs) monthSales += total;
    });

    // Most sold items — top 3
    var sortedItems = Object.entries(itemCount).sort(function(a,b){ return b[1]-a[1]; }).slice(0,3);

    // Reports page update karo
    var rPage = document.getElementById('page-reports');
    if (!rPage) return;
    var cards = rPage.querySelectorAll('.report-card');

    // Sales Summary card
    if (cards[0]) {
      var rows = cards[0].querySelectorAll('.report-val');
      if (rows[0]) rows[0].textContent = '₹' + todaySales.toLocaleString('en-IN');
      if (rows[1]) rows[1].textContent = '₹' + weekSales.toLocaleString('en-IN');
      if (rows[2]) rows[2].textContent = '₹' + monthSales.toLocaleString('en-IN');
    }

    // Order Report card
    if (cards[1]) {
      var orows = cards[1].querySelectorAll('.report-val');
      if (orows[0]) orows[0].textContent = todayOrders;
      if (orows[1]) orows[1].textContent = completedOrders;
      if (orows[2]) orows[2].textContent = cancelledOrders;
    }

    // Most Sold Items card
    if (cards[2] && sortedItems.length > 0) {
      var emojis = ['🍕','🍔','🥤','🍜','🍣','🍛'];
      var irows = cards[2].querySelectorAll('.report-row');
      sortedItems.forEach(function(item, idx) {
        if (irows[idx]) {
          irows[idx].querySelector('span').textContent = (emojis[idx] || '🍽️') + ' ' + item[0];
          irows[idx].querySelector('.report-val').textContent = item[1];
        }
      });
    }

    // console.log('✅ Reports loaded from Firebase — Orders:', allOrders.length);
  } catch(e) {
    console.warn('Reports load error:', e);
  }
}


// Reports ke liye ek hi baar onSnapshot lagao (infinite loop avoid)
var _reportsListenerStarted = false;
function startReportsListener() {
  if (_reportsListenerStarted || !_captainDb || !_captainCollection || !_captainOnSnapshot) return;
  _reportsListenerStarted = true;
  _captainOnSnapshot(_captainCollection(_captainDb, 'orders'), function() {
    _loadReportsFromFirebase();
  });
}
