// ═══════════════════════════════════════════════════════════════════════════
// 👥 CUSTOMERS & VIP + 🎁 LOYALTY POINTS — FULL FIREBASE + AI SYSTEM
// Collections: captainCustomers, captainLoyaltyConfig
// ═══════════════════════════════════════════════════════════════════════════

var _custDb = null;            // shared with _captainDb
var _custData = [];            // live array from Firebase
var _custCurrentFilter = 'all';
var _custEditId = null;        // for detail modal
var _loyConfig = { perRupee: 10, ptsEarned: 1, expDays: 90 };
var _loyCurrentFilter = 'all';

// ── Wait for Firebase then boot ──────────────────────────────────────────
(function bootCustomerSystem() {
  function tryBoot() {
    if (_captainDb && _captainCollection && _captainOnSnapshot && _captainAddDoc) {
      _custDb = _captainDb;
      _startCustomerListener();
      _loadLoyaltyConfig();
      // console.log('✅ Customer & Loyalty system booted');
    } else {
      setTimeout(tryBoot, 1500);
    }
  }
  setTimeout(tryBoot, 2500);
})();

// ── REAL-TIME CUSTOMER LISTENER ──────────────────────────────────────────
function _startCustomerListener() {
  _captainOnSnapshot(_captainCollection(_custDb, 'captainCustomers'), function(snap) {
    _custData = [];
    snap.forEach(function(d) {
      var c = d.data(); c._fbId = d.id;
      _custData.push(c);
    });
    _custData.sort(function(a,b){ return (b.totalSpend||0)-(a.totalSpend||0); });
    _autoTierAllCustomers();
    _renderCustomerCards(_custFilter(_custCurrentFilter));
    _renderLoyaltyCards(_loyFilter(_loyCurrentFilter));
    _updateCustStats();
    _updateLoyaltyStats();
    _checkBirthdays();
    _runCustAI();
    _runLoyaltyAI();
    // console.log('🔄 Customers synced:', _custData.length);
  });
}

// ── AUTO TIER LOGIC ──────────────────────────────────────────────────────
function _autoTierAllCustomers() {
  _custData.forEach(function(c) {
    var sp = c.totalSpend || 0;
    var visits = c.visits || 0;
    if (sp >= 50000 || visits >= 50)      c.tier = 'vip';
    else if (sp >= 20000 || visits >= 20) c.tier = 'gold';
    else if (sp >= 5000  || visits >= 8)  c.tier = 'silver';
    else                                   c.tier = 'bronze';
  });
}

// ── FILTER HELPERS ───────────────────────────────────────────────────────
function _custFilter(f) {
  var q = (document.getElementById('custSearch')||{}).value||'';
  if (f==='search' || q) {
    return _custData.filter(function(c){
      return (c.name||'').toLowerCase().includes(q.toLowerCase()) ||
             (c.phone||'').includes(q);
    });
  }
  if (f==='all') return _custData;
  return _custData.filter(function(c){ return c.tier===f; });
}
function _loyFilter(f) {
  if (f==='high') return [..._custData].sort(function(a,b){return (b.loyaltyPoints||0)-(a.loyaltyPoints||0);});
  if (f==='expiring') {
    var expMs = _loyConfig.expDays * 86400000;
    var now = Date.now();
    return _custData.filter(function(c){
      return c.pointsEarnedAt && (now - c.pointsEarnedAt) > (expMs * 0.75) && (c.loyaltyPoints||0) > 0;
    });
  }
  return _custData;
}

// ── RENDER CUSTOMER CARDS ────────────────────────────────────────────────
function _renderCustomerCards(list) {
  var grid = document.getElementById('custCardsGrid');
  if (!grid) return;
  if (!list || list.length===0) {
    grid.innerHTML = '<div style="grid-column:1/-1;text-align:center;padding:40px;color:var(--ink4);font-size:13px;font-weight:600">📭 Koi customer nahi mila. Upar se add karo!</div>';
    return;
  }
  var tierColors = { vip:'linear-gradient(135deg,#7c3aed,#4f46e5)', gold:'linear-gradient(135deg,#d97706,#b45309)', silver:'linear-gradient(135deg,#6b7280,#4b5563)', bronze:'linear-gradient(135deg,#b45309,#92400e)' };
  var tierLabels = { vip:'👑 VIP', gold:'🥇 Gold', silver:'🥈 Silver', bronze:'🥉 Bronze' };
  var tierClass  = { vip:'vip-card', gold:'gold-card', silver:'silver-card', bronze:'silver-card' };
  var maxSpend = Math.max.apply(null, _custData.map(function(c){return c.totalSpend||0;})) || 1;

  grid.innerHTML = list.map(function(c) {
    var tier = c.tier||'bronze';
    var av   = (c.name||'?').charAt(0).toUpperCase();
    var stars = Math.min(5, Math.round((c.avgRating||3)));
    var starStr = '⭐'.repeat(stars);
    var pct = Math.round(((c.totalSpend||0)/maxSpend)*100);
    var lastVisit = c.lastVisit ? _timeAgoMs(c.lastVisit) : 'Never';
    var bdayFlag = _isBirthday(c.birthday) ? '🎂 ' : '';
    return '<div class="customer-card '+tierClass[tier]+'" onclick="openCustDetail(\''+c._fbId+'\')">'+
      '<div class="cust-tier-badge '+tier+'">'+tierLabels[tier]+'</div>'+
      '<div class="customer-head">'+
        '<div class="customer-avatar" style="background:'+tierColors[tier]+'">'+av+'</div>'+
        '<div>'+
          '<div style="font-size:13px;font-weight:800;color:var(--ink)">'+bdayFlag+(c.name||'—')+'</div>'+
          '<div style="font-size:11px;color:var(--ink3);font-weight:600">📞 '+(c.phone||'—')+'&nbsp;·&nbsp;'+((c.visits||0))+' visits</div>'+
          '<div class="star-row">'+starStr+'</div>'+
        '</div>'+
      '</div>'+
      '<div class="cust-meta-row">'+
        '<span>💰 ₹'+(c.totalSpend||0).toLocaleString('en-IN')+'</span>'+
        '<span>🎁 '+(c.loyaltyPoints||0)+' pts</span>'+
        '<span>🕒 '+lastVisit+'</span>'+
      '</div>'+
      '<div class="cust-pts-bar"><div class="cust-pts-fill" style="width:'+pct+'%"></div></div>'+
    '</div>';
  }).join('');
}

// ── RENDER LOYALTY CARDS ─────────────────────────────────────────────────
function _renderLoyaltyCards(list) {
  var grid = document.getElementById('loyCardsGrid');
  if (!grid) return;
  if (!list || list.length===0) {
    grid.innerHTML = '<div style="grid-column:1/-1;text-align:center;padding:40px;color:var(--ink4);font-size:13px;font-weight:600">📭 Koi data nahi</div>';
    return;
  }
  var expMs = _loyConfig.expDays * 86400000;
  grid.innerHTML = list.filter(function(c){ return (c.loyaltyPoints||0)>=0; }).map(function(c,i) {
    var isExpiring = c.pointsEarnedAt && (Date.now()-c.pointsEarnedAt) > (expMs*0.75) && (c.loyaltyPoints||0)>0;
    var daysLeft = c.pointsEarnedAt ? Math.max(0,Math.round((_loyConfig.expDays*86400000-(Date.now()-c.pointsEarnedAt))/86400000)) : _loyConfig.expDays;
    var rank = ['🥇','🥈','🥉'][i]||'🎖️';
    var streak = c.visitStreak||0;
    return '<div class="loyalty-card" onclick="openCustDetail(\''+c._fbId+'\')">'+
      '<div style="display:flex;align-items:center;gap:8px;margin-bottom:8px">'+
        '<span style="font-size:16px">'+rank+'</span>'+
        '<div>'+
          '<div style="font-size:12px;font-weight:800;color:var(--ink)">'+(c.name||'—')+'</div>'+
          '<div style="font-size:10.5px;color:var(--ink3);font-weight:600">'+((c.phone||''))+'</div>'+
        '</div>'+
      '</div>'+
      '<div class="loyalty-points">'+(c.loyaltyPoints||0).toLocaleString()+'</div>'+
      '<div style="font-size:10px;color:var(--ink3);font-weight:600">points</div>'+
      (streak>0?'<div class="loy-streak">🔥 '+streak+' day streak</div>':'')+
      (isExpiring?'<div class="loy-expiry">⏳ '+daysLeft+' din mein expire</div>':'')+
      '<div style="display:flex;gap:6px;margin-top:10px">'+
        '<button class="btn btn-outline" onclick="event.stopPropagation();quickAddPoints(\''+c._fbId+'\')" style="flex:1;font-size:10px;padding:4px">➕ Points</button>'+
        '<button class="btn btn-outline" onclick="event.stopPropagation();openRedeemForCustomer(\''+c._fbId+'\')" style="flex:1;font-size:10px;padding:4px;color:var(--amber);border-color:var(--amber)">🎁 Redeem</button>'+
      '</div>'+
    '</div>';
  }).join('');
}

// ── STAT UPDATES ─────────────────────────────────────────────────────────
function _updateCustStats() {
  var total  = _custData.length;
  var vips   = _custData.filter(function(c){return c.tier==='vip'||c.tier==='gold';}).length;
  var repeat  = total>0?Math.round((_custData.filter(function(c){return (c.visits||0)>1;}).length/total)*100):0;
  var todayStart = new Date(); todayStart.setHours(0,0,0,0);
  var todayV = _custData.filter(function(c){return c.lastVisit && c.lastVisit>=todayStart.getTime();}).length;
  _setText('cst-total', total);
  _setText('cst-vip',   vips);
  _setText('cst-repeat',repeat+'%');
  _setText('cst-today', todayV);
}
function _updateLoyaltyStats() {
  var totalPts   = _custData.reduce(function(s,c){return s+(c.loyaltyPoints||0);},0);
  var todayRedeem= _custData.reduce(function(s,c){return s+(c.redeemedToday||0);},0);
  var expMs = _loyConfig.expDays*86400000;
  var expiring   = _custData.filter(function(c){return c.pointsEarnedAt&&(Date.now()-c.pointsEarnedAt)>(expMs*0.75)&&(c.loyaltyPoints||0)>0;}).length;
  var topPts     = _custData.reduce(function(m,c){return Math.max(m,c.loyaltyPoints||0);},0);
  _setText('loy-total',    totalPts.toLocaleString());
  _setText('loy-redeemed', todayRedeem);
  _setText('loy-expiring', expiring);
  _setText('loy-top',      topPts.toLocaleString());
}

// ── BIRTHDAY CHECKER ─────────────────────────────────────────────────────
function _checkBirthdays() {
  var bar = document.getElementById('custBdayBar');
  if (!bar) return;
  var today = new Date();
  var mm = String(today.getMonth()+1).padStart(2,'0');
  var dd = String(today.getDate()).padStart(2,'0');
  var bdays = _custData.filter(function(c){
    if (!c.birthday) return false;
    var parts = c.birthday.split('-');
    return parts[1]===mm && parts[2]===dd;
  });
  if (bdays.length>0) {
    bar.style.display='block';
    bar.innerHTML = '🎂 <b>Aaj Birthday:</b> ' + bdays.map(function(c){return c.name;}).join(', ') + ' — Special discount ya free dessert dena mat bhoolo!';
    addNotificationToFirebase('🎂 Birthday Alert', bdays.map(function(c){return c.name;}).join(', ')+" ka aaj birthday hai!", 'info', '🎂');
  } else {
    bar.style.display='none';
  }
}
function _isBirthday(bday) {
  if (!bday) return false;
  var today = new Date();
  var parts = bday.split('-');
  return parts[1]===String(today.getMonth()+1).padStart(2,'0') && parts[2]===String(today.getDate()).padStart(2,'0');
}

// ── ADD CUSTOMER ─────────────────────────────────────────────────────────
function openAddCustomerModal() { openModal('addCustModal'); }
async function doAddCustomer() {
  var name  = (document.getElementById('nc-name')||{}).value||'';
  var phone = (document.getElementById('nc-phone')||{}).value||'';
  var email = (document.getElementById('nc-email')||{}).value||'';
  var bday  = (document.getElementById('nc-bday')||{}).value||'';
  var pts   = parseInt((document.getElementById('nc-pts')||{}).value)||0;
  if (!name||!phone){showToast('⚠️ Naam aur phone required hai!');return;}
  if (!_custDb||!_captainAddDoc||!_captainCollection){showToast('⚠️ Firebase ready nahi');return;}
  try {
    await _captainAddDoc(_captainCollection(_custDb,'captainCustomers'),{
      name:name,phone:phone,email:email,birthday:bday,
      loyaltyPoints:pts,totalSpend:0,visits:0,avgRating:0,
      tier:'bronze',visitStreak:0,lastVisit:null,
      pointsEarnedAt:pts>0?Date.now():null,
      createdAt:Date.now()
    });
    closeModal('addCustModal');
    ['nc-name','nc-phone','nc-email','nc-bday','nc-pts'].forEach(function(id){var el=document.getElementById(id);if(el)el.value=id==='nc-pts'?'0':'';});
    showToast('✅ Customer add ho gaya! Firebase mein save.');
  } catch(e){showToast('⚠️ Error: '+e.message);}
}

// ── CUSTOMER DETAIL MODAL ────────────────────────────────────────────────
var _cdmFbId = null;
function openCustDetail(fbId) {
  _cdmFbId = fbId;
  var c = _custData.find(function(x){return x._fbId===fbId;});
  if (!c) return;
  var titleEl = document.getElementById('cdm-title');
  var bodyEl  = document.getElementById('cdm-body');
  if (titleEl) titleEl.textContent = '👤 ' + c.name + ' (' + (c.tier||'bronze').toUpperCase() + ')';
  if (bodyEl) bodyEl.innerHTML =
    '<div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:12px">'+
      '<div style="background:var(--G50);border-radius:10px;padding:12px;text-align:center"><div style="font-size:10px;color:var(--ink4);font-weight:700;text-transform:uppercase">Total Spend</div><div style="font-size:22px;font-weight:900;color:var(--G700);font-family:JetBrains Mono,monospace">₹'+(c.totalSpend||0).toLocaleString('en-IN')+'</div></div>'+
      '<div style="background:var(--amber-bg);border-radius:10px;padding:12px;text-align:center"><div style="font-size:10px;color:var(--ink4);font-weight:700;text-transform:uppercase">Loyalty Points</div><div style="font-size:22px;font-weight:900;color:var(--amber);font-family:JetBrains Mono,monospace">'+(c.loyaltyPoints||0)+'</div></div>'+
      '<div style="background:var(--blue-bg);border-radius:10px;padding:12px;text-align:center"><div style="font-size:10px;color:var(--ink4);font-weight:700;text-transform:uppercase">Visits</div><div style="font-size:22px;font-weight:900;color:var(--blue);font-family:JetBrains Mono,monospace">'+(c.visits||0)+'</div></div>'+
      '<div style="background:var(--violet-bg);border-radius:10px;padding:12px;text-align:center"><div style="font-size:10px;color:var(--ink4);font-weight:700;text-transform:uppercase">Streak</div><div style="font-size:22px;font-weight:900;color:var(--violet);font-family:JetBrains Mono,monospace">🔥'+(c.visitStreak||0)+'</div></div>'+
    '</div>'+
    '<div style="font-size:12px;color:var(--ink2);font-weight:600;line-height:1.9">'+
      '<div>📞 <b>Phone:</b> '+(c.phone||'—')+'</div>'+
      '<div>📧 <b>Email:</b> '+(c.email||'—')+'</div>'+
      '<div>🎂 <b>Birthday:</b> '+(c.birthday||'—')+'</div>'+
      '<div>🕒 <b>Last Visit:</b> '+(c.lastVisit?_timeAgoMs(c.lastVisit):'Never')+'</div>'+
    '</div>'+
    '<div style="margin-top:10px"><div style="font-size:11px;font-weight:700;color:var(--ink3);margin-bottom:4px">Points Add Karo:</div>'+
    '<div style="display:flex;gap:8px"><input id="cdm-pts-in" type="number" placeholder="Points" style="flex:1;padding:7px 12px;border:1.5px solid var(--line2);border-radius:8px;font-size:13px;font-family:Outfit,sans-serif;outline:none;font-weight:700"></div></div>';
  var promoteBtn = document.getElementById('cdm-promote-btn');
  if (promoteBtn) promoteBtn.style.display = (c.tier==='vip')?'none':'';
  openModal('custDetailModal');
}

