// ── REDEEM POINTS ────────────────────────────────────────────────────────
function openRedeemModal() { openModal('redeemModal'); }
function openRedeemForCustomer(fbId) {
  var c = _custData.find(function(x){return x._fbId===fbId;});
  if (!c) return;
  openModal('redeemModal');
  var ph = document.getElementById('rd-phone');
  if (ph){ph.value=c.phone; lookupRedeemCustomer();}
}
function lookupRedeemCustomer() {
  var ph = (document.getElementById('rd-phone')||{}).value||'';
  var c  = _custData.find(function(x){return (x.phone||'').includes(ph)&&ph.length>=5;});
  var info = document.getElementById('rd-custInfo');
  if (c && info) {
    info.style.display='block';
    _setText('rd-custName',c.name);
    _setText('rd-custPts',(c.loyaltyPoints||0)+' pts');
    _cdmFbId = c._fbId;
  } else if (info) { info.style.display='none'; }
}
async function doRedeemPoints() {
  var pts    = parseInt((document.getElementById('rd-amount')||{}).value)||0;
  var reason = (document.getElementById('rd-reason')||{}).value||'Redemption';
  if (!pts||pts<1||!_cdmFbId){showToast('⚠️ Valid info enter karo');return;}
  var c = _custData.find(function(x){return x._fbId===_cdmFbId;});
  if (!c){showToast('⚠️ Customer nahi mila');return;}
  if ((c.loyaltyPoints||0)<pts){showToast('⚠️ Itne points available nahi!');return;}
  try {
    var {doc,updateDoc} = await import("https://www.gstatic.com/firebasejs/10.12.2/firebase-firestore.js");
    await updateDoc(doc(_custDb,'captainCustomers',_cdmFbId),{
      loyaltyPoints:(c.loyaltyPoints||0)-pts,
      redeemedToday:(c.redeemedToday||0)+pts,
      lastRedeemedAt:Date.now()
    });
    addNotificationToFirebase('🎁 Points Redeemed',c.name+' ne '+pts+' points redeem kiye — '+reason,'info','🎁');
    showToast('🎁 '+pts+' points redeem ho gaye — '+c.name+'!');
    closeModal('redeemModal');
  } catch(e){showToast('⚠️ '+e.message);}
}

