// ── LOYALTY CONFIG ───────────────────────────────────────────────────────
async function _loadLoyaltyConfig() {
  try {
    var {doc,getDoc} = await import("https://www.gstatic.com/firebasejs/10.12.2/firebase-firestore.js");
    var snap = await getDoc(doc(_custDb,'captainSettings','loyaltyConfig'));
    if (snap.exists()) {
      var d = snap.data();
      _loyConfig = { perRupee: d.perRupee||10, ptsEarned: d.ptsEarned||1, expDays: d.expDays||90 };
      var el1=document.getElementById('loyPerRupee'), el2=document.getElementById('loyPtsEarned'), el3=document.getElementById('loyExpDays');
      if(el1) el1.value=_loyConfig.perRupee;
      if(el2) el2.value=_loyConfig.ptsEarned;
      if(el3) el3.value=_loyConfig.expDays;
    }
  } catch(e){ console.warn('LoyConfig load:',e); }
}
async function saveLoyaltyConfig() {
  _loyConfig.perRupee  = parseInt(document.getElementById('loyPerRupee')?.value)||10;
  _loyConfig.ptsEarned = parseInt(document.getElementById('loyPtsEarned')?.value)||1;
  _loyConfig.expDays   = parseInt(document.getElementById('loyExpDays')?.value)||90;
  try {
    var {doc,setDoc} = await import("https://www.gstatic.com/firebasejs/10.12.2/firebase-firestore.js");
    await setDoc(doc(_custDb,'captainSettings','loyaltyConfig'),_loyConfig);
    showToast('✅ Loyalty config save ho gayi!');
  } catch(e){showToast('⚠️ '+e.message);}
}

// ── AUTO POINTS ON ORDER ─────────────────────────────────────────────────
// Jab bhi order place ho, customer ke phone se match karo aur points add karo
// ── AUTO POINTS — placeOrder ke saath hook (sahi wali jagah) ──
async function _autoPointsFromOrder(custName, total) {
  try {
    if (!custName || custName==='Dine-In Customer' || !total || total<1) return;
    if (!_custDb || !_captainCollection) return;
    var earned = Math.floor((total / (_loyConfig.perRupee||10)) * (_loyConfig.ptsEarned||1));
    if (earned < 1) return;

    // Name se customer dhundo (case-insensitive, partial match bhi)
    var c = _custData.find(function(x){
      return (x.name||'').toLowerCase() === custName.toLowerCase() ||
             (x.name||'').toLowerCase().includes(custName.toLowerCase());
    });

    if (c) {
      // Existing customer — update karo
      var {doc,updateDoc} = await import("https://www.gstatic.com/firebasejs/10.12.2/firebase-firestore.js");
      await updateDoc(doc(_custDb,'captainCustomers',c._fbId),{
        loyaltyPoints:  (c.loyaltyPoints||0) + earned,
        totalSpend:     (c.totalSpend||0) + total,
        visits:         (c.visits||0) + 1,
        lastVisit:      Date.now(),
        pointsEarnedAt: Date.now(),
        visitStreak:    (c.visitStreak||0) + 1
      });
      showToast('🎁 '+earned+' points auto earn — '+c.name+'!');
      addNotificationToFirebase('🎁 Points Earned', c.name+' ne '+earned+' pts earn kiye (₹'+total+' order se)','success','🎁');
    } else {
      // Naya customer — automatically add karo Firebase mein
      var {addDoc,collection} = await import("https://www.gstatic.com/firebasejs/10.12.2/firebase-firestore.js");
      await addDoc(collection(_custDb,'captainCustomers'),{
        name:           custName,
        phone:          '',
        email:          '',
        birthday:       '',
        loyaltyPoints:  earned,
        totalSpend:     total,
        visits:         1,
        avgRating:      0,
        tier:           'bronze',
        visitStreak:    1,
        lastVisit:      Date.now(),
        pointsEarnedAt: Date.now(),
        createdAt:      Date.now(),
        autoAdded:      true   // flag: order se auto create hua
      });
      showToast('👤 Naya customer auto-add: '+custName+' ('+earned+' pts)!');
      addNotificationToFirebase('👤 New Customer Auto-Added', custName+' ka profile order se automatically create hua!','success','👤');
    }
  } catch(e){ console.warn('Auto points error:',e); }
}

// ── AI CUSTOMER INSIGHT ──────────────────────────────────────────────────
async function refreshCustAI() {
  var el = document.getElementById('custAiText');
  if (el) el.textContent = '🤖 AI analyze kar raha hai...';
  var summary = _custData.slice(0,8).map(function(c){
    return c.name+' ('+c.tier+', visits:'+c.visits+', spend:₹'+c.totalSpend+', pts:'+c.loyaltyPoints+')';
  }).join('; ');
  var prompt = 'Restaurant customer data (Hinglish mein jawab do, 2-3 lines): '+summary+'. Key insight aur 1 actionable suggestion do.';
  try {
    var txt = await captainCallGemini('Tu ek restaurant customer analytics expert hai. Hinglish mein jawab de, 2-3 lines mein.', prompt);
    if (el && txt) el.textContent = txt;
  } catch(e){ if(el) el.textContent='AI analysis temporarily unavailable.'; }
}
async function _runCustAI() { if (_custData.length>0 && !_custAiRan) { _custAiRan=true; refreshCustAI(); } }
var _custAiRan = false;

// ── AI LOYALTY INSIGHT ───────────────────────────────────────────────────
async function refreshLoyaltyAI() {
  var el = document.getElementById('loyAiText');
  if (el) el.textContent = '🤖 AI loyalty trend analyze kar raha hai...';
  var totalPts  = _custData.reduce(function(s,c){return s+(c.loyaltyPoints||0);},0);
  var avgPts    = _custData.length ? Math.round(totalPts/_custData.length) : 0;
  var expMs     = _loyConfig.expDays*86400000;
  var expCount  = _custData.filter(function(c){return c.pointsEarnedAt&&(Date.now()-c.pointsEarnedAt)>(expMs*0.75)&&(c.loyaltyPoints||0)>0;}).length;
  var topCustomer = _custData.reduce(function(m,c){return (c.loyaltyPoints||0)>(m.loyaltyPoints||0)?c:m;},{});
  var prompt = 'Loyalty program data (Hinglish mein, 2-3 lines): Total points='+totalPts+', Average='+avgPts+', Expiring soon='+expCount+' customers, Top customer='+topCustomer.name+' with '+topCustomer.loyaltyPoints+' pts. Loyalty improvement suggestion do.';
  try {
    var txt = await captainCallGemini('Tu ek restaurant loyalty program expert hai. Hinglish mein jawab de, 2-3 lines mein.', prompt);
    if (el && txt) el.textContent = txt;
  } catch(e){ if(el) el.textContent='AI analysis temporarily unavailable.'; }
}
async function _runLoyaltyAI() { if (_custData.length>0 && !_loyAiRan) { _loyAiRan=true; refreshLoyaltyAI(); } }
var _loyAiRan = false;

// ── HELPERS ──────────────────────────────────────────────────────────────
function _setText(id,val){ var el=document.getElementById(id); if(el) el.textContent=val; }
function _timeAgoMs(ts) {
  var diff=Math.floor((Date.now()-ts)/1000);
  if(diff<60) return diff+'s ago';
  if(diff<3600) return Math.floor(diff/60)+'m ago';
  if(diff<86400) return Math.floor(diff/3600)+'h ago';
  return Math.floor(diff/86400)+'d ago';
}

// console.log('✅ Customers & VIP + Loyalty Points — Full Firebase + AI System Ready!');

// ─────────────────────────────────

(function bootAnalyticsFirebase() {
  'use strict';

  // ── State ──────────────────────────────────────────────────────
  var _anFirebaseReady = false;
  var _anAllOrders = [];          // orders + orderHistory combined
  var _anCurrentTabLocal = 'today';

  // ── Helper: ek element ka text set karo ────────────────────────
  function _anSet(id, val) {
    var el = document.getElementById(id);
    if (el) el.textContent = val;
  }

  // ── Format number to Indian currency ───────────────────────────
  function _anFmt(n) {
    if (n >= 100000) return '₹' + (n / 100000).toFixed(1) + 'L';
    if (n >= 1000)   return '₹' + n.toLocaleString('en-IN');
    return '₹' + n;
  }

  // ── Calculate KPI from orders array ────────────────────────────
  function _anCalc(orders) {
    if (!orders.length) return { rev: '₹0', revChg: 'No orders yet', ord: '0', ordChg: '', avg: '₹0', avgChg: '', can: '0%', canChg: '' };

    var totalRev = 0, totalOrd = orders.length, cancelled = 0;
    orders.forEach(function(o) {
      totalRev += (o.totalAmount || o.total || o.grandTotal || 0);
      if ((o.status || '').toLowerCase() === 'cancelled') cancelled++;
    });

    var avg = totalOrd > 0 ? Math.round(totalRev / totalOrd) : 0;
    var canRate = totalOrd > 0 ? ((cancelled / totalOrd) * 100).toFixed(1) : '0.0';

    return {
      rev:     _anFmt(totalRev),
      revChg:  totalOrd + ' orders se calculated',
      ord:     totalOrd.toLocaleString('en-IN'),
      ordChg:  cancelled > 0 ? cancelled + ' cancelled hain' : 'All clear ✅',
      avg:     '₹' + avg.toLocaleString('en-IN'),
      avgChg:  'Per order average',
      can:     canRate + '%',
      canChg:  cancelled + ' orders cancelled'
    };
  }

  // ── Render KPI cards with data ─────────────────────────────────
  function _anRenderKPI(d) {
    _anSet('anRevVal',    d.rev);
    _anSet('anRevChange', d.revChg);
    _anSet('anOrdVal',    d.ord);
    _anSet('anOrdChange', d.ordChg);
    _anSet('anAvgVal',    d.avg);
    _anSet('anAvgChange', d.avgChg);
    _anSet('anCanVal',    d.can);
    _anSet('anCanChange', d.canChg);
  }

  // ── Update Revenue vs Target section ───────────────────────────
  function _anUpdateTargets(todayRev, weekRev, monthRev) {
    try {
      var dailyTarget  = 60000;
      var weeklyTarget = 400000;
      var monthTarget  = 1500000;

      var dailyPct  = Math.min(100, Math.round((todayRev  / dailyTarget)  * 100));
      var weeklyPct = Math.min(100, Math.round((weekRev   / weeklyTarget) * 100));
      var monthPct  = Math.min(100, Math.round((monthRev  / monthTarget)  * 100));

      var wrap = document.querySelector('#page-analytics .table-wrap');
      if (!wrap) return;
      var allBars  = wrap.querySelectorAll('.target-bar-fill');
      var allTexts = wrap.querySelectorAll('.target-bar-bg + div');
      var allSpans = wrap.querySelectorAll('[style*="JetBrains Mono"]');

      // Bar widths
      if (allBars[0]) allBars[0].style.width = dailyPct  + '%';
      if (allBars[1]) allBars[1].style.width = weeklyPct + '%';
      if (allBars[2]) allBars[2].style.width = monthPct  + '%';

      // Revenue text spans (Daily / Weekly / Monthly)
      if (allSpans[0]) allSpans[0].textContent = _anFmt(todayRev) + ' / ₹60,000';
      if (allSpans[1]) allSpans[1].textContent = _anFmt(weekRev)  + ' / ₹4,00,000';
      if (allSpans[2]) allSpans[2].textContent = _anFmt(monthRev) + ' / ₹15,00,000';

      // Sub-text
      var remaining = Math.max(0, dailyTarget - todayRev);
      if (allTexts[0]) allTexts[0].textContent = dailyPct  + '% achieved — ₹' + remaining.toLocaleString('en-IN') + ' remaining';
      if (allTexts[1]) allTexts[1].textContent = weeklyPct + '% achieved';
      if (allTexts[2]) allTexts[2].textContent = monthPct  + '% achieved';
    } catch(e) { console.warn('Analytics target update error:', e); }
  }

  // ── Filter orders by time range ─────────────────────────────────
  function _anFilterByRange(orders, from, to) {
    var fromTs = from ? new Date(from).getTime() : 0;
    var toTs   = to   ? (new Date(to).getTime() + 86399999) : Date.now(); // include full end day
    return orders.filter(function(o) {
      var ts = o.createdAt || o.savedAt || o.timestamp || 0;
      return ts >= fromTs && ts <= toTs;
    });
  }

  // ── Main render function called on tab switch ───────────────────
  function _anRenderTab(tab) {
    if (!_anFirebaseReady || !_anAllOrders.length) return;

    var now    = Date.now();
    var todayStart = new Date(); todayStart.setHours(0,0,0,0);
    var todayTs    = todayStart.getTime();
    var weekTs     = now - 7  * 24 * 60 * 60 * 1000;
    var monthTs    = now - 30 * 24 * 60 * 60 * 1000;

    var filtered;
    if (tab === 'today') {
      filtered = _anAllOrders.filter(function(o) {
        return (o.createdAt || o.savedAt || o.timestamp || 0) >= todayTs;
      });
    } else if (tab === 'week') {
      filtered = _anAllOrders.filter(function(o) {
        return (o.createdAt || o.savedAt || o.timestamp || 0) >= weekTs;
      });
    } else if (tab === 'month') {
      filtered = _anAllOrders.filter(function(o) {
        return (o.createdAt || o.savedAt || o.timestamp || 0) >= monthTs;
      });
    } else {
      // custom — don't update KPIs yet, wait for Apply
      return;
    }

    _anRenderKPI(_anCalc(filtered));

    // Always update target bars with real today/week/month totals
    var todayRev = _anAllOrders.filter(function(o){ return (o.createdAt||o.savedAt||o.timestamp||0) >= todayTs; })
                               .reduce(function(s,o){ return s+(o.totalAmount||o.total||o.grandTotal||0); }, 0);
    var weekRev  = _anAllOrders.filter(function(o){ return (o.createdAt||o.savedAt||o.timestamp||0) >= weekTs; })
                               .reduce(function(s,o){ return s+(o.totalAmount||o.total||o.grandTotal||0); }, 0);
    var monthRev = _anAllOrders.filter(function(o){ return (o.createdAt||o.savedAt||o.timestamp||0) >= monthTs; })
                               .reduce(function(s,o){ return s+(o.totalAmount||o.total||o.grandTotal||0); }, 0);
    _anUpdateTargets(todayRev, weekRev, monthRev);
  }

  // ── Override switchAnTab to also call Firebase render ──────────
  var _origSwitchAnTab = window.switchAnTab;
  window.switchAnTab = function(tab, btn) {
    _anCurrentTabLocal = tab;
    // Call original (handles UI tabs + custom range show/hide)
    if (typeof _origSwitchAnTab === 'function') _origSwitchAnTab(tab, btn);
    // Firebase data update
    _anRenderTab(tab);
  };

  // ── Override applyCustomAnRange for date range ──────────────────
  var _origApplyCustom = window.applyCustomAnRange;
  window.applyCustomAnRange = function() {
    var from = (document.getElementById('anFromDate') || {}).value;
    var to   = (document.getElementById('anToDate')   || {}).value;
    if (!from || !to) { if (typeof showToast === 'function') showToast('⚠️ Date range select karo pehle!'); return; }
    if (!_anFirebaseReady) { if (typeof showToast === 'function') showToast('⏳ Firebase load ho raha hai...'); return; }
    var filtered = _anFilterByRange(_anAllOrders, from, to);
    _anRenderKPI(_anCalc(filtered));
    if (typeof showToast === 'function') showToast('📊 ' + from + ' se ' + to + ' ka data loaded!');
  };

  // ── Override refreshAnAI to use real data ───────────────────────
  window.refreshAnAI = async function() {
    var el = document.getElementById('anAiText');
    if (el) el.textContent = '🤖 AI revenue prediction generate kar raha hai...';

    // Real data se prompt banao
    var now = Date.now();
    var todayTs = new Date().setHours(0,0,0,0);
    var weekTs  = now - 7 * 24 * 60 * 60 * 1000;
    var todayOrders = _anAllOrders.filter(function(o){ return (o.createdAt||o.savedAt||o.timestamp||0) >= todayTs; });
    var weekOrders  = _anAllOrders.filter(function(o){ return (o.createdAt||o.savedAt||o.timestamp||0) >= weekTs; });
    var weekRev  = weekOrders.reduce(function(s,o){ return s+(o.totalAmount||o.total||o.grandTotal||0); }, 0);
    var todayRev = todayOrders.reduce(function(s,o){ return s+(o.totalAmount||o.total||o.grandTotal||0); }, 0);
    var weekAvg  = weekOrders.length ? Math.round(weekRev / weekOrders.length) : 0;
    var cancelled = weekOrders.filter(function(o){ return (o.status||'').toLowerCase()==='cancelled'; }).length;
    var canRate  = weekOrders.length ? ((cancelled / weekOrders.length)*100).toFixed(1) : 0;

    // Customer repeat data from _custData if available
    var repeatPct = (typeof _custData !== 'undefined' && _custData.length > 0)
      ? Math.round((_custData.filter(function(c){ return (c.visits||0) > 1; }).length / _custData.length) * 100)
      : 68;

    var prompt = 'Restaurant analytics (Hinglish mein jawab do, 2-3 lines): Weekly revenue ₹' + weekRev.toLocaleString('en-IN') +
      ', Aaj ka revenue ₹' + todayRev.toLocaleString('en-IN') +
      ', Weekly orders ' + weekOrders.length +
      ', Avg order ₹' + weekAvg +
      ', Cancellation rate ' + canRate + '%' +
      ', Repeat customers ' + repeatPct + '%. Next week ka revenue prediction do aur ek actionable tip bhi do.';

    try {
      var txt = await captainCallGemini('Tu ek restaurant analytics expert hai. Hinglish mein jawab de, 2-3 lines mein.', prompt);
      if (el && txt) el.textContent = txt;

      // Predicted revenue estimate (simple: weekRev * 1.05 to 1.15)
      var predRev = Math.round(weekRev * 1.10);
      var predEl = document.getElementById('anAiRevPred');
      if (predEl && predRev > 0) predEl.textContent = _anFmt(predRev);
    } catch(e) {
      if (el) el.textContent = 'AI prediction temporarily unavailable. Real data se manually calculate karo.';
    }
  };

  // ── Boot: wait for Firebase then load orders ────────────────────
  function _tryBoot() {
    if (!_captainDb || !_captainCollection || !_captainOnSnapshot) {
      setTimeout(_tryBoot, 1500);
      return;
    }

    // orders + orderHistory dono sun — Analytics mein dono chahiye
    var _ordersLoaded = false, _historyLoaded = false;
    var _anLiveOrders = [], _anHistoryOrders = [];

    function _merge() {
      // Combine, deduplicate by _fbId
      var seen = {};
      _anAllOrders = [];
      _anLiveOrders.concat(_anHistoryOrders).forEach(function(o) {
        var key = o._fbId || (o.tableNumber + '_' + (o.createdAt||o.savedAt||0));
        if (!seen[key]) { seen[key] = true; _anAllOrders.push(o); }
      });
      _anFirebaseReady = true;
      _anRenderTab(_anCurrentTabLocal);
      // console.log('📊 Analytics: ' + _anAllOrders.length + ' orders loaded from Firebase');
    }

    // Live orders listener
    _captainOnSnapshot(_captainCollection(_captainDb, 'orders'), function(snap) {
      _anLiveOrders = [];
      snap.forEach(function(d) { _anLiveOrders.push(Object.assign({ _fbId: d.id }, d.data())); });
      _ordersLoaded = true;
      if (_historyLoaded) _merge(); else _anAllOrders = _anLiveOrders, _anFirebaseReady = true, _anRenderTab(_anCurrentTabLocal);
    });

    // Order history listener
    _captainOnSnapshot(_captainCollection(_captainDb, 'orderHistory'), function(snap) {
      _anHistoryOrders = [];
      snap.forEach(function(d) { _anHistoryOrders.push(Object.assign({ _fbId: d.id }, d.data())); });
      _historyLoaded = true;
      if (_ordersLoaded) _merge();
    });

    // Also re-render when Analytics tab is opened
    var origShowPage = window.showPage;
    window.showPage = function(page, el) {
      if (typeof origShowPage === 'function') origShowPage(page, el);
      if (page === 'analytics' && _anFirebaseReady) {
        setTimeout(function(){ _anRenderTab(_anCurrentTabLocal); }, 100);
      }
    };
  }

  // Start after short delay to let Firebase init complete
  setTimeout(_tryBoot, 3000);
  // console.log('📊 Analytics Firebase integration booted!');
})();

