// ── MOBILE SIDEBAR TOGGLE ──
function toggleMobileSidebar() {
  const sidebar = document.querySelector('.sidebar');
  const overlay = document.getElementById('sidebarOverlay');
  const isOpen = sidebar.classList.contains('open');
  if (isOpen) {
    sidebar.classList.remove('open');
    overlay.classList.remove('show');
  } else {
    sidebar.classList.add('open');
    overlay.classList.add('show');
  }
}
function closeMobileSidebar() {
  document.querySelector('.sidebar').classList.remove('open');
  document.getElementById('sidebarOverlay').classList.remove('show');
}

// ── MOBILE BOTTOM NAV ──
function showPageMob(id, el) {
  showPage(id, null);
  document.querySelectorAll('.mob-nav-item').forEach(n => n.classList.remove('active'));
  if (el) el.classList.add('active');
  closeMobileSidebar();
  // Update mob-order-tabs visibility
  const tabs = document.getElementById('mobOrderTabs');
  if (tabs) tabs.style.display = (id === 'orderplace') ? 'flex' : 'none';
}

// Close sidebar when nav item clicked on mobile
document.querySelectorAll('.nav-item').forEach(item => {
  const orig = item.getAttribute('onclick');
  if (orig && orig.includes('showPage')) {
    item.addEventListener('click', function() {
      setTimeout(closeMobileSidebar, 150);
    });
  }
});

// ── MOBILE ORDER PANEL TOGGLE ──
function mobShowPanel(panel) {
  const menuPanel = document.getElementById('orderMenuPanel')?.closest('div[style*="flex:1"]') 
    || document.querySelector('#page-orderplace > div > div:first-child');
  const cartPanel = document.getElementById('orderCartPanel');
  const menuTab = document.getElementById('mobTabMenu');
  const cartTab = document.getElementById('mobTabCart');
  
  if (window.innerWidth > 768) return; // Desktop pe toggle nahi
  
  if (panel === 'menu') {
    if (menuPanel) menuPanel.style.display = 'flex';
    if (cartPanel) cartPanel.style.display = 'none';
    if (menuTab) menuTab.classList.add('active');
    if (cartTab) cartTab.classList.remove('active');
  } else {
    if (menuPanel) menuPanel.style.display = 'none';
    if (cartPanel) { cartPanel.style.display = 'flex'; cartPanel.style.width = '100%'; }
    if (menuTab) menuTab.classList.remove('active');
    if (cartTab) cartTab.classList.add('active');
  }
}

// ── UPDATE MOB CART BADGE ──
const _origRenderCart = window.renderCart;
if (typeof renderCart === 'function') {
  const _rc = renderCart;
  window.renderCart = function() {
    _rc();
    const badge = document.getElementById('mobCartBadge');
    if (badge && window.cart) {
      const count = window.cart.reduce((a,i) => a + i.qty, 0);
      badge.textContent = count > 0 ? ` (${count})` : '';
    }
  };
}

// ── SHOW MOB TABS ON ORDER PAGE ──
const _origShowPageMob = window.showPage;
const _origSP = window.showPage;
window.showPage = function(id, el) {
  _origSP(id, el);
  const tabs = document.getElementById('mobOrderTabs');
  if (tabs) {
    tabs.style.display = (id === 'orderplace' && window.innerWidth <= 768) ? 'flex' : 'none';
  }
  // Reset panels on page change
  if (id !== 'orderplace') {
    const mp = document.querySelector('#page-orderplace > div > div:first-child');
    const cp = document.getElementById('orderCartPanel');
    if (mp) mp.style.display = '';
    if (cp) cp.style.display = '';
  }
};

// ── INIT: show mob tabs if on orderplace ──
if (document.querySelector('.page.active[id="page-orderplace"]') && window.innerWidth <= 768) {
  const tabs = document.getElementById('mobOrderTabs');
  if (tabs) tabs.style.display = 'flex';
}

