// ─────────────────────────────────

(function() {
  'use strict';

  // ── Track placed orders locally ──
  var _mobPlacedOrders = [];

  // ── Show/hide floating buttons when on orderplace page ──
  function mobSyncFloatingBtns(pageId) {
    var btns = document.getElementById('mobFloatingBtns');
    if (!btns) return;
    var isMob = window.innerWidth <= 768;
    if (pageId === 'orderplace' && isMob) {
      btns.style.display = 'flex';
      // Reset to menu view
      mobShowPanel('menu');
    } else {
      btns.style.display = 'none';
    }
  }

  // ── Hook showPage to control floating buttons ──
  var _sp2 = window.showPage;
  window.showPage = function(id, el) {
    if (_sp2) _sp2(id, el);
    mobSyncFloatingBtns(id);
  };

  // ── On load: check if already on orderplace ──
  window.addEventListener('load', function() {
    var active = document.querySelector('.page.active');
    if (active && active.id === 'page-orderplace') {
      mobSyncFloatingBtns('orderplace');
    }
  });

  // ── Highlight active floating button ──
  window.mobHighlightBtn = function(panel) {
    var menuBtn = document.getElementById('mobFloatMenuBtn');
    var cartBtn = document.getElementById('mobFloatCartBtn');
    if (!menuBtn || !cartBtn) return;
    if (panel === 'menu') {
      menuBtn.style.background = 'linear-gradient(135deg,#1d4ed8,#1e40af)';
      menuBtn.style.boxShadow = '0 6px 22px rgba(29,78,216,.55)';
      cartBtn.style.background = 'linear-gradient(135deg,#059669,#047857)';
      cartBtn.style.boxShadow = '0 4px 18px rgba(5,150,105,.35)';
    } else {
      cartBtn.style.background = 'linear-gradient(135deg,#059669,#047857)';
      cartBtn.style.boxShadow = '0 6px 22px rgba(5,150,105,.55)';
      menuBtn.style.background = 'linear-gradient(135deg,#1d4ed8,#1e40af)';
      menuBtn.style.boxShadow = '0 4px 18px rgba(29,78,216,.3)';
    }
  };

  // ── Update cart badge on floating cart button ──
  function mobUpdateFloatCartBadge() {
    var badge = document.getElementById('mobFloatCartBadge');
    if (!badge) return;
    var count = 0;
    if (window.cart && Array.isArray(window.cart)) {
      count = window.cart.reduce(function(a, i) { return a + (i.qty || 1); }, 0);
    }
    badge.textContent = count;
    badge.style.display = count > 0 ? 'flex' : 'none';
  }

  // ── Hook addToCart to update badge ──
  var _origATC = window.addToCart;
  window.addToCart = function(name, fullPrice, halfPrice, id) {
    if (_origATC) _origATC(name, fullPrice, halfPrice, id);
    setTimeout(mobUpdateFloatCartBadge, 50);
  };

  // ── Hook renderCart to update badge ──
  var _origRC2 = window.renderCart;
  window.renderCart = function() {
    if (_origRC2) _origRC2();
    setTimeout(mobUpdateFloatCartBadge, 50);
  };

  // ══════════════════════════════════════════
  // PLACED ORDERS PANEL
  // ══════════════════════════════════════════

  // ── Format time ──
  function _fmtTime(ts) {
    var d = ts ? new Date(ts) : new Date();
    return d.toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit', hour12: true });
  }

  // ── Add to placed orders list ──
  function _addToMobPlacedOrders(orderData) {
    _mobPlacedOrders.unshift(orderData);
    if (_mobPlacedOrders.length > 50) _mobPlacedOrders.pop();
    _renderMobPlacedOrders();
    // Also save to localStorage
    try {
      var stored = JSON.parse(localStorage.getItem('mob_placed_orders') || '[]');
      stored.unshift(orderData);
      if (stored.length > 50) stored.pop();
      localStorage.setItem('mob_placed_orders', JSON.stringify(stored));
    } catch(e) {}
  }

  // ── Load from localStorage on init ──
  function _loadMobPlacedOrders() {
    try {
      var stored = JSON.parse(localStorage.getItem('mob_placed_orders') || '[]');
      _mobPlacedOrders = stored;
      _renderMobPlacedOrders();
    } catch(e) {}
  }

  // ── Render placed orders ──
  function _renderMobPlacedOrders() {
    var list = document.getElementById('mobPlacedOrdersList');
    if (!list) return;

    if (!_mobPlacedOrders || _mobPlacedOrders.length === 0) {
      list.innerHTML = '<div style="text-align:center;padding:32px 16px;color:#9ca3af"><div style="font-size:36px;margin-bottom:8px">🛒</div><div style="font-size:13px;font-weight:700">Koi order nahi abhi</div><div style="font-size:11px;margin-top:4px">Order place karo — yahan dikhega</div></div>';
      return;
    }

    var statusColors = { new: '#1d4ed8', cooking: '#d97706', ready: '#059669', served: '#7c3aed', cancelled: '#dc2626' };
    var statusLabels = { new: '🆕 New', cooking: '🍳 Cooking', ready: '✅ Ready', served: '👨‍🍽️ Served', cancelled: '❌ Cancelled' };

    list.innerHTML = _mobPlacedOrders.map(function(o, idx) {
      var status = o.status || 'new';
      var sc = statusColors[status] || '#6b7280';
      var sl = statusLabels[status] || status;
      var items = (o.items || []).map(function(i) { return (i.name || i) + (i.qty > 1 ? ' ×' + i.qty : ''); }).join(', ');
      return '<div style="background:#f9fafb;border:1.5px solid #e5e7eb;border-radius:14px;padding:13px 14px;margin-bottom:10px">' +
        '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:8px">' +
          '<div>' +
            '<div style="font-size:13px;font-weight:900;color:#0f172a">' + (o.orderId || ('#100' + (idx + 1))) + '</div>' +
            '<div style="font-size:11px;color:#6b7280;margin-top:1px">📍 ' + (o.table || 'Table —') + '  •  ⏰ ' + _fmtTime(o.timestamp) + '</div>' +
          '</div>' +
          '<span style="font-size:10px;font-weight:800;padding:4px 10px;border-radius:20px;background:' + sc + '15;color:' + sc + ';border:1px solid ' + sc + '30">' + sl + '</span>' +
        '</div>' +
        '<div style="font-size:11.5px;color:#374151;font-weight:600;margin-bottom:6px;line-height:1.5">' + (items || 'Items not recorded') + '</div>' +
        '<div style="display:flex;align-items:center;justify-content:space-between">' +
          '<span style="font-size:13px;font-weight:900;color:#059669;font-family:\'JetBrains Mono\',monospace">₹' + (o.total || 0) + '</span>' +
          (o.customerName ? '<span style="font-size:10px;color:#9ca3af">👤 ' + o.customerName + '</span>' : '') +
        '</div>' +
      '</div>';
    }).join('');
  }

  // ── Open placed orders panel ──
  window.openMobOrdersPanel = function() {
    var panel = document.getElementById('mobPlacedOrdersPanel');
    var overlay = document.getElementById('mobOrdersPanelOverlay');
    _renderMobPlacedOrders();
    if (panel) {
      panel.style.display = 'block';
      panel.style.transform = 'translateY(100%)';
      setTimeout(function() { panel.style.transform = 'translateY(0)'; }, 10);
    }
    if (overlay) overlay.style.display = 'block';
  };

  // ── Close placed orders panel ──
  window.closeMobOrdersPanel = function() {
    var panel = document.getElementById('mobPlacedOrdersPanel');
    var overlay = document.getElementById('mobOrdersPanelOverlay');
    if (panel) {
      panel.style.transform = 'translateY(100%)';
      setTimeout(function() { panel.style.display = 'none'; }, 350);
    }
    if (overlay) overlay.style.display = 'none';
  };

  // ── Hook placeOrder to capture placed orders ──
  var _origPO = window.placeOrder;
  window.placeOrder = function() {
    // Capture cart before it clears
    var cartItems = [];
    if (window.cart && Array.isArray(window.cart)) {
      cartItems = window.cart.map(function(i) { return { name: i.name, qty: i.qty, price: i.price || i.halfPrice || 0 }; });
    }
    var tableEl = document.getElementById('cartTableSelect');
    var tableManual = document.getElementById('cartTableManual');
    var custEl = document.getElementById('cartCustomerName');
    var grandTotalEl = document.getElementById('grandTotal');

    var tableVal = (tableEl && tableEl.value) || (tableManual && tableManual.value) || '';
    var custName = (custEl && custEl.value) || '';
    var total = grandTotalEl ? (grandTotalEl.textContent || '₹0').replace('₹','') : '0';

    // Call original
    if (_origPO) _origPO();

    // Generate order id
    var orderId = '#' + Math.floor(1000 + Math.random() * 9000);
    _addToMobPlacedOrders({
      orderId: orderId,
      items: cartItems,
      table: tableVal || 'Table —',
      customerName: custName,
      total: total,
      status: 'new',
      timestamp: Date.now()
    });

    // If on mobile, show orders panel briefly to confirm
    if (window.innerWidth <= 768) {
      setTimeout(function() {
        openMobOrdersPanel();
      }, 800);
    }
  };

  // ── Update order status (can be called from Firebase hooks) ──
  window.mobUpdateOrderStatus = function(orderId, status) {
    _mobPlacedOrders.forEach(function(o) {
      if (o.orderId === orderId) o.status = status;
    });
    _renderMobPlacedOrders();
  };

  // ── Cart panel: add "View Placed Orders" button ──
  function _injectOrdersLinkInCart() {
    var cartPanel = document.getElementById('orderCartPanel');
    if (!cartPanel || document.getElementById('mobViewOrdersBtn')) return;

    var btn = document.createElement('div');
    btn.id = 'mobViewOrdersBtn';
    btn.style.cssText = 'display:none;margin:0 0 10px;';
    btn.innerHTML = '<button onclick="openMobOrdersPanel()" style="width:100%;padding:9px;background:linear-gradient(135deg,#eff6ff,#dbeafe);border:1.5px solid rgba(29,78,216,.25);border-radius:10px;font-size:12.5px;font-weight:800;color:#1d4ed8;cursor:pointer;font-family:\'Outfit\',sans-serif;display:flex;align-items:center;justify-content:center;gap:7px;-webkit-tap-highlight-color:transparent">' +
      '<span style="font-size:15px">📋</span> Placed Orders Dekho' +
      '<span id="mobOrderCountChip" style="background:#1d4ed8;color:#fff;border-radius:12px;padding:1px 8px;font-size:10px;font-weight:900;margin-left:2px">0</span>' +
      '</button>';

    // Insert before the scrollable cart body
    var cartScrollable = cartPanel.querySelector('[style*="overflow-y"]');
    if (cartScrollable) {
      cartPanel.insertBefore(btn, cartScrollable);
    } else {
      cartPanel.appendChild(btn);
    }
  }

  // ── Show/hide the orders link based on mobile ──
  function _syncOrdersBtnVisibility() {
    var btn = document.getElementById('mobViewOrdersBtn');
    if (!btn) return;
    btn.style.display = window.innerWidth <= 768 ? 'block' : 'none';
    var chip = document.getElementById('mobOrderCountChip');
    if (chip) chip.textContent = _mobPlacedOrders.length;
  }

  window.addEventListener('resize', _syncOrdersBtnVisibility);

  // ── INIT ──
  window.addEventListener('load', function() {
    _loadMobPlacedOrders();
    setTimeout(function() {
      _injectOrdersLinkInCart();
      _syncOrdersBtnVisibility();
      mobUpdateFloatCartBadge();
    }, 600);
  });

  // console.log('📱 Floating Buttons + Placed Orders Panel loaded!');

})();

