        '<div class="stat-card orange" style="padding:14px 12px">',
          '<div class="stat-icon" style="font-size:18px;margin-bottom:6px">☕</div>',
          '<div class="stat-label">On Leave</div>',
          '<div class="stat-value orange" id="bwStatLeave" style="font-size:22px">0</div>',
        '</div>',
        '<div class="stat-card blue" style="padding:14px 12px">',
          '<div class="stat-icon" style="font-size:18px;margin-bottom:6px">👥</div>',
          '<div class="stat-label">Total</div>',
          '<div class="stat-value blue" id="bwStatTotal" style="font-size:22px">0</div>',
        '</div>',
      '</div>',

      // Filter tabs
      '<div style="display:flex;gap:8px;margin-bottom:14px;flex-wrap:wrap">',
        '<button id="bwFilter-all"    class="btn btn-green"   style="font-size:11px" onclick="filterBillingWaiters(\'all\')">All</button>',
        '<button id="bwFilter-active" class="btn btn-outline" style="font-size:11px;color:var(--G700)" onclick="filterBillingWaiters(\'active\')">✅ Active</button>',
        '<button id="bwFilter-absent" class="btn btn-outline" style="font-size:11px;color:var(--red)"  onclick="filterBillingWaiters(\'absent\')">❌ Absent</button>',
        '<button id="bwFilter-leave"  class="btn btn-outline" style="font-size:11px;color:var(--orange)" onclick="filterBillingWaiters(\'leave\')">☕ On Leave</button>',
        '<input id="bwSearch" class="form-input" placeholder="🔍 Waiter search karo..." style="flex:1;min-width:180px;max-width:260px;font-size:12px" oninput="filterBillingWaiters(\'search\',this.value)">',
      '</div>',

      // Grid
      '<div id="billingWaiterGrid" class="waiter-grid">',
        '<div style="text-align:center;padding:32px;color:var(--ink4);background:var(--white);border:1px solid var(--line);border-radius:var(--r16);grid-column:1/-1">',
          '<div style="font-size:36px;margin-bottom:8px">⏳</div>',
