/* ══════════════════════════════════════════════
   SWIPE TO CLOSE SIDEBAR
══════════════════════════════════════════════ */
(function(){
  if(window.innerWidth > 768) return;
  var startX = 0, isDrag = false;
  document.addEventListener('touchstart', function(e){
    startX = e.touches[0].clientX;
    isDrag = false;
  }, {passive:true});
  document.addEventListener('touchmove', function(e){
    var diff = startX - e.touches[0].clientX;
    if(diff > 30) isDrag = true;
  }, {passive:true});
  document.addEventListener('touchend', function(){
    if(isDrag){
      var sb = document.querySelector('.sidebar');
      if(sb && sb.classList.contains('open')){
        if(typeof closeMobileSidebar === 'function') closeMobileSidebar();
      }
    }
  }, {passive:true});
})();

/* ══════════════════════════════════════════════
   PULL-TO-REFRESH HINT (visual only)
══════════════════════════════════════════════ */
(function(){
  if(window.innerWidth > 768) return;
  // Add active state visual feedback on all buttons
  document.querySelectorAll('button, .btn, .mob-nav-item').forEach(function(el){
    el.addEventListener('touchstart', function(){
      el.style.opacity = '0.75';
    }, {passive:true});
    el.addEventListener('touchend', function(){
      setTimeout(function(){ el.style.opacity = ''; }, 180);
    }, {passive:true});
  });
})();

