/* ════════════════════════════════════════════
   MOBILE TOUCH MASTER FIX v3.0
   Dynamically created elements bhi fix hote hain
════════════════════════════════════════════ */
(function(){
  if(window.innerWidth > 768) return;

  // Fix content scroll — ensure touch works
  function fixContentScroll(){
    var content = document.querySelector('.content');
    if(content){
      content.style.overflowY = 'scroll'; // 'scroll' is more reliable than 'auto' on iOS
      content.style.webkitOverflowScrolling = 'touch';
      content.style.touchAction = 'pan-y pinch-zoom';
      content.style.willChange = 'scroll-position';
    }
    // Fix all pages
    document.querySelectorAll('.page').forEach(function(p){
      p.style.touchAction = 'pan-y';
    });
  }

  // Fix all buttons/clickable elements including dynamic ones
  function fixTouchOnElements(){
    var sel = 'button, [onclick], .btn, .stat-card, .dish-card, .order-card, .nav-item, .mob-nav-item, .card, [role="button"], .kitchen-card, .menu-item, .customer-card, .table-card, .loyalty-card, .delivery-card';
    document.querySelectorAll(sel).forEach(function(el){
      if(!el._touchFixed){
        el._touchFixed = true;
        el.style.touchAction = 'manipulation';
        el.style.webkitTapHighlightColor = 'rgba(0,0,0,0.04)';
        el.style.cursor = 'pointer';
      }
    });
  }

  // Run on load
  window.addEventListener('load', function(){
    fixContentScroll();
    fixTouchOnElements();
  });

  // Run on page change — showPage hook
  var _origShow = window.showPage;
  window.showPage = function(id, el){
    _origShow && _origShow(id, el);
    setTimeout(function(){
      fixContentScroll();
      fixTouchOnElements();
    }, 100);
  };

  // MutationObserver — dynamically added elements bhi fix honge
  var observer = new MutationObserver(function(mutations){
    var needsFix = mutations.some(function(m){ return m.addedNodes.length > 0; });
    if(needsFix) setTimeout(fixTouchOnElements, 50);
  });
  observer.observe(document.body, { childList: true, subtree: true });

  console.log('📱 Mobile Touch Master Fix v3.0 loaded!');
})();

