// CAPTAIN RICH POP NOTIFICATION SYSTEM v2.0
var _captainNotifHistory=[];var _captainNotifUnread=0;var _captainTrayOpen=false;
var CAPTAIN_NOTIF_TYPES={
  order:{type:'type-order',icon:'🛒',tag:'Naya Order',dur:6000},
  cooking:{type:'type-cooking',icon:'🍳',tag:'Kitchen Update',dur:5000},
  ready:{type:'type-ready',icon:'✅',tag:'Order Ready',dur:8000},
  waiter:{type:'type-waiter',icon:'🧑‍🍽',tag:'Waiter Assigned',dur:5000},
  payment:{type:'type-payment',icon:'💰',tag:'Payment Done',dur:5000},
  urgent:{type:'type-urgent',icon:'🚨',tag:'Urgent Alert',dur:8000},
  info:{type:'type-info',icon:'ℹ️',tag:'Information',dur:5000},
  note:{type:'type-note',icon:'📝',tag:'Chef Note',dur:6000},
  system:{type:'type-system',icon:'⚙️',tag:'System',dur:4000}
};
function _capEsc(s){return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');}
window.showRichPop=function(title,msg,category,customIcon){
  category=category||'info';
  var cfg=CAPTAIN_NOTIF_TYPES[category]||CAPTAIN_NOTIF_TYPES.info;
  var icon=customIcon||cfg.icon;
  var dur=cfg.dur;
  var container=document.getElementById('captainRichPopContainer');
  if(!container)return;
  var existing=container.querySelectorAll('.cap-rich-pop');
  if(existing.length>=4){_captainDismissPop(existing[0].id);}
  var id='crpop-'+Date.now();
  var time=new Date().toLocaleTimeString('en-IN',{hour:'2-digit',minute:'2-digit'});
  var pop=document.createElement('div');
  pop.className='cap-rich-pop '+cfg.type;
  pop.id=id;
  pop.innerHTML='<div class="cap-rich-pop-inner"><div class="cap-rich-pop-icon">'+icon+'</div><div class="cap-rich-pop-body"><div class="cap-rich-pop-tag">'+cfg.tag+'</div><div class="cap-rich-pop-title">'+_capEsc(title)+'</div><div class="cap-rich-pop-msg">'+_capEsc(msg)+'</div><div class="cap-rich-pop-time">'+time+'</div></div></div><div class="cap-rich-pop-progress"><div class="cap-rich-pop-progress-bar" style="animation-duration:'+(dur/1000)+'s"></div></div><button class="cap-rich-pop-close" onclick="captainDismissPopById(this.dataset.id)" data-id="'+id+'">&#x2715;</button>';
  container.appendChild(pop);
  _captainNotifHistory.unshift({id:id,title:title,msg:msg,icon:icon,time:time,category:category});
  if(_captainNotifHistory.length>30)_captainNotifHistory.pop();
  _captainNotifUnread++;
  _captainUpdateTrayBadge();
  if(_captainTrayOpen)_captainRenderTray();
  var t=setTimeout(function(){_captainDismissPop(id);},dur);
  pop.addEventListener('mouseenter',function(){clearTimeout(t);var b=pop.querySelector('.cap-rich-pop-progress-bar');if(b)b.style.animationPlayState='paused';});
  pop.addEventListener('mouseleave',function(){var t2=setTimeout(function(){_captainDismissPop(id);},2000);var b=pop.querySelector('.cap-rich-pop-progress-bar');if(b)b.style.animationPlayState='running';pop._t=t2;});
};
function _captainDismissPop(id){var el=document.getElementById(id);if(!el||el.classList.contains('dismissing'))return;el.classList.add('dismissing');setTimeout(function(){if(el&&el.parentNode)el.parentNode.removeChild(el);},320);}
window.captainDismissPopById=function(id){_captainDismissPop(id);};
function _captainUpdateTrayBadge(){var b=document.getElementById('captainNotifTrayBadge');if(!b)return;if(_captainNotifUnread>0){b.textContent=_captainNotifUnread>99?'99+':_captainNotifUnread;b.style.display='block';}else{b.style.display='none';}}
function _captainRenderTray(){var list=document.getElementById('captainNotifTrayList');if(!list)return;if(_captainNotifHistory.length===0){list.innerHTML='<div class="cap-tray-empty">Abhi koi notification nahi</div>';return;}list.innerHTML=_captainNotifHistory.map(function(n){return'<div class="cap-tray-item"><div class="cap-tray-item-icon">'+n.icon+'</div><div style="flex:1;min-width:0"><div class="cap-tray-item-title">'+_capEsc(n.title)+'</div><div class="cap-tray-item-msg">'+_capEsc(n.msg)+'</div></div><div class="cap-tray-item-time">'+n.time+'</div></div>';}).join('');}
window.captainToggleNotifTray=function(){var tray=document.getElementById('captainNotifTray');if(!tray)return;_captainTrayOpen=!_captainTrayOpen;tray.classList.toggle('open',_captainTrayOpen);if(_captainTrayOpen){_captainRenderTray();_captainNotifUnread=0;_captainUpdateTrayBadge();}};
window.captainClearNotifTray=function(){_captainNotifHistory=[];_captainNotifUnread=0;_captainUpdateTrayBadge();_captainRenderTray();};
document.addEventListener('click',function(e){if(_captainTrayOpen){var tray=document.getElementById('captainNotifTray');var btn=document.getElementById('captainNotifTrayBtn');if(tray&&btn&&!tray.contains(e.target)&&!btn.contains(e.target)){_captainTrayOpen=false;tray.classList.remove('open');}}});
// Hook showAdvancedNotif
var _origSAN=window.showAdvancedNotif;
window.showAdvancedNotif=function(title,message,type,voiceMsg){
  var catMap={green:'ready',red:'urgent',orange:'cooking',blue:'order',purple:'waiter'};
  showRichPop(title,message,catMap[type]||'info');
  if(_origSAN)_origSAN(title,message,type,voiceMsg);
};
// Hook captainToast
var _origCT=window.captainToast;
window.captainToast=function(msg,color){
  if(_origCT)_origCT(msg,color);
  if(!msg)return;
  var skip=['Firebase connect','refresh ho','settings','Settings','menu prices','Naya QR','URL saved','Key saved','Test ho','API'];
  for(var i=0;i<skip.length;i++){if(msg.indexOf(skip[i])!==-1)return;}
  var cat='info';
  if(msg.indexOf('Naya Order')!==-1||msg.indexOf('naya order')!==-1)cat='order';
  else if(msg.indexOf('Chef')!==-1||msg.indexOf('cooking')!==-1||msg.indexOf('Cooking')!==-1)cat='cooking';
  else if(msg.indexOf('Ready')!==-1||msg.indexOf('ready')!==-1)cat='ready';
  else if(msg.indexOf('Waiter')!==-1||msg.indexOf('waiter')!==-1||msg.indexOf('assign')!==-1)cat='waiter';
  else if(msg.indexOf('Paid')!==-1||msg.indexOf('paid')!==-1||msg.indexOf('Bill')!==-1)cat='payment';
  else if(msg.indexOf('URGENT')!==-1||msg.indexOf('urgent')!==-1)cat='urgent';
  else if(msg.indexOf('note')!==-1||msg.indexOf('Note')!==-1)cat='note';
  else if(color==='#dc2626'||color==='error')cat='urgent';
  else if(color==='#059669')cat='ready';
  else if(color==='#2563eb')cat='order';
  else if(color==='#f59e0b')cat='cooking';
  else if(color==='#7c3aed')cat='waiter';
  showRichPop(msg.length>70?msg.substring(0,67)+'...':msg,'',cat);
};
// Hook addNotificationToFirebase (on load)
window.addEventListener('load',function(){
  if(window.addNotificationToFirebase&&!window._capRichPopHooked){
    window._capRichPopHooked=true;
    var _o=window.addNotificationToFirebase;
    window.addNotificationToFirebase=function(title,body,type,icon){
      var m={order:'order',warn:'cooking',success:'ready',alert:'urgent',info:'info',chef:'cooking'};
      showRichPop(title||'Notification',body||'',m[type]||'info',(icon&&icon.length<=4?icon:null));
      return _o(title,body,type,icon);
    };
  }
});
console.log('🔔 CaptainDash Rich Pop Notifications v2.0 loaded!');

// ═══════════════════════════════════════════════
// PHONE PERFORMANCE FIX — Pause heavy work when app is hidden
// ═══════════════════════════════════════════════
document.addEventListener('visibilitychange', function() {
  if (document.hidden) {
    // App background mein gaya — speech cancel karo
    if (window.speechSynthesis && window.speechSynthesis.speaking) {
      window.speechSynthesis.cancel();
    }
  }
});

// Prevent scroll jank on mobile
document.addEventListener('touchstart', function() {}, { passive: true });
document.addEventListener('touchmove', function() {}, { passive: true });